-- Poems batch 408
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-772','西江月','范成大','宋','宋词','song-ci','西江月','[]','樱笋园林绿暗，槐榆院落清和，年年高会引笙歌，戏彩人随燕贺。',58,'宋词/ci.song.20000.json','["樱笋园林绿暗，槐榆院落清和，年年高会引笙歌，戏彩人随燕贺。", "一笑难逢身健，十分休惜颜酡。", "还将瓜枣送金荷，遍照金章满座。"]'),
('song-ci-773','临江仙','范成大','宋','宋词','song-ci','临江仙','[]','功行三千宜五福，长生何假金丹。',70,'宋词/ci.song.20000.json','["功行三千宜五福，长生何假金丹。", "从教沧海又成田。", "琼枝春不老，壁月夜长妍。", "上界从来官府满，何妨游戏人间。", "年年强健到樽前。", "莫辞杯潋滟，君是酒中仙。"]'),
('song-ci-774','鹧鸪天','范成大','宋','宋词','song-ci','鹧鸪天','[]','绣户当年瑞气充。',64,'宋词/ci.song.20000.json','["绣户当年瑞气充。", "紫阳驾鹤下天风。", "万山秀色浑锺尽，六月炎光一洗空。", "蕉叶满，彩衣重。", "刻符持节尽人雄。", "坐中金母欣馀庆，劝醉周公劝鲁公。"]'),
('song-ci-775','满江红','范成大','宋','宋词','song-ci','满江红','[]','天气新晴，寻昨梦，池塘春早。',112,'宋词/ci.song.20000.json','["天气新晴，寻昨梦，池塘春早。", "雨过湔裙，水上柳丝风袅。", "却忆去年今日，桃花人面依前好。", "怪今年、酒量却添多，银杯小。", "谁劝我，玉山倒。", "催细抹，翻新调。", "渐金狎压锦，喷首云绕。", "笼柏飞来双翠袖，弓弯内样人间少。", "为留连、春色伴山翁，都休老。"]'),
('song-ci-776','清平乐','范成大','宋','宋词','song-ci','清平乐','[]','降嵩储昂，仙驭来尘表。',54,'宋词/ci.song.20000.json','["降嵩储昂，仙驭来尘表。", "身佩安危人不老。", "化国风光长好。", "功名南北天涯，欢声蛮峤胡沙。", "草木何□□露，小春桃李都花。"]'),
('song-ci-777','清平乐','范成大','宋','宋词','song-ci','清平乐','[]','何须轻举，上界多官府。',54,'宋词/ci.song.20000.json','["何须轻举，上界多官府。", "身似灵光长镇鲁。", "俯仰人间今古。", "雨馀帘卷江流，朱颜流映琼舟。", "不假岗陵□寿，西山低似西楼。"]'),
('song-ci-778','八声甘州','□阳','宋','宋词','song-ci','八声甘州','[]','渐纷纷、木叶下亭皋，秋容际寒空。',119,'宋词/ci.song.20000.json','["渐纷纷、木叶下亭皋，秋容际寒空。", "庆屏山南畔，龟游绿藻，鹤舞青松。", "缥缈非烟非雾，喜色有无中。", "帘幕金风细，香篆迷濛。", "好是庭闱称寿，簇舞裙歌板，欢意重重。", "况芝兰满砌，行见黑头公。", "看升平、乌栖画戟，更重开、大国荷荣封。", "人难老，年年醉赏，满院芙蓉。"]'),
('song-ci-779','点绛唇','赵彦逾','宋','宋词','song-ci','点绛唇','[]','春到皇都，日边已觉风光丽。',50,'宋词/ci.song.20000.json','["春到皇都，日边已觉风光丽。", "异人名世。", "独禀阳和粹。", "福寿川增，行庆鸳行缀。", "笙歌重。", "几多珠翠。", "拚取今宵醉。"]'),
('song-ci-780','南歌子','张孝祥','宋','宋词','song-ci','南歌子','[]','俭德仁诸族，阴功格上清。',62,'宋词/ci.song.20000.json','["俭德仁诸族，阴功格上清。", "焚香扫地夜朝真。", "看取名花浮玉、鉴齐精。", "宝篆融融满，□流细细倾。", "双亲俱寿八千龄。", "却捧紫皇飞诏、上蓬瀛。"]'),
('song-ci-781','水调歌头','卫时敏','宋','宋词','song-ci','水调歌头','[]','骑鲸紫霞客，来作世耆英。',114,'宋词/ci.song.20000.json','["骑鲸紫霞客，来作世耆英。", "襟怀金玉循良，名字古无人。", "所至民歌遗爱，脱屣归来绿野，笑傲乐天真。", "不学渭滨老，公子自长生。", "一杯酒，再三祝，八十春。", "从今细数庆集，百度似今辰。", "绿鬓朱颜长好，何事紫芝仙草，兰玉自诜诜。", "盛事有如此，谁道四难并。"]'),
('song-ci-782','念奴娇','卫时敏','宋','宋词','song-ci','念奴娇','[]','春风桃李，问耐寒何似，霜松雪柏。',121,'宋词/ci.song.20000.json','["春风桃李，问耐寒何似，霜松雪柏。", "珍重拨烦京兆手，早岁声名霹雳。", "收卷经论，摆遗荣利，物外多间适。", "熊经龟咽，真传秘诀消息。", "奉秩初满华严，韶颜转映，绿鬓方瞳碧。", "况□□云供宴几，静对凫翁鹤客。", "只恐日边，蒲轮催动，密侍钧天席。", "上玉卮尧殿，长生倍注仙籍。"]'),
('song-ci-783','汉宫春','高伯达','宋','宋词','song-ci','汉宫春','[]','绛阙朝元。',116,'宋词/ci.song.20000.json','["绛阙朝元。", "倦飞鸾控鹤，来寓人间。", "天教散舒和气，好与春还。", "蓬瀛罢宴，褪仙裳、欲冠貂蝉。", "应是念、潇湘胜概，来与蕃宣。", "宣室向来初见，叹不如、文帝夜半虚前。", "多情吊沉赋罢，莫负留连。", "经纶事叶，向朝廷、谁与争先。", "明岁好，云屏间坐，十分宣劝金船。"]'),
('song-ci-784','千秋岁','高伯达','宋','宋词','song-ci','千秋岁','[]','影摇波动。',87,'宋词/ci.song.20000.json','["影摇波动。", "晓日浮华栋。", "庆麟绂，徵兰梦。", "绿擎龟叶小，红拂莲腮重。", "帘幕外，半天仙驭来飞鞚。", "两两骖鸾凤。", "□窣珠衣纵。", "香雾散，祥云拥。", "口传金母信，酒为麻姑送。", "休惜醉，与君更下蟠桃种。"]'),
('song-ci-785','鹧鸪天','高伯达','宋','宋词','song-ci','鹧鸪天','[]','海上蟠桃月样圆。',64,'宋词/ci.song.20000.json','["海上蟠桃月样圆。", "从头屈指几千年。", "双成已报春消息，输与萧郎半月前。", "风露晓，月华鲜。", "兽炉烟袅水沉烟。", "骑鸾ⅶ鹤休归去，留取人间作女仙。"]'),
('song-ci-786','喜迁莺','郝子直','宋','宋词','song-ci','喜迁莺','[]','风云际会。',126,'宋词/ci.song.20000.json','["风云际会。", "自军兴勋业，唯公屈指。", "中镝红心，骄虏胆丧，中正已回天意。", "采石扶危鏖战，激励熊罴乘势。", "震天地，沮金狄百万，元颜诛毙。", "英卫。", "摅红气，寰海共欣，雪恨亡胡岁。", "宸眷褒功，华衮貂蝉，荣拜济时左揆。", "圣君用贤终始，肯使留侯谦退。", "后范蠡，愿永佐中兴，庄椿同纪。"]'),
('song-ci-787','画堂春','郝子直','宋','宋词','song-ci','画堂春','[]','华堂当日诞今辰。',54,'宋词/ci.song.20000.json','["华堂当日诞今辰。", "庆门人降西真。", "一杯千岁祝遐龄。", "莫厌频斟。", "不愿头白还黑，不愿齿落重生。", "但容艳只如今。", "寿等松椿。"]'),
('song-ci-788','天香','何得之','宋','宋词','song-ci','天香','[]','南国蜚声，三鳌孕粹，中兴循吏称首。',116,'宋词/ci.song.20000.json','["南国蜚声，三鳌孕粹，中兴循吏称首。", "官在中都，斑参玉笋，妙简帝心应久。", "长材已试，名字向、金瓯先覆。", "貂冕冠蝉载服，鸾台凤池荣簉。", "年年桂觞介寿。", "正江梅、犯寒时候。", "料想舞僮歌女，翠鬟依旧。", "富贵人间罕有。", "任鼎沸笙箫对樽□。", "稳步堤沙，高攀禁柳。"]'),
('song-ci-789','水调歌头','徐明仲','宋','宋词','song-ci','水调歌头','[]','迟日笼晴昼，新火敛馀寒。',114,'宋词/ci.song.20000.json','["迟日笼晴昼，新火敛馀寒。", "东君着意，留恋春色在人间。", "故遣蓬瀛仙侣，来布阳和德泽，造化寄毫端。", "麾节经行处，喜气满江山。", "听歌谣，五裤暖，二天宽。", "汉朝侧席，英隽玺诏促徵还。", "鞭算钱流粟腐，刃往剧剸烦解，启沃动龙颜。", "已有白麻笔，草制在金銮。"]'),
('song-ci-790','水调歌头','徐明仲','宋','宋词','song-ci','水调歌头','[]','宗社中兴佐，廊庙黑头公。',114,'宋词/ci.song.20000.json','["宗社中兴佐，廊庙黑头公。", "故家乔木，十年风虎会云龙。", "三镇上流藩翰，千里北门符钥，何许在民功。", "刀剑还牛犊，饥馑化登丰。", "政成时，春明媚，日和融。", "寿觞如海，愿公一酌倒三松。", "移取活人心手，归作调元勋业，谈笑共平戎。", "还使十书老，直与古人同。"]'),
('song-ci-791','满江红','陈之贤','宋','宋词','song-ci','满江红','[]','人物英雄，更独抱、无双才气。',115,'宋词/ci.song.20000.json','["人物英雄，更独抱、无双才气。", "年正壮，文章武略，尽曾留意。", "破胆欲凭胸内甲，清原宴启舟中誓。", "笑区区、燕雀不能知，青云志。", "封侯貌，神人比。", "社下手，须荣试。", "况相门出将，君家常事。", "斗印垂金他日贵，寿杯浮玉今朝醉。", "看年年、南极倍明时，春明媚。"]'),
('song-ci-792','念奴娇','陈之贤','宋','宋词','song-ci','念奴娇','[]','炎精昌运，庆天为笃生，中兴人杰。',119,'宋词/ci.song.20000.json','["炎精昌运，庆天为笃生，中兴人杰。", "横臆甲兵三百万，要扫群胡妖孽。", "抚弱怜贫，排奸击暴，所至人推服。", "飘飘志气，伟哉一代英特。", "预信衮衮公侯，名闻英胄，素有阴功积。", "腾踏从天上去，笑作龙头奇客。", "相印重封，将符再绾，尽履青毡物。", "寿杯满泛，年年长醉正月。"]'),
('song-ci-793','踏莎行','丁求安','宋','宋词','song-ci','踏莎行','[]','风卷霜浓，寒销冰谢。',68,'宋词/ci.song.20000.json','["风卷霜浓，寒销冰谢。", "一年皎月惟今夜。", "桑弧蓬矢庆门阑，云旌羽盖连车马。", "命服新翻，恩波如泻。", "海沂致锦傅声价。", "晓来和气着梅梢，春随温诏看看下。"]'),
('song-ci-794','踏莎行','丁求安','宋','宋词','song-ci','踏莎行','[]','紫府延龄，瑶池开宴。',68,'宋词/ci.song.20000.json','["紫府延龄，瑶池开宴。", "人间好事都如愿。", "凤雏喜带桂宫香，东床镇压鸾台彦。", "酒泛金杯，香飘龙篆。", "大家齐把瑶觞献。", "中兴天子急贤才，相期共入金銮殿。"]'),
('song-ci-795','念奴娇','赵师律','宋','宋词','song-ci','念奴娇','[]','镜天露洗，荡仁风，满县正开桃李。',120,'宋词/ci.song.20000.json','["镜天露洗，荡仁风，满县正开桃李。", "无讼堂深睛画永，帘卷鹅山浓翠。", "吏散棠阴，鸟啼花散，箫鼓弦歌地。", "印封碧藓，笑谈无限清致。", "佳会正属悬弧，十分蕉叶，共祝千秋岁。", "道骨仙风元自有，功业人间游戏。", "名覆金瓯，班联玉笋，行庆风云会。", "莲舟容与，此时归继仙裔。"]'),
('song-ci-796','念奴娇','赵师律','宋','宋词','song-ci','念奴娇','[]','楚天春晚，尽替了，残红点成层碧。',120,'宋词/ci.song.20000.json','["楚天春晚，尽替了，残红点成层碧。", "蝴蝶蜂儿娇未足，舞破游丝千尺。", "一夜风高，满天清露，冷浸琼楼彻。", "遮鸾绕凤，使君不是凡骨。", "游荡偶尔人间，铃斋谈笑，好作龚黄匹。", "火急功成天上去，却问蓬莱消息。", "酒泻鹅儿，十分金盏，染就眉间色。", "满城争看，一封鹗荐飞入。"]'),
('song-ci-797','齐天乐','赵师律','宋','宋词','song-ci','齐天乐','[]','重阳还近秋光好，银屏翠箔凉透。',120,'宋词/ci.song.20000.json','["重阳还近秋光好，银屏翠箔凉透。", "凤髓炉温，鱼轩瑞应，天与冰壶清透。", "多文在手。", "更赖玉腰肢，唾花衫袖。", "旧约梅仙，为来人世作珍偶。", "虚堂帘半卷，化工何限意，妆点时昼。", "裛真香葵倾劝盏，都把芳心为寿。", "当歌对酒。", "愿绿发朱颜，镇长依旧。", "宝箓名高，已书千岁久。"]'),
('song-ci-798','蓦山溪','赵师严','宋','宋词','song-ci','蓦山溪','[]','文章太守，今作湖山主。',102,'宋词/ci.song.20000.json','["文章太守，今作湖山主。", "冰雪照人清，赋仙家、出尘风度。", "流芳积庆，故自有渊源，家将相，世侯王，勋德藏盟府。", "政修人治，千里歌来暮。", "有脚是阳春，鼓和风、遍充寰宇。", "芝泥封诏，肯为郡人留，苍玉佩，紫金貂，稳上星辰去。"]'),
('song-ci-799','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','["\u957f\u6c5f"]','光风转蕙，正中和节过，艳阳春半。',126,'宋词/ci.song.20000.json','["光风转蕙，正中和节过，艳阳春半。", "暖日曈昽，瑞烟蓬勃，正是生申华旦。", "保厘东土三载，分却九重霄旰。", "政成也，且凝香燕寝，雍容方面。", "堪羡。", "德望重，敌国隐然，不假长江险。", "堂上奇兵，胸中妙画，便是当年韩范。", "况逢左辖虚位，早晚洪钧须转。", "来岁里，看内家敕使，传呼宣劝。"]'),
('song-ci-800','蓦山溪','辛弃疾','宋','宋词','song-ci','蓦山溪','[]','画堂帘卷，贺燕双双语。',102,'宋词/ci.song.20000.json','["画堂帘卷，贺燕双双语。", "花柳一番春，倚东风、雕红镂翠。", "草堂风月，还似旧家时，歌扇底，舞裀边，寿斝年年醉。", "兵符传垒，已莅葵丘戍。", "两手挽天河，要一洗、蛮烟瘴雨。", "貂蝉冠冕，应是出兜鍪，飡五鼎，梦三刀，侯印黄金铸。"]'),
('song-ci-801','感皇恩','辛弃疾','宋','宋词','song-ci','感皇恩','[]','露染武夷秋，千蛮耸翠。',81,'宋词/ci.song.20000.json','["露染武夷秋，千蛮耸翠。", "练色泓澄玉清水。", "十分冰鉴，未吐玉壶天地。", "精神先付与，人中瑞。", "青锁步趋，紫微标致。", "凤翼看看九十里。", "任挥金碗，莫负凉飚佳致。", "瑶台人度曲，千秋岁。"]'),
('song-ci-802','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','簪履竟晴昼，画戟插层霄。',114,'宋词/ci.song.20000.json','["簪履竟晴昼，画戟插层霄。", "红莲幕底风定，香雾不成飘。", "螺髻梅妆环列，凤管檀糟交泰，回雪无纤腰。", "觞酒荡寒玉，冰颊醉江潮。", "颂丰功，祝难老，沸民谣。", "晓庭梅蕊初绽，定报鼎羹调。", "龙衮方思勋旧，已覆金瓯名姓，行看紫泥褒。", "重试补天手，高插侍中貂。"]'),
('song-ci-803','望海潮','沈伯文','宋','宋词','song-ci','望海潮','[]','山连嵩岱，疆分齐鲁，济南自古多奇月。',130,'宋词/ci.song.20000.json','["山连嵩岱，疆分齐鲁，济南自古多奇月。", "魄堕英星，芒剪瑞□，来参汉主龙飞。", "仙露浥繁枝。", "振家声赫奕，金印传龟。", "一种春风，后园桃李自成蹊。", "淮堧暂弭旌旗。", "庆歌浮绿野，人静圜扉。", "梅破粉痕，柳回星眼，相将紫诏催归。", "玉勒晓骢嘶。", "望天墀咫尺，香惹朝衣。", "最好朱颜绿发，劝宴凤凰池。"]'),
('song-ci-804','念奴娇','钱处仁','宋','宋词','song-ci','念奴娇','[]','勋门积庆，为皇家此日，重生贤辅。',122,'宋词/ci.song.20000.json','["勋门积庆，为皇家此日，重生贤辅。", "崧岳储神须信道，非特当年申甫。", "清白传芳，高明驰誉，材更兼文武。", "黑头年少，风云还会龙虎。", "天为指日垂弧，张旜持节，不遣穹庐去。", "中使传宣，颁赐锡赍，清晓欢声旁午。", "两世光华，一门荣耀，盛事夸千古。", "祝公千岁，庙堂长佐贤主。"]'),
('song-ci-805','醉蓬莱','钱处仁','宋','宋词','song-ci','醉蓬莱','[]','正梧阴碧转，扇浪凉生，渐回秋意。',120,'宋词/ci.song.20000.json','["正梧阴碧转，扇浪凉生，渐回秋意。", "祥绕朱门，有崧灵锺瑞。", "笔走龙蛇，句雕风月，好客敦高谊。", "苏小琵琶，绿珠箫管，日添罗绮。", "邃阁清班，贰车清政，奕叶蝉联，世间谁比。", "行侍甘泉，趁青春荣贵。", "尽卷虾须，满斟鹦鹉，向画堂沉醉。", "铜狄摩挲，蓬莱清浅，八千椿岁。"]'),
('song-ci-806','喜迁莺','李焕','宋','宋词','song-ci','喜迁莺','["\u897f\u6e56"]','云蒸雷动。',125,'宋词/ci.song.20000.json','["云蒸雷动。", "庆瑞岳降真，祥生申甫。", "元后慈贤，勋臣英烈，百世显光家谱。", "久许致身忠孝，何止满怀今古。", "听舆论，是侯王苗裔，神仙俦侣。", "争睹藩尹盛，刑揩政成，和气横眉宇。", "北阙莺花，西湖风月，旌骑稳游天路。", "福海寿山无比，烂醉黄堂歌舞。", "正荣耀，有华姻宠授，清朝恩数。"]'),
('song-ci-807','喜迁莺','李焕','宋','宋词','song-ci','喜迁莺','[]','风云嘉会，有英杰瑞时，来符平泰。',125,'宋词/ci.song.20000.json','["风云嘉会，有英杰瑞时，来符平泰。", "子建才华，平阳勋业，流庆至今犹在。", "闾史卿来曾记，骨相堂堂庞艾。", "少年日，已心包云泽，名高嵩岱。", "超迈人尽道，今代吏师，小试犹淹大。", "两路登车，三州出牧，游刃了无凝碍。", "便合进推荷橐，迤逦参陪天縡。", "愿从此，奉明君真相，优游千载。"]'),
('song-ci-808','喜迁莺','林伯镇','宋','宋词','song-ci','喜迁莺','[]','百年卿族。',126,'宋词/ci.song.20000.json','["百年卿族。", "更七叶桂籍，蝉联相续。", "早冠鳌峰，入持魁柄，却商野耕岩筑。", "搢绅望山瞻斗。", "勋业铭书金竹。", "倦陶冶，暂镜湖舒啸，琳宫休足。", "催促。", "归秉轴，须与君王，同享无疆福。", "缓访赤松，莫留绿野，宇县待公恢复。", "手把命珪堂印，腰束精鏐寒玉。", "愿岁岁，看和羹梅绽，古阶槐绿。"]'),
('song-ci-809','凤栖梧・蝶恋花','林伯镇','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','破腊星回春可数。',70,'宋词/ci.song.20000.json','["破腊星回春可数。", "天佑中兴，岳降神生再。", "造膝一言曾寤主，翱翔历遍清华路。", "盖代功名知自许。", "倦把州麾，小向琳宫任。", "早晚诏催归禁署，致身宰相双亲具。"]'),
('song-ci-810','南乡子','林伯镇','宋','宋词','song-ci','南乡子','[]','弥诞秩初筵。',66,'宋词/ci.song.20000.json','["弥诞秩初筵。", "催舞春雷杂管弦。", "惊破梅梢香喷雪，都缘。", "王母瑶池会列仙。", "残腊嫩寒天。", "恰在正朝两日前。", "搀借椒花先献寿，新元。", "重数壬辰第一年。"]'),
('song-ci-811','念奴娇','王涣','宋','宋词','song-ci','念奴娇','[]','水沉香霭，满钱塘千里，秋烟如织。',120,'宋词/ci.song.20000.json','["水沉香霭，满钱塘千里，秋烟如织。", "万井欢声瞻宝钱，遥指明星南极。", "辇路看花，神旗垂彩，名冠金门籍。", "平阳家世，凌烟都减颜色。", "须信勋业风流，阳春有脚，到处开桃李。", "洊拥油幢宸眷重，吴越江南江北。", "认取疏梅，东君深意，遣调羹消息。", "凤书飞下，绿槐元自相识。"]'),
('song-ci-812','水调歌头','陈敷','宋','宋词','song-ci','水调歌头','[]','明月双溪上，胜景号金华。',114,'宋词/ci.song.20000.json','["明月双溪上，胜景号金华。", "当年此夕，多少鸾凤杂云霞。", "共拥飘颻倦伯，来作人间英杰，王谢旧名家。", "纶绋妙文采，帷幄富忠嘉。", "圣天子，形梦寐。", "眷尤加。", "麒麟烟上早晚，丹陛听宣麻。", "鼎袖无穷勋业，岁岁薰风日永，萱秀北堂花。", "潋滟绮筵酒，寿算等胡沙。"]'),
('song-ci-813','满庭芳','甄良友','宋','宋词','song-ci','满庭芳','[]','杲杲重光，遥山耸翠，九天秋气高明。',118,'宋词/ci.song.20000.json','["杲杲重光，遥山耸翠，九天秋气高明。", "露团仙掌，初月挂前星。", "帝念吾君父子，亲传授、光启中兴。", "生储后，是为三圣，一道以相承。", "升平。", "当此际，黄花照座，丹桂充庭。", "对雨宫喜色，百辟欢声。", "好是橙黄桔绿，宣猷殿、酒碧香清。", "重重庆，尧仁舜孝，亲见禹功成。"]'),
('song-ci-814','南乡子','甄良友','宋','宋词','song-ci','南乡子','[]','十月小春天。',66,'宋词/ci.song.20000.json','["十月小春天。", "放榜梅花作状元。", "会庆礼成三日后，生贤。", "第一龙飞不偶然。", "劝酒自弹弦。", "更着班衣寿老仙。", "见说海坛沙张也，明年。", "此夜休嗔我近前。"]'),
('song-ci-815','感皇恩','甄良友','宋','宋词','song-ci','感皇恩','[]','华表鹤重来，嘉禾合穗。',79,'宋词/ci.song.20000.json','["华表鹤重来，嘉禾合穗。", "天命真人救斯世。", "故仙子来佐，中兴之际。", "这回真是个，风云会。", "天水庆源，钱塘潮势。", "主圣臣贤千岁。", "半钩月小，一剪梅花香细。", "太平无事也，休辞醉。"]'),
('song-ci-816','水调歌头','甄良友','宋','宋词','song-ci','水调歌头','[]','直节傲山雪，偃盖咏松风。',114,'宋词/ci.song.20000.json','["直节傲山雪，偃盖咏松风。", "天香真色来报，春信月明中。", "六七日分景纬，五百年间英气，相值产维崧。", "君子中庸也，天下有胡公。", "把州麾，将漕计，简渊衷。", "淳熙新政，往风虎，趁云龙。", "底用玉卮卜寿，看取天然难老，高竹与长松。", "更有红梅实，调鼎告成功。"]'),
('song-ci-817','菩萨蛮','甄良友','宋','宋词','song-ci','菩萨蛮','[]','希夷本是儒先祖。',52,'宋词/ci.song.20000.json','["希夷本是儒先祖。", "云仍来自神仙所。", "前日一阳生。", "德星今夜明。", "灵椿殊未老。", "仙桂双双好。", "好是百花魁。", "年年称寿杯。"]'),
('song-ci-818','蝶恋花','甄良友','宋','宋词','song-ci','蝶恋花','[]','照水绮霞明木杪。',70,'宋词/ci.song.20000.json','["照水绮霞明木杪。", "彩翼双栖，未觉桐阴少。", "正是一年秋光好。", "世间重睹香山老。", "祝寿人如群玉绕。", "满酌金莲，愿永谐歌笑。", "仙客莫疑来不早。", "洞中日月天昏晓。"]'),
('song-ci-819','水调歌头','郑元秀','宋','宋词','song-ci','水调歌头','[]','富贵不难致，名节几人全。',114,'宋词/ci.song.20000.json','["富贵不难致，名节几人全。", "渡江龙化，于今五十有三年。", "历数中兴诸老，谁似武夷仙伯，操行老弥坚。", "吾道方中否，一柱独擎天。", "江南北，湘左右，惠宣敷。", "见说韩公城下，米斗只三钱。", "人愿公归台鼎，我愿公归草隐，九老要齐肩。", "岁岁祝公寿，风月满梅川。"]'),
('song-ci-820','水调歌头','郑元秀','宋','宋词','song-ci','水调歌头','[]','园林夸富贵，红绿簇枝头。',114,'宋词/ci.song.20000.json','["园林夸富贵，红绿簇枝头。", "阳和毓秀，气劘屈贾压曹刘。", "翰墨场中独步，洒落胸中万卷，横截百川流。", "邈视青云侣，俯着看瀛洲。", "到如今，萦扃务，尚淹留。", "庙堂应得好语，早晚觐宸旒。", "从此立登要路，便可羽仪台阁，指日凤池游。", "岁岁蟠桃会，椿算八千秋。"]'),
('song-ci-821','瑞鹤仙','黄人杰','宋','宋词','song-ci','瑞鹤仙','[]','飞花闲院落。',125,'宋词/ci.song.20000.json','["飞花闲院落。", "渐燕觜泥融，蜂须香薄。", "风光未全恶。", "有出林青杏，殿春红药。", "东皇旧约。", "把馀芳、一时留著。", "等君侯维岳佳辰，惜景为供春酌。", "新乐。", "谁番清韵，非石非金，金城弦索。", "如闻荐鹗，青云外，有飞削。", "双凫容与，摩天东上，稳步鸾台凤阁。", "管平泉，昼锦归时，发犹未鹤。"]'),
('song-ci-822','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','垛翠云蓬远。',140,'宋词/ci.song.20000.json','["垛翠云蓬远。", "日鸟高、炎官直午，暑风微扇。", "二六尧蓂开秀荚，跨海冰轮待满。", "怪院落，笙箫如剪。", "太乙然藜天际下，度卯金仙子，生华旦。", "依日月，近云汉。", "经时持橐明光殿。", "问江乡年来有几，只君方见。", "入座夫人难老甚，炯炯金霞照眼。", "笑指点，琼舟权劝。", "愿得调元勋业就，为红泉石磴轻轩冕。", "归共作，赤松伴。"]'),
('song-ci-823','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','突屼金仙屋。',140,'宋词/ci.song.20000.json','["突屼金仙屋。", "素秋深、长空霁雨，万山如浴。", "惊破元戎呼小队，来看飞泉喷玉。", "正晚谷，清镜圆熟。", "还是紫微初度至，对禅关，自奏长生曲。", "留杖屦，倚松竹。", "汉中念远眉休蹙。", "问擎天拄地，个事只今谁独。", "看领召环回鹢首，笑把江神要束。", "任碾破，澄波新绿。", "去了中兴台辅叶，挂貂蝉莫受风埃触。", "归绿野，种瑶簌。"]'),
('song-ci-824','满江红','黄人杰','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','季琯灰融，盛寒里、梅香乍放。',114,'宋词/ci.song.20000.json','["季琯灰融，盛寒里、梅香乍放。", "元道是酿成和气，间生名将。", "马革裹尸男子志，虎头食肉通侯相。", "更胸中、十万拥奇兵，人皆仰。", "腰金印，垂玉帐。", "忠胆锐，雄心壮。", "倚辕门几望，北州驰想。", "且倒长江为寿酒，却翻银浦千寻浪。", "算时来、一笑洗胡尘，迎天仗。"]'),
('song-ci-825','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','老子生朝，萧然坐离骚窟宅。',114,'宋词/ci.song.20000.json','["老子生朝，萧然坐离骚窟宅。", "更莫诧、才雄屈宋，诗高刘白。", "不向凤凰池上住，不逃鹦鹉洲边迹。", "谩一官、如水过称呼，诸侯客。", "平生志，水投石。", "首已皓，心犹赤。", "算陆沉雄奋，总非人力。", "广武成名惟孺子，高阳适意须欢伯。", "睨醉乡、一笑抚青萍，乾坤窄。"]'),
('song-ci-826','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','老火西流，风露洗、银湾一色。',115,'宋词/ci.song.20000.json','["老火西流，风露洗、银湾一色。", "还又近、半秋天气，月将成魄。", "玉燕来时清梦觉，书麟游处飞仙谪。", "问东南、一尉着斯人，如何得。", "君不学，吴门卒。", "君不问，长安狄。", "且持杯半揖，楚江鸂鶒。", "东府西台看历遍，归来绿野盟泉石。", "却从容、三万六千朝，追元白。"]'),
('song-ci-827','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','小驻碧油，公两载、重临初度。',115,'宋词/ci.song.20000.json','["小驻碧油，公两载、重临初度。", "满全楚、袭人和气，拍天歌舞。", "波涌荆江流不断，地连巫峡山无数。", "指此山、此水诵公恩，难忘处。", "民有恨，来何暮。", "民有愿，归无遽。", "各相携卧断，衮衣归路。", "只恐九重劳梦寐，不容十国私霖雨。", "看便飞、丹诏日边来，朝天去。"]'),
('song-ci-828','醉蓬莱','黄人杰','宋','宋词','song-ci','醉蓬莱','[]','记征鸿归候，梦燕来时，雪清梅瘦。',120,'宋词/ci.song.20000.json','["记征鸿归候，梦燕来时，雪清梅瘦。", "寒日迎长，觉微宽宫漏。", "翼轸分辉，斗牛呈瑞，间气维锺秀。", "江左风流，夷吾家世，尘源深厚。", "况是新闻，日边增秩，诰墨方妍，玉符将剖。", "五马西还，看鸳鸿为偶。", "我有新词，不论龟鹤，会祝公眉寿。", "南浦长春，西山不老，年华同久。"]'),
('song-ci-829','念奴娇','黄人杰','宋','宋词','song-ci','念奴娇','[]','菊黄萸紫，近重阳、天气秋光如洗。',121,'宋词/ci.song.20000.json','["菊黄萸紫，近重阳、天气秋光如洗。", "怀燕占熊，还又应、崧岳生申时节。", "玉女擎香，金仙持送，锦里欢声彻。", "照人风度，满怀俱是冰雪。", "那更千里江城，政成人化，比春生秋杀。", "双凤云间御诏墨，将下十行新札。", "黄阁亨衢，碧油重幕，稳复清毡物。", "策勋归去，蟠桃犹许三窃。"]'),
('song-ci-830','念奴娇','黄人杰','宋','宋词','song-ci','念奴娇','[]','山光堂下，恰催花雨过，韶华将半。',121,'宋词/ci.song.20000.json','["山光堂下，恰催花雨过，韶华将半。", "蝶舞回风莺度曲，暖响笙箫庭院。", "泥轼仙翁，当时此夕，正梦投怀燕。", "紫髯黄发，到今如此清健。", "岂但风月平分，海沂千里，流得欢声遍。", "屈宋江山，还助说，莫惜金荷频卷。", "问寿何如，凤池三到，却放壶天晚。", "赤松应待，挂冠归伴萧散。"]'),
('song-ci-831','玉楼春','黄人杰','宋','宋词','song-ci','玉楼春','[]','生申时节书云月。',64,'宋词/ci.song.20000.json','["生申时节书云月。", "惊怪玉梅开不彻。", "犯寒那得一枝春，要与邦君供胜绝。", "可轩有个词清切。", "解送双凫朝降阙。", "一声声祝一千年，试倩雪儿歌几阕。"]'),
('song-ci-832','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','晓色收梅雨。',139,'宋词/ci.song.20000.json','["晓色收梅雨。", "玉衡高、寒杓插午，月生银浦。", "一片祥光横碧落，幻出新晴院宇。", "拥阆苑、擎香天女。", "簇引飞仙来瑞世，向乌衣巷陌，生文度。", "人物似，古怀祖。", "履声合上尧阶去。", "问如何低回计幕，蜀山深处。", "金字催还知有日，且听尊前妙语。", "更领略、双成歌舞。", "愿借流三峡水，与君侯尽作流霞注。", "觞百举，寿千数。"]'),
('song-ci-833','渔家傲','黄人杰','宋','宋词','song-ci','渔家傲','[]','桔绿橙黄霜落候。',72,'宋词/ci.song.20000.json','["桔绿橙黄霜落候。", "小春天气宜晴昼。", "一片祥光横宇宙。", "仙乐奏。", "千官共祝南山寿。", "湛露恩波浓似酒。", "□堂宴罢嵩呼后。", "压帽宫花红欲溜。", "还拜手。", "瞻天望圣徘徊久。"]'),
('song-ci-834','祝英台近','黄人杰','宋','宋词','song-ci','祝英台近','[]','绛河清，丹阙晓。',95,'宋词/ci.song.20000.json','["绛河清，丹阙晓。", "云路烛龙照。", "鹤发仙翁，笞凤下天眇。", "莹然璞玉襟怀，层冰风表。", "镇长住、人间三岛。", "怎知道。", "不用九转丹砂，灵椿自难老。", "骥子麟儿、勋业付渠了。", "已持红药开时，赤松游处，寿觞对、壶天倾倒。"]'),
('song-ci-835','胜胜慢・声声慢','黄人杰','宋','宋词','song-ci','胜胜慢・声声慢','[]','荣喉娇脆，燕体轻盈，争翻妙舞新声。',121,'宋词/ci.song.20000.json','["荣喉娇脆，燕体轻盈，争翻妙舞新声。", "元是君侯生日，爽气澄清。", "天应人为献寿。", "春着意、花也留情。", "恣豪饮，似流觞曲水，前度兰亭。", "况遇湖山官满，无一事、身心分外安宁。", "买个归舟，随鸥趁鹭长征。", "逢时了些事业，还未遇、月钓云耕。", "世尘外，看西真桃熟，南极星明。"]'),
('song-ci-836','临江仙','黄人杰','宋','宋词','song-ci','临江仙','[]','六月炎官收火伞，南薰尽洗烦蒸。',70,'宋词/ci.song.20000.json','["六月炎官收火伞，南薰尽洗烦蒸。", "十三蓂荚又争青。", "问知陈仲举，元是此时生。", "别驾功成清暇日，题舆尚带屏星。", "黑头非晚至公卿。", "且倾浮蚁酒，来听祝龟龄。"]'),
('song-ci-837','临江仙','黄人杰','宋','宋词','song-ci','临江仙','[]','江上小春来几许，湘桃已发微妍。',70,'宋词/ci.song.20000.json','["江上小春来几许，湘桃已发微妍。", "开云今夕降飞仙。", "花神回暖律，天女炷祥烟。", "见说士元方展骥，低回共应尘缘。", "人间更住一千年。", "却骑丹凤去，归到五云边。"]'),
('song-ci-838','临江仙','黄人杰','宋','宋词','song-ci','临江仙','[]','秋色三分绕过二，江城又近重阳。',70,'宋词/ci.song.20000.json','["秋色三分绕过二，江城又近重阳。", "翠蓂双荚为谁芳。", "梅仙生此日，神物自呈祥。", "陶菊半黄萸斗紫，一时来共飞觞。", "祝君腾踏比奇章。", "玉枝元不许，眉寿与天长。"]'),
('song-ci-839','临江仙','黄人杰','宋','宋词','song-ci','临江仙','[]','解事西风真可意，秋声不到尧蓂。',70,'宋词/ci.song.20000.json','["解事西风真可意，秋声不到尧蓂。", "尚馀□荚十分清。", "知君当此际，清梦应长庚。", "道骨仙风元不老，天开鹤算龟龄。", "更看宝带换红鞓。", "拂衣辞管库，谈笑取功名。"]'),
('song-ci-840','蝶恋花','黄人杰','宋','宋词','song-ci','蝶恋花','[]','问讯梅花开也未。',70,'宋词/ci.song.20000.json','["问讯梅花开也未。", "孕雪┭香，春在寒梢尾。", "试与折来供一醉。", "寿乡容与生春意。", "律转黄锺霜小霁。", "月姊乘鸾，伴我浮尘世。", "结取年年今日誓。", "梅花影里看仙桂。"]'),
('song-ci-841','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','三月桃花浪。',142,'宋词/ci.song.20000.json','["三月桃花浪。", "涌荆红、浮光散彩，倚空千丈。", "杨柳阴中长堤路，一片笙歌暖响。", "春待晚、气清天亮。", "闻道君侯生此日，具虎头、飞食封侯相。", "风度远，襟怀爽。", "宝杯为我倾家酿。", "醉乡深，何妨更尽，吸川鲸量。", "富贵时来应自有，岂在随人俯仰。", "且共把、眉头开放。", "但得仙风长不老，又安知、不做东南将。", "勋业付，云台上。"]'),
('song-ci-842','瑞鹧鸪','黄人杰','宋','宋词','song-ci','瑞鹧鸪','[]','江梅还是嫁东风。',64,'宋词/ci.song.20000.json','["江梅还是嫁东风。", "夜半春心一点融。", "知道个人生此日，暗香浮雪荐金锺。", "阳春一曲无他愿，长愿梅花似玉容。", "教见夫荣并子贵，与梅同过百年冬。"]'),
('song-ci-843','清平乐','黄人杰','宋','宋词','song-ci','清平乐','[]','西风猎猎，秋到双蓂荚。',54,'宋词/ci.song.20000.json','["西风猎猎，秋到双蓂荚。", "天女擎香开寿□，寿酒浮花蘸甲。", "眉间一点轻黄。", "归帆已载斜阳。", "去矣留中好住，尧天日月偏长。"]'),
('song-ci-844','沁园春','黄人杰','宋','宋词','song-ci','沁园春','[]','金虎鸣秋，玉龙ㄏ月，天气正凉。',139,'宋词/ci.song.20000.json','["金虎鸣秋，玉龙ㄏ月，天气正凉。", "应梦熊时侯，叶丹苔碧，栖鸾亭馆，桔绿橙黄。", "人在兰台公子上，更身寄风流屈宋卿。", "登赏处，记含情纾思，曾赋高唐。", "春明旧家不远，算蝉嫣袭庆，都付仇香。", "况鵾弦初续，和生角徵，鹗书频下，名厕循良。", "但得西风吹峡水，尽倒卷波澜添寿觞。", "功业事，有朱颜领略，未许称量。"]'),
('song-ci-845','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','腊近嘉平，谁教放、梅梢弄雪。',115,'宋词/ci.song.20000.json','["腊近嘉平，谁教放、梅梢弄雪。", "更为问、霜前甘泽，应何时节。", "十荚尧蓂开翠羽，一番潘貌蒸红颊。", "是武夷、六六洞王中，生贤哲。", "头未雪，心犹铁。", "柔不茹，刚难折。", "个功名怀抱，试看摅发。", "渌水中间辞地角，绛霄高处朝天阙。", "管痴儿、事了挂冠归，方华发。"]'),
('song-ci-846','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','居士生朝，元来是、湖山胜日。',115,'宋词/ci.song.20000.json','["居士生朝，元来是、湖山胜日。", "长共荐、霜前篱落，半黄橙桔。", "酒压浮蛆新旨酽，香浮瑞兽祥烟密。", "更小蛮、清唱入时宜，声飘逸。", "湖海量，冰霜质。", "年未老，身犹屈。", "记平生操履，几曾亏失。", "季野阳秋虽有自，伯仁崆峒原无物。", "待着君、添个老人星，人间出。"]'),
('song-ci-847','满江红','黄人杰','宋','宋词','song-ci','满江红','[]','解语宫商，为谁奏、长生一曲。',115,'宋词/ci.song.20000.json','["解语宫商，为谁奏、长生一曲。", "见说道、密堂深处，宝香芬馥。", "月里飞仙云际下，乘鸾来伴凫仙宿。", "约年年、生日醉冰篘，簪梅玉。", "花与貌，争清淑。", "云共发，斗新绿。", "尽壶觞为寿，苦无他说。", "有子有孙真老大，无嗔无妒家和睦。", "更鸾花、剩着几番封，平生足。"]'),
('song-ci-848','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','逗晓晴烟敛。',142,'宋词/ci.song.20000.json','["逗晓晴烟敛。", "过书云、祥开五日，漏添宫线。", "葭莞飞灰微度暖，眷着梅梢尚浅。", "怪深院、笙箫如剪。", "非雾非烟浮月观，应麟书，吐处豪英产。", "迟绣斧，启华宴。", "楚腰舞彻霓裳遍。", "拥金船，柔纤莹玉，十分争劝。", "醉入无何休莫问，日下长安非远。", "况一点、眉黄新见。", "掩鼻功名须办了，赋归来、却访乔松伴。", "应未许，雪枝汗。"]'),
('song-ci-849','贺新郎','黄人杰','宋','宋词','song-ci','贺新郎','[]','急雨收庚暑。',141,'宋词/ci.song.20000.json','["急雨收庚暑。", "倚三峰、祥光万丈，晓窥临汝。", "金石台边人语闹，惊怪麟书夜吐。", "又却是、重生申甫。", "笔底婆澜翻瀚海，更风流，不减王文度。", "冰共雪，是标榘。", "双凫有底人间住。", "为萍江，一齐洗尽，吏奸民蠹。", "见说王堂新有诏，趣近尧天尺五。", "看紫闼黄扉平步。", "我有新翻长寿曲，愿淮波、衮衮长东注。", "波未竭，寿无数。"]'),
('song-ci-850','鹧鸪天','黄人杰','宋','宋词','song-ci','鹧鸪天','[]','挺挺君家有祖风。',64,'宋词/ci.song.20000.json','["挺挺君家有祖风。", "ō任馀庆尚无穷。", "钓鳌莫问当年事，汗马须收第一功。", "何日是，梦维熊。", "麦光摇翠浪花红。", "一尊敬为祈难老，要作人间矍铄翁。"]'),
('song-ci-851','鹧鸪天','黄人杰','宋','宋词','song-ci','鹧鸪天','[]','落落南班间世英。',64,'宋词/ci.song.20000.json','["落落南班间世英。", "风流人物汉更生。", "当时良月垂孤处，天女惊香下广庭。", "鲸作量，兕为觥。", "尽倾家酿祝脩龄。", "校雠天禄须君辈，藜杖看陪太乙星。"]'),
('song-ci-852','鹧鸪天','黄人杰','宋','宋词','song-ci','鹧鸪天','[]','瑞霭朝迷紫极宫。',64,'宋词/ci.song.20000.json','["瑞霭朝迷紫极宫。", "梅香轻度琐窗风。", "关西都护生时节，来吐芳心献寿锺。", "头来白，频先红。", "臂强方解挽雕功。", "银符玉帐轻毡在，稳著功名继乃翁。"]'),
('song-ci-853','菩萨蛮','黄人杰','宋','宋词','song-ci','菩萨蛮','[]','小春撋就双桃靥。',52,'宋词/ci.song.20000.json','["小春撋就双桃靥。", "伴他二六尧蓂荚。", "红绿若为新。", "个时生玉人。", "玉人持酒笑。", "笑与仙翁道。", "从此百年中，莺花几度封。"]'),
('song-ci-854','虞美人','黄人杰','宋','宋词','song-ci','虞美人','[]','瑶台夜冷清霜泣。',66,'宋词/ci.song.20000.json','["瑶台夜冷清霜泣。", "听得双成语。", "有人乘月下云端。", "吹彻凤箫来此、伴栖鸾。", "尊前有个新番曲。", "不唱蟠桃熟。", "一杯聊驻玉精神，长与雪梅争韵、更争春。"]'),
('song-ci-855','虞美人','黄人杰','宋','宋词','song-ci','虞美人','[]','吕城春色知何处。',66,'宋词/ci.song.20000.json','["吕城春色知何处。", "试听流莺语。", "江头别有小壶天，唤起一番花柳、弄芳妍。", "主人元是虬髯种。", "胸次吞云梦。", "一尊何翅祝长年。", "看取金枝从此、更关联。"]'),
('song-ci-856','虞美人','黄人杰','宋','宋词','song-ci','虞美人','[]','菊花不等重阳到。',66,'宋词/ci.song.20000.json','["菊花不等重阳到。", "昨夜都开了。", "问知仙子是生辰。", "采翠浮金来供、玉壶春。", "周郎莫计文君寿。", "头白须相守。", "从今更数百年期。", "月底云间同跨、彩鸾归。"]'),
('song-ci-857','虞美人','黄人杰','宋','宋词','song-ci','虞美人','[]','蓂飞八叶书云后。',66,'宋词/ci.song.20000.json','["蓂飞八叶书云后。", "此日孙枝秀。", "爱他风味似吾人。", "都是笔头能篆、又能文。", "青青两鬓年方壮。", "儿女俱成长。", "要添福寿与荣华。", "教取一庭兰玉、共成家。"]'),
('song-ci-858','虞美人','黄人杰','宋','宋词','song-ci','虞美人','[]','疏梅淡月年年好。',66,'宋词/ci.song.20000.json','["疏梅淡月年年好。", "景思今年早。", "迎长时节近佳辰。", "看取衮衣华发、尽麒麟。", "酒中倒卧南山绿。", "起舞人如玉。", "风流椿树可怜生。", "长与柳枝桃叶、共青青。"]'),
('song-ci-859','念奴娇','黄人杰','宋','宋词','song-ci','念奴娇','[]','挽红留翠，为东皇、那住二分春色。',120,'宋词/ci.song.20000.json','["挽红留翠，为东皇、那住二分春色。", "燕舞回风莺度曲，晴昼光生瑶席。", "天女擎香，长庚入梦，还有飞仙谪。", "方瞳方颊，玉壶清浸胸臆。", "休问辟谷延年，介君眉寿，自有阴功□。", "膝下鹓雏俱擢秀，争奋摩天云翼。", "白雪声中，黄流影里，且放琼舟侧。", "醉乡深处，兴来时拊金伏。"]'),
('song-ci-860','满江红','石孝友','宋','宋词','song-ci','满江红','[]','分景亭前，梅红糁、柳金谁粟。',114,'宋词/ci.song.20000.json','["分景亭前，梅红糁、柳金谁粟。", "芳意闹，烧灯初过，坠萱才六。", "此日悔康歌别驾，当年神降生崧岳。", "看邦人，称寿雾凝香，杯丛玉。", "采石月，光天禄。", "姑溪水，增川福。", "炳灵祥曾产，瑞枝奇木。", "秋露短檠诗礼训，春风小院琵琶曲。", "愿长眉疏鬓等松椿，年年绿。"]'),
('song-ci-861','鹧鸪天','石孝友','宋','宋词','song-ci','鹧鸪天','[]','贤圣相逢信有因。',64,'宋词/ci.song.20000.json','["贤圣相逢信有因。", "同年同月下穹庭。", "紫薇花下丝纶手，采石江边衮绣身。", "梅破腊，酒浮春。", "锦绷行弄掌珠新。", "那人请效封人祝，愿寿尧君与舜臣。"]'),
('song-ci-862','南乡子','石孝友','宋','宋词','song-ci','南乡子','[]','梅雪弄芳馨。',66,'宋词/ci.song.20000.json','["梅雪弄芳馨。", "饯日迎辰契月蓂。", "争着琴堂称贺处，娉婷。", "满捧霞觞璨鲤庭。", "鹤等更龟龄。", "八十仙翁醉复醒。", "好倩洛阳驰誉手，丹青。", "乞与人间作寿星。"]'),
('song-ci-863','满江红','石孝友','宋','宋词','song-ci','满江红','[]','帘卷南薰，微雨过、天容似沐。',115,'宋词/ci.song.20000.json','["帘卷南薰，微雨过、天容似沐。", "开绮燕，红蕖别馆，绿槐高屋。", "灵寿杖横龙脊瘦，长年酒酿鹅儿熟。", "唤飞琼、亲捧紫霞杯，歌新曲。", "双凤好，温和玉。", "谈俭幕，嬉莱眼。", "且功成身退，注名仙箓。", "莲社焚香冰琢句，兰亭泚笔云翻墨。", "愿朱颜、长伴赤松游，骑黄鹄。"]'),
('song-ci-864','满江红','石孝友','宋','宋词','song-ci','满江红','[]','且转桐阴，正玉燕、飞来夏屋。',115,'宋词/ci.song.20000.json','["且转桐阴，正玉燕、飞来夏屋。", "帘幕映，海留红艳，麝重兰馥。", "风采传闻瞻瑞节，婉谋曾是回钧轴。", "卷秦淮、吹入酒杯中，波翻绿。", "丹诏下，公归速。", "看日奏，三千牍。", "想春迷柳院，夜分莲烛。", "清暑声寒苍玉佩，月娥笑捧长生箓。", "问瑶池、阿母手栽花，何年熟。"]'),
('song-ci-865','满庭芳','周云','宋','宋词','song-ci','满庭芳','[]','黄蕊封金，素英缕玉，此花端为君开。',61,'宋词/ci.song.20000.json','["黄蕊封金，素英缕玉，此花端为君开。", "五云深处，昨夜见三台。", "天相勋门庆胄，嫖姚后，重产英材。", "蝉宫客，胸中万卷，荷橐久徘徊……。"]'),
('song-ci-866','洞仙歌','周云','宋','宋词','song-ci','洞仙歌','[]','千崖滴翠。',103,'宋词/ci.song.20000.json','["千崖滴翠。", "正秋高时侯。", "橙黄桔绿又重九。", "有蓬壶仙子、赤鲤来游，风云会，施展经纶妙手。", "去年称寿处，北斗天浆，今夜天浆挹南斗。", "听笙箫云里奏，月满琼楼，瑶台上、拥出嫦娥观酒。", "待脚踏层云倒天河，尽倾向霞觞，与君为寿。"]'),
('song-ci-867','水调歌头','俞国宝','宋','宋词','song-ci','水调歌头','[]','灵谷有荚气，盘结在巴山。',114,'宋词/ci.song.20000.json','["灵谷有荚气，盘结在巴山。", "云蒸雨朵欲遣，奇怪出人间。", "不作丰城宝剑，不作渥洼灵种，不作化龙竿。", "生此济时杰，理乱总相关。", "入为相，出为将，两馀闲。", "忠肝义胆，曾将鲠论破天颜。", "好把昪平勋业，趁取河清桃熟，千岁奉金銮。", "草却登封检，双鬓未曾斑。"]'),
('song-ci-868','满庭芳','俞国宝','宋','宋词','song-ci','满庭芳','[]','南省西清，黄扉青琐，五年历遍中都。',118,'宋词/ci.song.20000.json','["南省西清，黄扉青琐，五年历遍中都。", "一封朝奏，无乃爱君欤。", "便作筠阳胜赏，东溪上、鸥鸟相娱。", "谁知道，心存魏阙，身暂寄江湖。", "东溪，何所有，冬梅夏柳，春杞秋蕖。", "谩回首，多少笼鸟池鱼。", "细看山林朝市，经行处、等是蘧庐。", "今朝好，一杯寿酒，一卷养生书。"]'),
('song-ci-869','临江仙','俞国宝','宋','宋词','song-ci','临江仙','[]','落落江湖三岛，才高懒住清都。',69,'宋词/ci.song.20000.json','["落落江湖三岛，才高懒住清都。", "手携黄石一编书。", "醉眠莘垅月，闲钓渭川鱼。", "见说玉阶三尺地，思君来讲唐虞。", "夜来南极一星孤。", "不知天子梦，曾到傅岩无。"]'),
('song-ci-870','蓦山溪','俞国宝','宋','宋词','song-ci','蓦山溪','[]','木犀开了。',103,'宋词/ci.song.20000.json','["木犀开了。", "还是生辰到。", "一笑对东风，喜人与、花容俱好。", "寿筵启处，香雾扑帘帏，星河晓，晚丝簧奏，拚取金尊倒。", "当年仙子，容易抛蓬岛。", "月窟与花期，要同向、人间不老。", "拈枝弄蕊，此乐几时穷，一岁里，一番新，莫与蟠桃道。"]'),
('song-ci-871','临江仙','俞国宝','宋','宋词','song-ci','临江仙','[]','春到江南江北了，东皇未识花权。',70,'宋词/ci.song.20000.json','["春到江南江北了，东皇未识花权。", "直将和气入巴川。", "逢迎天上客，来作地行仙。", "满捧一杯听细说，只今谁似公贤。", "愿推功业辅尧年。", "都将闲日月，来醉百花前。"]'),
('song-ci-872','蓦山溪','俞国宝','宋','宋词','song-ci','蓦山溪','[]','群花烂熳，春色浓如酒。',102,'宋词/ci.song.20000.json','["群花烂熳，春色浓如酒。", "芳草绿铺茵，正荼䕷、牡丹时侯。", "佳辰协瑞，来降蕊宫仙，珠帘卷，画堂深，香雾腾金兽。", "朱颜绿鬓，不改长安旧。", "金盏莫辞深，拚通宵、尽从银漏。", "笙歌丛里，欢笑度年华。", "看荣贵，有儿孙，永祝松椿寿。"]'),
('song-ci-873','蓦山溪','俞国宝','宋','宋词','song-ci','蓦山溪','[]','江天霜晓，梅粉参差吐。',102,'宋词/ci.song.20000.json','["江天霜晓，梅粉参差吐。", "剪剪暗香风，自吹到、瑶台仙路。", "辎軿缥缈，昨夜出蓬莱，云鬓薄，月眉纤，元是飞琼侣。", "知书识字，书带先生女。", "来配计然家，货财等、封君千户。", "谷量牛马，更用斗量金，年不老，富无穷，常作蟠桃主。"]'),
('song-ci-874','念奴娇','俞国宝','宋','宋词','song-ci','念奴娇','[]','云收雾敛，过一番疏雨，秋容新沐。',120,'宋词/ci.song.20000.json','["云收雾敛，过一番疏雨，秋容新沐。", "月满巴山天似水，满眼祥云飞扑。", "一点长庚，瑞腾光彩，独照梅仙屋。", "十洲三岛，有人初降凡俗。", "长怪李白疏狂，骑鲸一去，千载无人逐。", "也解重来应尚欠，多少人间传曲。", "只怨君王，促归批诏，夜对金莲烛。", "蓬莱日醉，不知海岛桃熟。"]'),
('song-ci-875','念奴娇','王孝严','宋','宋词','song-ci','念奴娇','[]','昨宵灰动，有阶前春草，侵凌春雪。',121,'宋词/ci.song.20000.json','["昨宵灰动，有阶前春草，侵凌春雪。", "碧玉堂前为寿处，齐祝遐龄千百。", "夜冷笙箫，庭深灯火，应照梅妆额。", "容华依旧，向来姑射标格。", "独恨绾系日边，东风回首，还有溪山隔。", "怅望云飞，凝伫久，空使怀英心折。", "遥折一枝，饱斟花露，再拜瞻南极。", "愿言来岁，凤池同看春色。"]'),
('song-ci-876','南歌子','陈晔','宋','宋词','song-ci','南歌子','[]','腰下重金贵，眉间一点黄。',62,'宋词/ci.song.20000.json','["腰下重金贵，眉间一点黄。", "定知从此庆非常。", "况有阴功宜寿、等天长。", "乞得仙家酒，来称诞日觞。", "乃翁阿母醉何妨。", "行见诸郎接武、上明光。"]'),
('song-ci-877','满庭芳','陈晔','宋','宋词','song-ci','满庭芳','[]','翠竹阴团，绿荷芗嫩，朝来和气盈盈。',118,'宋词/ci.song.20000.json','["翠竹阴团，绿荷芗嫩，朝来和气盈盈。", "薰风楼阁，玉燕梦初成。", "便有功名壮志，持符节，麟虎频。", "更归来后，挂冠神武，四海□高名。", "今年，方八十，莱衣舞处，岨拜霞觥。", "想笙歌递奏，鼎沸欢声。", "何用渠渠颂祝，自应合、福禄安荣。", "丹台上，玉清山籍，金字注长生。"]'),
('song-ci-878','醉蓬莱','陈晔','宋','宋词','song-ci','醉蓬莱','["\u897f\u6e56"]','算当年紫府，乘兴霓车，世间游戏。',120,'宋词/ci.song.20000.json','["算当年紫府，乘兴霓车，世间游戏。", "符节功名，谩略儿小试。", "自挂衣冠，旋栽松菊，占水云佳致。", "九人年高，重重恩渥，丝纶光贲。", "十里西湖，九霞仙酿，举劝吾翁，诞辰一醉。", "窦氏阴功，筹彭篯久视。", "啸傲壶中，燕超尘外，此乐谁能继。", "庭砌年年，斑斓□济，朱颜见喜。"]'),
('song-ci-879','耍鼓令','陈晔','宋','宋词','song-ci','耍鼓令','[]','化日长。',86,'宋词/ci.song.20000.json','["化日长。", "政莺语，啭新篁。", "到处园林垂绿幄，槐风细，梅雨凉。", "见庭户，瑞霭回翔。", "拥真仙，鸾驭临华堂。", "阗阗珠履争相庆，笙箫奏，绮筵张，捧玉觞。", "好深酌九霞浆，舞袖弓弯呈妙态，更……。"]'),
('song-ci-880','水调歌头','邵元实','宋','宋词','song-ci','水调歌头','[]','双阙步云尾，六阁上鳌头。',114,'宋词/ci.song.20000.json','["双阙步云尾，六阁上鳌头。", "侍臣冠底，英英人物是君侯。", "闻道东皇深意，回想西清往事，早晚启金瓯。", "丹扆伫宏略，黄阁待名流。", "九秋天，千岁日，一樽酬。", "策勋黄石，相期茅土更封侯。", "稳扈钩陈天仗，净扫搀抢氛祲，按辔入神州。", "收了卢龙塞，却访赤松游。"]'),
('song-ci-881','喜迁莺','卑叔文','宋','宋词','song-ci','喜迁莺','[]','春回天际，见柳眼翠窥，梅腮粉腻。',126,'宋词/ci.song.20000.json','["春回天际，见柳眼翠窥，梅腮粉腻。", "日庆三阳，时逢千载，帷幄挺生元帅。", "亘古抚今忠义，天下安危注意。", "负英伟，信功高耿贾，勋侔霍卫。", "和气。", "东风里，楼阁五云，玉帐环珠翠。", "庙食真扬，人怀邵父，当代虎臣难比。", "拟把倩桃为寿，莫惜金花沉醉。", "受阃寄，佐君王神武，复恢舆地。"]'),
('song-ci-882','满庭芳','臧鲁子','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','澹露零空，好风光袂，月华飞入觥筹。',118,'宋词/ci.song.20000.json','["澹露零空，好风光袂，月华飞入觥筹。", "青莲碧藕，芡实与鸡头。", "笑傲纶巾羽扇，有如此、人物风流。", "西湖上，不妨游戏，民富自封侯。", "骈蕃。", "新宠渥，弃华延阁，领事园丘。", "看木牛流马，恢复神州。", "万里凉霄浩渺，使星共、南极光浮。", "从今好，一秋长醉，直醉过千秋。"]'),
('song-ci-883','鹧鸪天','臧鲁子','宋','宋词','song-ci','鹧鸪天','[]','虎踞龙蟠万古雄。',64,'宋词/ci.song.20000.json','["虎踞龙蟠万古雄。", "横飞一节大江东。", "今归定作鸾坡客，笔底山川写不穷。", "吟絮柳，赋东风。", "年年春在建章宫。", "天教随佛生人世，恰似河沙寿我公。"]'),
('song-ci-884','满庭芳','臧鲁子','宋','宋词','song-ci','满庭芳','[]','露洗银潢，风来玉宇，正当□□□□。',118,'宋词/ci.song.20000.json','["露洗银潢，风来玉宇，正当□□□□。", "□□□阁，争看拥冰轮。", "共指银河影里，依稀见、执斧仙人。", "还知麽，天教此夕，嵩岳再生申。", "夤缘，当阃寄，高明洞物，爽气侵云。", "记广寒宫殿，曾对高真。", "玉兔捣馀灵药，霞觞化、万种花春。", "嫦娥嘱，愿公难老，长似月精神。"]'),
('song-ci-885','满庭芳','陈秉文','宋','宋词','song-ci','满庭芳','[]','山涌银涛，屏间绣巘，太平今日皇州。',118,'宋词/ci.song.20000.json','["山涌银涛，屏间绣巘，太平今日皇州。", "共惟京牧，昭裔本宗周。", "好是王春正月，维岳降，膺此神休。", "尧阶下，蓂存八荚，长应八千秋。", "优游。", "兼国计，丰财重谷，首善承流。", "更刑清讼简，政入歌讴。", "已副貂蝉眷宠，夸中外，耸动□讴。", "居恩重，苍生望切，好个富民侯。"]'),
('song-ci-886','满庭芳','谈羲仲','宋','宋词','song-ci','满庭芳','[]','星宿呈祥，溪山锺秀，凛然生此真贤。',117,'宋词/ci.song.20000.json','["星宿呈祥，溪山锺秀，凛然生此真贤。", "冰清玉润，还称岁寒天。", "正是梅梢酝雪，探江南，春信先傅。", "庭轩爽，涓涓皎月，今夜十分圆。", "开筵。", "称寿处，歌尘飞动，舞袖蹁跹。", "愿公与椿松，对阅天年。", "第恐宏才重望，不容暂吟醉苕川。", "龙光近，行看凤诏，来自日华边。"]'),
('song-ci-887','点绛唇','谈羲仲','宋','宋词','song-ci','点绛唇','[]','冰玉神人，岁寒时节迎初诞。',50,'宋词/ci.song.20000.json','["冰玉神人，岁寒时节迎初诞。", "照溪梅绽。", "秀岭孤松远。", "香雾氤氲，不放重帘卷。", "歌声缓。", "酒杯深劝。", "此会年年见。"]'),
('song-ci-888','水调歌头','王高','宋','宋词','song-ci','水调歌头','[]','千枝蔓仙牒，眉宇肖苍龙。',114,'宋词/ci.song.20000.json','["千枝蔓仙牒，眉宇肖苍龙。", "就中天赋英杰，玉磬照金锺。", "满袖春风和气，散在苕溪霅水，讴歌颂儿童。", "好个庙堂样，貂弁马头公。", "烛如椽，香似雾，宴蓬瀛。", "我家寿酒须信，不与世间同。", "昨夜欢传清禁，今日黄堂歌舞，千载一相逢。", "来岁五云里，宣劝折黄封。"]'),
('song-ci-889','水调歌头','王高','宋','宋词','song-ci','水调歌头','[]','今夕是何夕，南极见祥光。',114,'宋词/ci.song.20000.json','["今夕是何夕，南极见祥光。", "自天飘下佳气，五色覆黄堂。", "为借盐梅妙手，暂对裤襦欢颂，森戟护凝香。", "馀事剩吟咏，金薤灿琳琅。", "眷田园，松径旧，菊畦荒。", "欲乘风驭归去，策杖纵相羊。", "物外乾坤自在，壶里无尘日月，千岁傲羲皇。", "天意未应许，军国要平章。"]'),
('song-ci-890','蝶恋花','江袤','宋','宋词','song-ci','蝶恋花','[]','身世谁人知觉梦。',70,'宋词/ci.song.20000.json','["身世谁人知觉梦。", "阳焰空花，尽被三彭弄。", "可但运机畦上瓮。", "由来不了轻根重。", "休要寻文披大洞。", "丹鼎屯蒙，养取元珠动。", "意马此时何用鞚。", "长生自与天齐共。"]'),
('song-ci-891','瑞鹧鸪','华岳','宋','宋词','song-ci','瑞鹧鸪','[]','挑尽银缸半夜花。',64,'宋词/ci.song.20000.json','["挑尽银缸半夜花。", "拍帘风劲卷龙沙。", "香传梅福深深意，春在钱塘小小家。", "鸳被半闲才子恨，莺簧初转史君夸。", "归来醉体娇无力，压尽名园无限花。"]'),
('song-ci-892','瑞鹧鸪','华岳','宋','宋词','song-ci','瑞鹧鸪','[]','华月楼前见玉容。',64,'宋词/ci.song.20000.json','["华月楼前见玉容。", "凤钗斜褪鬓云松。", "梅花体态香凝雪，杨柳腰肢瘦怯风。", "几向白云寻楚□，难凭红叶到吴宫。", "别来风韵浑如旧，犹恐相逢是梦中。"]'),
('song-ci-893','满江红','华岳','宋','宋词','song-ci','满江红','[]','自古称稀，须信道、人生七十。',115,'宋词/ci.song.20000.json','["自古称稀，须信道、人生七十。", "当七月、庆生佳节，更逢七夕。", "丹鼎麻姑多两转，蟠桃王母无双实。", "更竹林、作者茂芝兰，俱无敌。", "持觞劝，辰拱北。", "阴功在，头俱黑。", "况轲亲教子，同声战国。", "九万鹏程当不二，八千椿寿看逾一。", "愿从今、屈指再从头，山中日。"]'),
('song-ci-894','菩萨蛮','华岳','宋','宋词','song-ci','菩萨蛮','[]','玉纤倒把罗纨扇。',52,'宋词/ci.song.20000.json','["玉纤倒把罗纨扇。", "屏山半倚羞人见。", "回首忽相逢。", "桃花生嫩红。", "见了娇无语。", "还向屏山去。", "略略转秋波。", "客愁无奈何。"]'),
('song-ci-895','念奴娇','华岳','宋','宋词','song-ci','念奴娇','[]','倚藤临水，照丰姿自笑，天然丘壑。',120,'宋词/ci.song.20000.json','["倚藤临水，照丰姿自笑，天然丘壑。", "利鞅名缰成底事，空把此身缠缚。", "李杜文章，良平事业，且束之高阁。", "浩然归去，暮霞残照零落。", "闻道西北埃尘，东南形胜，次第清河岳。", "此等功名尘世事，与我初无关约。", "十里松萝，一蓑烟雨，说甚扬州鹤。", "倚栏长啸，玉轮飞上天角。"]'),
('song-ci-896','满江红','华岳','宋','宋词','song-ci','满江红','[]','懒取冠儿，只偏带、一枝翠柏。',115,'宋词/ci.song.20000.json','["懒取冠儿，只偏带、一枝翠柏。", "记刺指、封书罗带，尚馀残血。", "愁入柳眉云黛蹙，汗凝桃脸胭脂湿。", "把玉纤、掩定古词名，猜谁识。", "瓶已坠，宁无阙。", "盟已负，难成匹。", "念当年亭院，画楼东北。", "烛影烧残蝴蝶梦，縠纹皱起鸳鸯翼。", "叹如今、憔悴忆前欢，重门隔。"]'),
('song-ci-897','霜天晓角','华岳','宋','宋词','song-ci','霜天晓角','[]','裙儿六幅，谁染秋波绿。',50,'宋词/ci.song.20000.json','["裙儿六幅，谁染秋波绿。", "一搦柳腰两过，樽前粲粲玉。", "暑气消烦溽。", "日月飞车轴。", "线幕黄帘风露。", "那堪人在天北。"]'),
('song-ci-898','蝶恋花','华岳','宋','宋词','song-ci','蝶恋花','[]','叶底无风池面静。',70,'宋词/ci.song.20000.json','["叶底无风池面静。", "掬水佳人，拍破青铜镜。", "残月朦胧花弄影，新梳斜插乌云鬓。", "拍索闷怀添酒兴。", "旋撷园蔬，随分成盘饤。", "说与翠微休急性，功名富贵皆前定。"]'),
('song-ci-899','南歌子','华岳','宋','宋词','song-ci','南歌子','[]','粉絮飘琼树，摇花结玉池。',62,'宋词/ci.song.20000.json','["粉絮飘琼树，摇花结玉池。", "蕊仙滕六逞瑰奇。", "都把银河细剪、做花飞。", "小院风声急，歌楼酒力微。", "闷中犹记去年时。", "呵手牵人相伴、塑狮儿。"]'),
('song-ci-900','望江南・忆江南','华岳','宋','宋词','song-ci','望江南・忆江南','[]','罗雾薄、绀绿拥重重。',64,'宋词/ci.song.20000.json','["罗雾薄、绀绿拥重重。", "八幅宝香薰锦绣，一床烟浪卷芙蓉。", "屏翠叠东风。", "云点缀，香汗透玲珑。", "螺髻松松沾玉润，樱唇浅浅印珠红。", "人在翠华中。"]'),
('song-ci-901','霜天晓角','华岳','宋','宋词','song-ci','霜天晓角','[]','情刀无斸。',52,'宋词/ci.song.20000.json','["情刀无斸。", "割尽相思肉。", "说后说应难尽，除非是、写成轴。", "帖儿烦付祝。", "休对傍人读。", "恐怕那懑知后，和它也泪瀑漱。"]'),
('song-ci-902','霜天晓角','华岳','宋','宋词','song-ci','霜天晓角','[]','蒲帆十幅。',52,'宋词/ci.song.20000.json','["蒲帆十幅。", "飞破秋江绿。", "天际彩虹千丈，阑干外、泻寒玉。", "一雨收残溽。", "云山开画轴。", "试问故人何处，青楼在画桥北。"]'),
('song-ci-903','满江红','华岳','宋','宋词','song-ci','满江红','[]','……正秋容万里，十分明洁。',43,'宋词/ci.song.20000.json','["……正秋容万里，十分明洁。", "后羿久忘逃去处，东方尚忆来年月。", "但无端、燕贺赋声诗，容凡客。"]'),
('song-ci-904','满江红','华岳','宋','宋词','song-ci','满江红','[]','庙社如今，谁复问、夏松殷柏。',115,'宋词/ci.song.20000.json','["庙社如今，谁复问、夏松殷柏。", "最苦是、二江涂脑，两淮流血。", "壮士气虹箕斗贯，征夫汗马兜鍪湿。", "问孙吴、黄石几编书，何曾识。", "青玉锁，黄金阙。", "车万乘，骓□匹。", "看长驱万里，直冲燕北。", "禹地悉归龙虎掌，尧天更展鵾鹏翼。", "指凌烟、去路复何忧，关山隔。"]'),
('song-ci-905','渔家傲','华岳','宋','宋词','song-ci','渔家傲','[]','昨夜寿星朝北极。',72,'宋词/ci.song.20000.json','["昨夜寿星朝北极。", "牵牛织女排筵席。", "闻有谪仙先一夕。", "方知得。", "凮流倬底人生日。", "慷慨英雄当路识。", "鹗书已凝循京秩。", "试问遐龄谁与敌。", "回ò绎。", "撇头添个长长十。"]'),
('song-ci-906','水调歌头','华岳','宋','宋词','song-ci','水调歌头','[]','英荚才开六，宝历已当千。',114,'宋词/ci.song.20000.json','["英荚才开六，宝历已当千。", "人间收尽繁溽，凉意入虞弦。", "尽道荐衡交剡，更值生申佳节，喜色动闾阎。", "终夜望银汉，文宿贯台躔。", "定燕秦，封晋魏，信当然。", "处处红莲开幕，曹掾岂能淹。", "见说玉堂飞诏，已许金闺通籍，蓬岛伴神仙。", "来岁寿卮酒，应醉御炉烟。"]'),
('song-ci-907','水调歌头','华岳','宋','宋词','song-ci','水调歌头','[]','万里楚天阔，一点寿星明。',126,'宋词/ci.song.20000.json','["万里楚天阔，一点寿星明。", "庭语以识歌舞，拍拍□秋声。", "会过牛郎六夕，圆欠嫦娥一夜，此际是佳辰。", "□□□□□，□□□□□赍予说，□神岳，庆生申。", "□领仓符，□兼漕节握藩旌。", "但□闽山建水，无地不阳春。", "今日范滂刘宴，来岁周公伊尹，元化斡洪钧。", "北阙中书今，南极老人星。"]'),
('song-ci-908','满江红','华岳','宋','宋词','song-ci','满江红','[]','帘拍风颠，云共雨、商量欲雪。',115,'宋词/ci.song.20000.json','["帘拍风颠，云共雨、商量欲雪。", "愁不寐、兽炉灰冷，寸肠千结。", "罗带只贪珠泪擤，金钗不整乌云侧。", "对菱花、空自敛双蛾，伤离别。", "心下事，凭谁说。", "愁与恨，如山积。", "被傍人调闻，呢龟成鳖。", "塞雁来时空怅望，梅花开后无消息。", "恨薄情、拚却与分飞，还重忆。"]'),
('song-ci-909','瑞鹧鸪','赵希蓬','宋','宋词','song-ci','瑞鹧鸪','[]','强将纸帐醉梅花。',64,'宋词/ci.song.20000.json','["强将纸帐醉梅花。", "千劫应知作热沙。", "梦逐梨云迷去路，曲随杨柳到伊家。", "客怀暗遣心头恨，醉眼休将口上夸。", "清晓酒醒人不见，离愁片片逐飞花。"]'),
('song-ci-910','瑞鹧鸪','赵希蓬','宋','宋词','song-ci','瑞鹧鸪','[]','把定离觞不肯斟。',64,'宋词/ci.song.20000.json','["把定离觞不肯斟。", "闻君未醉尽衷情。", "丁香空结千般恨，柳线难萦一片心。", "只把文章酧素愿，莫贪歌舞阻归程。", "凭君试问湘江竹，班是阿谁旧染成。"]'),
('song-ci-911','瑞鹧鸪','赵希蓬','宋','宋词','song-ci','瑞鹧鸪','[]','长亭无路对孤斟。',64,'宋词/ci.song.20000.json','["长亭无路对孤斟。", "自古离家三日情。", "慷慨要酬平昔志，猖狂休起少年心。", "兰闺寂寂空回首，松盖亭亭认去程。", "展转清宵成不寐，巫山有梦几时成。"]'),
('song-ci-912','瑞鹧鸪','赵希蓬','宋','宋词','song-ci','瑞鹧鸪','[]','温柔乡里睹春容。',64,'宋词/ci.song.20000.json','["温柔乡里睹春容。", "无语闲将脚带松。", "魂梦阳台迷暮雨，丰姿洛浦挹仙风。", "追陪梅下黄昏路，仿佛槐安富贵宫。", "旧恨上心空有感，扫除全付一杯中。"]'),
('song-ci-913','念奴娇','赵希蓬','宋','宋词','song-ci','念奴娇','["\u8861\u5c71"]','功名富贵，算到头，怎免委沟填壑。',120,'宋词/ci.song.20000.json','["功名富贵，算到头，怎免委沟填壑。", "曳钓抱琴秋水畔，肯与微官空缚。", "五亩苍阴，一丘寒碧，说甚凌烟阁。", "静观物理，从他荣悴开落。", "任待入谷鸣雏，不须歆艳，免使朝南岳。", "修竹长松常与伴，更有寒梅堪约。", "夜且三更，西风万籁，入耳悲猿鹤。", "从头洗去，更无一点圭角。"]'),
('song-ci-914','蝶恋花','赵希蓬','宋','宋词','song-ci','蝶恋花','[]','昼永无人深院静。',70,'宋词/ci.song.20000.json','["昼永无人深院静。", "一枕春醒，犹未忺临镜。", "帘卷新蟾光射影。", "连忙掠起蓬松鬓。", "对景沉吟嗟没兴。", "薄幸不来，空把杯盘饤。", "休道妇人多水性。", "今宵独自言无定。"]'),
('song-ci-915','南歌子','赵希蓬','宋','宋词','song-ci','南歌子','[]','玉立亭亭树，水澌小小池。',62,'宋词/ci.song.20000.json','["玉立亭亭树，水澌小小池。", "园林遍地幻珍奇。", "战罢奇鳞无数、满天飞。", "云冻风威惨，天低月色微。", "红绡暖帐浅斟时。", "那更樽前清韵、听歌儿。"]'),
('song-ci-916','霜天晓角','赵希蓬','宋','宋词','song-ci','霜天晓角','[]','枕痕如斫。',51,'宋词/ci.song.20000.json','["枕痕如斫。", "一线红生肉。", "睡起娇羞无语，远山坐对横轴。", "烧香频祷祝。", "偷把简儿读。", "字在那人何在，泪珠飞下蔌蔌。"]'),
('song-ci-917','满江红','赵希蓬','宋','宋词','song-ci','满江红','[]','干结青铜，根走石、参天古柏。',115,'宋词/ci.song.20000.json','["干结青铜，根走石、参天古柏。", "最好是、苍阴不怕，火云如血。", "雪里直疑神物护，雨馀任待霜皮湿。", "但只愁、涧底老风烟，无人识。", "栋梁用，知难缺。", "轮囷辈，俱非匹。", "望长松万丈，徂徕山北，一种刚姿雕样劲，共扶大厦翬斯翼。", "便作舟、归去也何愁，蓬莱隔。"]'),
('song-ci-918','满江红','赵希蓬','宋','宋词','song-ci','满江红','[]','休羡莺花，春富贵、韶光九十。',115,'宋词/ci.song.20000.json','["休羡莺花，春富贵、韶光九十。", "最好是、清秋时候，人间何夕。", "天上紫云车趣驾，殿中青鸟音传实。", "正女牛、南极一齐明，光相敌。", "诗在手，堂趋北。", "染豪处，池翻黑。", "看回鸾飞诰，宠封新国。", "福比箕畴兼备五，寿除彭祖千中一。", "更好将、大衍数重推，来复日。"]'),
('song-ci-919','满江红','赵希蓬','宋','宋词','song-ci','满江红','[]','七叶蓂开，正祈巧、穿针时节。',114,'宋词/ci.song.20000.json','["七叶蓂开，正祈巧、穿针时节。", "织女不骖王母驾，谪生名阅。", "鹤算七旬书宝箓，鹊桥千丈飞银阙。", "更玳筵、银烛照红妆，神仙列。", "歌宛转，莺调舌。", "番舞袖，风回雪。", "对寿觞频劝，寿星明洁。", "今日汉宫千岁药，明年唐殿长生月。", "问班衣、戏彩是何人，蓝袍客。"]'),
('song-ci-920','满江红','赵希蓬','宋','宋词','song-ci','满江红','[]','缟兔黔乌，送不了、人间昏晓。',115,'宋词/ci.song.20000.json','["缟兔黔乌，送不了、人间昏晓。", "问底事、红尘野马，浮生扰扰。", "万古末来千古往，人生得失知多少。", "叹荣华、过眼只须臾，如风扫。", "篱下菊，门前柳。", "身外事，杯中酒。", "肯教它萧瑟，负持螯手。", "漠漠江南天万里，白云入望何时到。", "倚西风、吼彻剑花寒，频搔首。"]'),
('song-ci-921','菩萨蛮','赵希蓬','宋','宋词','song-ci','菩萨蛮','[]','何人四座环歌扇。',52,'宋词/ci.song.20000.json','["何人四座环歌扇。", "平生有限何曾见。", "今日忽遭逢，流霞映脸红。", "此恨凭谁语，梦逐巫山去。", "对景苦奔波，其如愁思何。"]'),
('song-ci-922','菩萨蛮','赵希蓬','宋','宋词','song-ci','菩萨蛮','[]','慧刀挥处人头落。',52,'宋词/ci.song.20000.json','["慧刀挥处人头落。", "虹霓万道冲云脚。", "灭尽我人心，何劳向外寻。", "白莲生火里，法忍无生死。", "忍辱两皆空，龟毛兔角同。"]'),
('song-ci-923','渔家傲','赵希蓬','宋','宋词','song-ci','渔家傲','[]','怪见台星离紫极。',72,'宋词/ci.song.20000.json','["怪见台星离紫极。", "果然揆左还虚席。", "明日人间逢七夕。", "真难得。", "生贤特也涓良日。", "饤坐侯鲭人罕识。", "流璃都把宾筵秩。", "寿祝乔松谁与敌。", "珠落绎。", "樽前一列金钗十。"]'),
('song-ci-924','水调歌头','赵希蓬','宋','宋词','song-ci','水调歌头','[]','熟见蟠桃几，岁阅大椿千。',113,'宋词/ci.song.20000.json','["熟见蟠桃几，岁阅大椿千。", "鞭鸾间出簇拥，仙仗蔼丝弦。", "落尽纨罗习气，都把诗书酝籍，忧念到闾阎。", "人物降崧岳，文采焕奎躔。", "抟扶摇，游汗漫，气飘然。", "珠曹莲区区，州县步难淹。", "鹗荐交腾当路，凤诏飞来伊夕，称寿萃群仙。", "事业登黄阁，图绘上凌烟。"]'),
('song-ci-925','满江红','赵希蓬','宋','宋词','song-ci','满江红','["\u957f\u6c5f"]','劲节刚姿，谁与比、岁寒松柏。',115,'宋词/ci.song.20000.json','["劲节刚姿，谁与比、岁寒松柏。", "几度欲、排云呈腹，叩头流血。", "杜老爱君□谩苦，贾生流涕衣空湿。", "为国家、子细计安危，渊然识。", "英雄士，非全阙。", "东南富，尤难匹。", "却甘心修好，无心逐北。", "螳怒空横林影臂，鹰扬不展秋空翼。", "但只将、南北限藩篱，长江隔。"]'),
('song-ci-926','满江红','赵希蓬','宋','宋词','song-ci','满江红','[]','海阔何人，工剪水、飞花作雪。',115,'宋词/ci.song.20000.json','["海阔何人，工剪水、飞花作雪。", "刚不北、秋高风劲，露凝霜洁。", "遍地直疑琼玉砌，对人恍在珠玑侧。", "比寻常、万翠与千红，浑然别。", "梁园内，都休说。", "蓝关路，堆如积。", "把行人冻得，头颅如鳌。", "翡翠帘中杯潋滟，销金帐里姑情息。", "偶兴来、访戴起山阴，真相忆。"]'),
('song-ci-927','水调歌头','程伯春','宋','宋词','song-ci','水调歌头','[]','功名果何物，天欲付英豪。',114,'宋词/ci.song.20000.json','["功名果何物，天欲付英豪。", "请看襄汉，今日谁驾六灵鳌。", "阅礼崇诗元帅，大纛高牙临塞，砥柱一洪涛。", "百辟拱辰极，欢动赭黄袍。", "策无遗，勋益著，德弥高。", "定知阳报，谢庭兰玉付儿曹。", "秀发如君独擅，浑似当年幼度，文武素兼韬。", "岁岁长为寿，霞液荐蟠桃。"]'),
('song-ci-928','满庭芳','赵良玉','宋','宋词','song-ci','满庭芳','[]','红杏香中，绿杨影里，画桥春水泠泠。',118,'宋词/ci.song.20000.json','["红杏香中，绿杨影里，画桥春水泠泠。", "深沉院满，风送卖花声。", "又是清明近也，粉墙畔，时有迁莺。", "当此际，人传天上，特降玉麒麟。", "风云。", "今会遇，名邦坐抚，入侍严宸。", "更儿孙兰玉，都是宁馨。", "脆管繁弦竞奏，蕙炉袅，沉水烟轻。", "华筵罢，江城回首，一点寿星明。"]'),
('song-ci-929','减字木兰花','赵孟谦','宋','宋词','song-ci','减字木兰花','[]','荣魁鹗荐。',52,'宋词/ci.song.20000.json','["荣魁鹗荐。", "一举南宫膺妙选。", "人物规模。", "楚楚吾家千里驹。", "彩衣侍酒。", "更祝二亲无限寿。", "父子荣迁。", "俱侍玉皇香案前。"]'),
('song-ci-930','贺新郎','张明中','宋','宋词','song-ci','贺新郎','[]','卓茕欧阳子。',142,'宋词/ci.song.20000.json','["卓茕欧阳子。", "是江山、毓秀锺灵，异才间世。", "恰则韶光三月暮，蓂叶尧阶有四。", "正天启、悬弧盛事。", "金鸭亭亭书云篆，散非烟、南极真仙至。", "来为尔，荐嘉瑞。", "神清洞府丹书字。", "拥笙歌、绮席高张，更罗珠翠。", "千里长春人不老，仙籍玉环暗记。", "但判取、醄醄沉醉。", "拟作新诗八千首，待一年、一献称俾尔。", "耆而艾，昌而炽。"]'),
('song-ci-931','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','四大因缘做，苦海凭船渡。',52,'宋词/ci.song.20000.json','["四大因缘做，苦海凭船渡。", "一棹清风到岸头，得上无生路。", "人叹风贫苦，我步闲闲趣。", "脱体全空没一文，胜似石崇富。"]'),
('song-ci-932','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','自入玄门户，寂寂清虚做。',52,'宋词/ci.song.20000.json','["自入玄门户，寂寂清虚做。", "静里披搜四假身，勘破尘行路。", "悟上还重悟，得得真闲趣。", "收住身中无价真，岂逐人情去。"]'),
('song-ci-933','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','风汉闲中做，彼岸神舟渡。',52,'宋词/ci.song.20000.json','["风汉闲中做，彼岸神舟渡。", "万里晴空无片云，月照南溪路。", "割断冤情苦，默默明玄趣。", "一任傍人笑我贫，肚里非常富。"]'),
('song-ci-934','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','纤软小腰身，明秀天真面。',52,'宋词/ci.song.20000.json','["纤软小腰身，明秀天真面。", "淡画修眉小作春，中有相思怨。", "昔立向人羞，颜破因谁倩。", "不比阳台梦里逢，亲向尊前见。"]'),
('song-ci-935','卜算子','刘克庄','宋','宋词','song-ci','卜算子','[]','梅岭数枝春，疏影斜临水。',52,'宋词/ci.song.20000.json','["梅岭数枝春，疏影斜临水。", "不借芳华只自香，娇面长如洗。", "还把最繁枝，过与偏怜底。", "试把鸾台子细看，何似丹青里。"]'),
('song-ci-936','满江红','方岳','宋','宋词','song-ci','满江红','[]','晓傍苍崖，滴寒露、研朱点易。',114,'宋词/ci.song.20000.json','["晓傍苍崖，滴寒露、研朱点易。", "五十四卦为归姝，惟幽人吉。", "彼美人兮春上下，如吾徒者山南北。", "辨一生、坚壁卧烟霞，诗无敌。", "人间世，胶中漆。", "功名事，刀头蜜。", "放乾坤醉眼，看朱成碧。", "曾共梅花相尔汝，仅教雪后无消息。", "莫怕寒、容易嫁东风，春狼藉。"]'),
('song-ci-937','水调歌头','方岳','宋','宋词','song-ci','水调歌头','[]','老子兴不浅，归矣复言归。',114,'宋词/ci.song.20000.json','["老子兴不浅，归矣复言归。", "不知归又何处，知我者何希。", "幸有青山一片，付与白云千载，便可乐渔矶。", "且尽一杯酒，春瓮晓生肥。", "倩梅花，邀涧叟，醉林扉。", "五年今已如此，莫倚健於飞。", "日月笼中双鸟，今古人间一马，五十五年非。", "归去不归去，未了比山薇。"]'),
('song-ci-938','满庭芳','方岳','宋','宋词','song-ci','满庭芳','[]','雨带苍烟，须粘残雪，几年今日秋崖。',118,'宋词/ci.song.20000.json','["雨带苍烟，须粘残雪，几年今日秋崖。", "梅花篱落，不减旧情怀。", "更觉神仙有分，一条冰、羽客官阶。", "朝真外，研朱点易，风露滴松钗。", "蓬莱。", "清浅未，吾将游戏，月坞云齐。", "已相期汗漫，鹤蜕青鞋。", "一念人间尘土，为雏孙、留醉茅柴。", "今而后，村书杂字，仅有老生涯。"]'),
('song-ci-939','江城子','方岳','宋','宋词','song-ci','江城子','[]','几年诗骨雪槎牙。',86,'宋词/ci.song.20000.json','["几年诗骨雪槎牙。", "痼烟霞。", "老生涯。", "五十八翁，堪喜亦堪嗟。", "忽忆香山居士语，还失笑，较争些。", "荒寒梅坞月横斜。", "短篱遮。", "野人家。", "枝北枝南，须有两三花。", "紧闭竹门传语客，那得暇，尽由他。"]'),
('song-ci-940','永遇乐','郭子正','宋','宋词','song-ci','永遇乐','[]','多种阴功，后蒙天报，荣贵长久。',129,'宋词/ci.song.20000.json','["多种阴功，后蒙天报，荣贵长久。", "一片灵台，丹青要画，画请看人间秀。", "慈仁雅着，延永松年，内鼎有丹方就。", "想除非，真的高人，五福自然兼有。", "从来义方，今见公辅，量运夔龙居后。", "承北门风，相传世业，都是经邦手。", "狂歌将意，知公难老，永助庆堂尊酒。", "有重重，腰金孙子，继来献寿。"]'),
('song-ci-941','菩萨蛮','朱子厚','宋','宋词','song-ci','菩萨蛮','[]','酴醿浴罢温香玉。',52,'宋词/ci.song.20000.json','["酴醿浴罢温香玉。", "牡丹睡起歌云绿。", "弹压属东阳。", "留春在庆堂。", "简端新组绶。", "辉映烟岚秀。", "妙曲倩清妍。", "祝君无尽年。"]'),
('song-ci-942','失调名','张埴','宋','宋词','song-ci','失调名','[]','玉宇风清，金茎露爽，五日新秋。',60,'宋词/ci.song.20000.json','["玉宇风清，金茎露爽，五日新秋。", "正好小轩，相逢初度，七十边头。", "满前白发けけ。", "有抱得曾孙弄否。", "从此长看，星明南极，人醉西楼。"]'),
('song-ci-943','瑞鹧鸪','汪元量','宋','宋词','song-ci','瑞鹧鸪','[]','内家雨宿日辉辉。',64,'宋词/ci.song.20000.json','["内家雨宿日辉辉。", "夹遥桃花张锦机。", "黄纛软舆抬圣母，红罗凉伞罩贤妃。", "龙舟缥缈摇红影，羯鼓喧哗撼绿漪。", "阿监柳亭排燕处，美人斗把玉箫吹。"]'),
('song-ci-944','汉宫春','汪元量','宋','宋词','song-ci','汉宫春','[]','玉砌雕栏。',118,'宋词/ci.song.20000.json','["玉砌雕栏。", "见吴宫西子，一笑嫣然。", "舞困人间半亸，艳粉争妍。", "珠帘尽卷，看人间、金屋神仙。", "歌队里，霞裾袅娜，百般娇态堪怜。", "别有一枝仙种，更同心并蒂，来奉君筵。", "猩蜃若教解语，曲谱应传。", "柘黄独步，昼笼睛，锦幄张天。", "试剪插，金瓶千朵，醉时细看婵娟。"]'),
('song-ci-945','瑶花','汪元量','宋','宋词','song-ci','瑶花','[]','天中树木，高耸玲珑，向濯缨亭曲。',125,'宋词/ci.song.20000.json','["天中树木，高耸玲珑，向濯缨亭曲。", "繁枝缀玉。", "开朵朵九出。", "飞琼环簇。", "唐昌曾见，有玉女、来送春目，更月夜、八仙相聚。", "素质粲然幽独。", "江淮倦客再游，访后土琼英，树已倾覆，攀条掐干，细嗅来、尚有微微清馥。", "却疑天上列燕赏，催汝归速。", "恐后时、重谪人间，剩把铅华妆束。"]'),
('song-ci-946','莺啼序','汪元量','宋','宋词','song-ci','莺啼序','["\u897f\u6e56"]','檀栾宫墙数仞，敞朱帘绣户。',293,'宋词/ci.song.20000.json','["檀栾宫墙数仞，敞朱帘绣户。", "正春暖、飘拂和风，衮入红尘香雾。", "见丝柳青青，袅娜如学宫腰舞。", "有黄莺、恰恰飞来，一梭金羽。", "小巧身儿，锦心绣口，圆滑遽如许。", "避人，渐飞入琼林藏身，桃杏深处。", "对银屏、珠圆翠陈，隔叶底、恣歌金缕。", "忽群妃，拍手惊飞，奋然高举。", "晓来雨湿，花娜柳垂，误投罗网去。", "缓缓访、六宫寻问，玉纤争握。", "放入金笼，眼娇眉妩。", "身如旅琐，无心求友。", "烟窗分影光阴里，听蛮声，似怨还如诉。", "青山隔断，红妆满眼，谁怜一匊。", "幽恨难吐，沉香拂拂。", "亭北阑干，已得君王顾。", "但暗忆、西湖美景，雨色晴光，入翠穿红，巧转娇语。", "莺莺休怨天家，已赠金衣公子。", "生前号这恩荣，物类将何补。", "娇黄白奏词臣，为尔翻成，太平乐府。"]'),
('song-ci-947','失调名','汪元量','宋','宋词','song-ci','失调名','[]','绿荷初展。',112,'宋词/ci.song.20000.json','["绿荷初展。", "海榴花半吐，绣帘高卷。", "整顿朱弦，奏霓裳初遍，音清意远。", "恍然在广寒宫殿，窈窕柔情，绸缪细意，闲愁难剪。", "曲中似哀似怨。", "似梧桐叶落，秋雨声颤。", "岂待闻铃，自泪珠如霰。", "春纤罢按，早心已笑慵歌懒。", "脉脉凭栏，槐阴转午，轻摇歌扇。"]'),
('song-ci-948','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','神舟稳驾出沉流。',36,'宋词/ci.song.20000.json','["神舟稳驾出沉流。", "明月辉辉命自周。", "两个先生暗点头。", "有来由。", "万劫轮回向此休。"]'),
('song-ci-949','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','修行谁会把心降。',36,'宋词/ci.song.20000.json','["修行谁会把心降。", "赤凤驱将饮碧江。", "调引婴娇笑舞双。", "剔银缸。", "物物头头现晓窗。"]'),
('song-ci-950','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','从初得得便风流。',36,'宋词/ci.song.20000.json','["从初得得便风流。", "降伏龟蛇住定州。", "千日丹成永永收。", "好因由。", "自在逍遥万事休。"]'),
('song-ci-951','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','心中无事气神和。',36,'宋词/ci.song.20000.json','["心中无事气神和。", "不觉忻忻言语多。", "剑用道钢磨更磨。", "害风哥。", "割了舌头赶退魔。"]'),
('song-ci-952','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','尘寰财色苦相萦。',36,'宋词/ci.song.20000.json','["尘寰财色苦相萦。", "著爱浮华役此身。", "好收灵源一点真。", "绝贪嗔。", "便是逍遥到岸人。"]'),
('song-ci-953','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','无无无有有无无，悟得无无便不愚。',36,'宋词/ci.song.20000.json','["无无无有有无无，悟得无无便不愚。", "日月年时损壮粗。", "见元初。", "万道霞光攒宝珠。"]'),
('song-ci-954','忆王孙','汪元量','宋','宋词','song-ci','忆王孙','[]','茫茫苦海两无边。',36,'宋词/ci.song.20000.json','["茫茫苦海两无边。", "无限迷鱼戏黑渊。", "我掷金钩钓有缘。", "线儿牵。", "引上神州采玉莲。"]'),
('song-ci-955','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','笑盈盈。',56,'宋词/ci.song.20000.json','["笑盈盈。", "晓妆扫出长眉青。", "长眉青。", "双开雉扇，六曲鸳屏。", "少年心在尚多情。", "酒边银甲弹长筝。", "弹长筝。", "碧桃花下，醉到三更。"]'),
('song-ci-956','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','雪霏霏。',56,'宋词/ci.song.20000.json','["雪霏霏。", "蓟门冷落人行稀。", "人行稀。", "秦娥渐老，着破宫衣。", "强将纤指按金徽。", "未成曲调心先悲。", "心先悲。", "更无言语，玉箸双垂。"]'),
('song-ci-957','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','天沉沉。',56,'宋词/ci.song.20000.json','["天沉沉。", "香罗拭泪行穷阴。", "行穷阴。", "左霜右雪，冷气难禁。", "几回相忆成孤斟。", "塞边鞞鼓愁人心。", "愁人心。", "北鱼南雁，望到而今。"]'),
('song-ci-958','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','["\u957f\u6c5f"]','水悠悠。',56,'宋词/ci.song.20000.json','["水悠悠。", "长江望断无归舟。", "无归舟。", "欲携斗酒，怕上高楼。", "当年出塞拥貂裘。", "更听马上弹箜篌。", "弹箜篌。", "万般哀怨，一种离愁。"]'),
('song-ci-959','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','风声恶。',56,'宋词/ci.song.20000.json','["风声恶。", "个人蕉萃凭高阁。", "凭高阁。", "相思无尽，泪珠偷落。", "锦书欲寄鸿难托。", "那堪更听边城角。", "边城角。", "又添烦恼，又添萧索。"]'),
('song-ci-960','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','如何说。',56,'宋词/ci.song.20000.json','["如何说。", "人生自古多离别。", "多离别。", "年年辜负，海棠时节。", "娇娇独坐成愁绝。", "胡笳吹落关山月。", "关山月。", "春来秋去，几番圆缺。"]'),
('song-ci-961','忆秦娥','汪元量','宋','宋词','song-ci','忆秦娥','[]','马萧萧。',56,'宋词/ci.song.20000.json','["马萧萧。", "燕支山中风飘飘。", "风飘飘。", "黄昏寒雨，直是无憀。", "玉人何处教吹箫。", "十年不见心如焦。", "心如焦。", "彩笺难寄，水远山遥。"]'),
('song-ci-962','人月圆','汪元量','宋','宋词','song-ci','人月圆','["\u94b1\u5858\u6c5f"]','钱塘江上春潮急，风卷锦帆飞。',59,'宋词/ci.song.20000.json','["钱塘江上春潮急，风卷锦帆飞。", "不堪回首，离宫别馆，杨柳依依。", "蓟门听雨，燕台听雪，寒入宫衣。", "娇鬟慵理，香肌瘦损，红泪双垂。"]'),
('song-ci-963','太常引','汪元量','宋','宋词','song-ci','太常引','[]','广寒宫殿五云边。',62,'宋词/ci.song.20000.json','["广寒宫殿五云边。", "看天上、烛金莲。", "香袅御炉烟。", "拥彩仗、千官肃然。", "世间王母，月中仙子，花甲一周天。", "乐指沸华年，更福寿，千年万年。"]'),
('song-ci-964','婆罗门引','汪元量','宋','宋词','song-ci','婆罗门引','[]','一生富贵，岂知今日有离愁。',89,'宋词/ci.song.20000.json','["一生富贵，岂知今日有离愁。", "锦帆风力难收。", "望断燕山蓟水，万里到幽州。", "恨病馀双眼，冷泪交流。", "行年已休岁，七十又平头。", "梦破银屏金屋，此意悠悠。", "几度见青冢，虚名不足留。", "且把酒、细听箜篌。"]'),
('song-ci-965','锦瑟清商引','汪元量','宋','宋词','song-ci','锦瑟清商引','[]','玉窗夜静月流光。',131,'宋词/ci.song.20000.json','["玉窗夜静月流光。", "拂鸳弦、先奏清商。", "天外塞鸿飞呼，群夜渡潇湘。", "风回处，戛玉铿金，翩翩作新势，声声字字，历历锵锵。", "忽低颦有恨，此意极凄凉。", "炉香帘栊正清洒，转调促柱成行。", "机籁杂然鸣素手，击碎琳琅。", "翠云深梦里昭阳。", "此心长。", "回顾穷阴绝漠，片影悠扬。", "那昭君更苦，香泪湿红裳。"]'),
('song-ci-966','玉楼春','汪元量','宋','宋词','song-ci','玉楼春','["\u9ec4\u6cb3"]','咸淳十载聪明帝。',64,'宋词/ci.song.20000.json','["咸淳十载聪明帝。", "不见宋家陵寝废。", "暂离绛阙九重天，飞过黄河千丈水。", "长春宫殿仙璈沸。", "嘉会今辰为愍忌。", "小儒百拜酹霞觞，寡妇孤儿流血泪。"]'),
('song-ci-967','玉楼春','汪元量','宋','宋词','song-ci','玉楼春','[]','帝乡春色浓於雾。',64,'宋词/ci.song.20000.json','["帝乡春色浓於雾。", "谁遣双环堆绣户。", "金张公子总封侯，姚魏弟兄皆列士。", "碧纱窗下修花谱。", "交颈鸳鸯娇欲语。", "绛绡新结转官球，桃李仆奴何足数。"]'),
('song-ci-968','满庭芳','丁无悔','宋','宋词','song-ci','满庭芳','[]','道格天渊，令行海岳，凛然名德尊崇。',118,'宋词/ci.song.20000.json','["道格天渊，令行海岳，凛然名德尊崇。", "云烟千里，分付笑谈中。", "川后波神效职，潮声细、一鉴涵空。", "风樯便，蛮珠贾舶，累译更遥通。", "雍容。", "廊庙手，蓍龟先见，日月精忠。", "自丛机初解，眷渥尤隆。", "共道奇庞福艾，衮衣到，宁久居东。", "谁门晓，高牙大纛，辉映醉颜红。"]'),
('song-ci-969','满庭芳','丁无悔','宋','宋词','song-ci','满庭芳','[]','偃屋霜清，棱层烟碧，玲珑移在人间。',118,'宋词/ci.song.20000.json','["偃屋霜清，棱层烟碧，玲珑移在人间。", "山光林色，常伴主人闲。", "元有仙风道骨，无心趁、玉简朝班。", "归来赋，不因五斗，谈笑挂衣冠。", "尤难。", "谁不羡，商山桔乐，湄水渔竿。", "引相君王子，助发幽欢。", "满泛寿觞多祝，南溟共、比海波澜。", "君知否，庙堂有意，相与问寒岩。"]'),
('song-ci-970','喜迁莺','杨再可','宋','宋词','song-ci','喜迁莺','[]','腊天初晓，庆五色瑞云，华轩呈绕。',126,'宋词/ci.song.20000.json','["腊天初晓，庆五色瑞云，华轩呈绕。", "紫府真人，丹台仙伯，合降世间荣耀。", "彩笔素题，篇翰未减，家声词藻。", "秀眉宇，俊丰标阀阅，声名都好。", "富贵长欢笑。", "此际锦堂，移下蓬莱岛。", "妙舞蹁跹，清歌宛转，两行翠娥燕赵。", "劝饮百千锺酒，岁岁朱颜不老。", "春近也，看香红又怕，小桃开了。"]'),
('song-ci-971','水调歌头','刘仲讷','宋','宋词','song-ci','水调歌头','[]','昨夜乘秋兴，长啸驭清风。',115,'宋词/ci.song.20000.json','["昨夜乘秋兴，长啸驭清风。", "飘然玉宇虚廓，忽到广寒宫。", "解后姮娥相见，为问中秋诞节，奇特世难同。", "底事长庚梦，独占此宵中。", "呼金兔，寻玉策，检前踪。", "自从盘古有月，便有此山仙翁。", "公向人间游戏，月在天衢来往，清气每相通。", "明月既无尽，公寿亦无穷。"]'),
('song-ci-972','水调歌头','蒋思恭','宋','宋词','song-ci','水调歌头','[]','紫府掣金钥，银汉夜乘槎。',114,'宋词/ci.song.20000.json','["紫府掣金钥，银汉夜乘槎。", "老仙暂驻幢节，来佐玉皇家。", "翠发朱颜好在，肘后有方医国，宝鼎养丹砂。", "谈笑功名了，身退饭胡麻。", "游物外，聚紫脑，炼青芽。", "星坦寓直有子，曾步八砖花。", "来岁称觞寿宴，衮绣彩衣交映，重荐枣如瓜。", "俯首拾瑶草，长啸卧烟霞。"]'),
('song-ci-973','水调歌头','蒋思恭','宋','宋词','song-ci','水调歌头','[]','风流九霞客，名在五云乡。',114,'宋词/ci.song.20000.json','["风流九霞客，名在五云乡。", "十年出入华禁，簪橐奉君王。", "黄伞西清日转，宝月红鸾影里，长近赭袍光。", "彩笔赓歌处，殿阁有馀凉。", "跨秋风，凌宝鼎，笑芝房。", "人间争识奇贵，妙帖焕名章。", "莫羡碧幢金印，换取玉堂清琐，翰墨看淋浪。", "岁岁宫壶酒，雨露带天香。"]'),
('song-ci-974','洞仙歌','张成可','宋','宋词','song-ci','洞仙歌','[]','薰风池阁，八叶蓂初展。',103,'宋词/ci.song.20000.json','["薰风池阁，八叶蓂初展。", "紫府当年侍香案。", "见蟠桃频着子，偷荐瑶觞，贪醉寐，谪向人间未满。", "青禽传近信，催赴仙班，怪我尘缘未能断。", "爱吴中山色好，抹日批风，蓑共笠，纵有金章不换。", "待驾鹤遨访蓬壶，问海水从来，几番增减。"]'),
('song-ci-975','醉蓬莱','丁仲远','宋','宋词','song-ci','醉蓬莱','[]','正霜融日暖，风淡寒轻，小春时候。',120,'宋词/ci.song.20000.json','["正霜融日暖，风淡寒轻，小春时候。", "后苑疏梅早放，数枝开就。", "知是花工，预回天气，与作仙翁寿。", "君看侯门，祥云锁戟，瑞烟笼昼。", "天赋麒麟风骨，尽道德耀宗盟，名高星斗。", "两郡甘棠，惠爱传民口。", "宣室思贤，锋车促召，行矣应非久。", "衣锦归来，双亲笑喜，朱颜如旧。"]'),
('song-ci-976','水龙吟','真知柔','宋','宋词','song-ci','水龙吟','[]','碧霄彩旆垂铃，应南极星躔光灿。',125,'宋词/ci.song.20000.json','["碧霄彩旆垂铃，应南极星躔光灿。", "巍巍名阀，芳传汉相，貂蝉炳焕。", "德莹冰壶，量包沧海，神锺岩电。", "向宝储内阁，英摽才华，声猷著膺宸眷。", "荐领名都屏翰，更循良、歌腾畿甸。", "峻专剧郡，荣登法从，光生尧殿。", "密勿论思，雍容启沃，才华独冠。", "愿年年长见，兰芽玉喷，柳梢金嫩。"]'),
('song-ci-977','玉楼春','张时甫','宋','宋词','song-ci','玉楼春','[]','姑苏台上春光发。',64,'宋词/ci.song.20000.json','["姑苏台上春光发。", "菊老寒轻香未歇。", "人言太守是龚黄，天为吾君生稷契。", "月良庆会俱良月。", "万岁千秋同瑞节。", "明朝仙领趣提鳌，十万人家齐卧辙。"]'),
('song-ci-978','玉楼春','张时甫','宋','宋词','song-ci','玉楼春','[]','蟠桃十月惊春早。',64,'宋词/ci.song.20000.json','["蟠桃十月惊春早。", "春到玉梅枝上小。", "和羹人物应时生，天上骑鲸生凤沼。", "万家宝篆祥烟晓。", "竞祝史君长不老。", "夜来南极照元台，见说沙堤新筑了。"]'),
('song-ci-979','玉楼春','李朝卿','宋','宋词','song-ci','玉楼春','[]','谪仙暂下金銮殿。',64,'宋词/ci.song.20000.json','["谪仙暂下金銮殿。", "开宴瑶池春未晚。", "飞琼献舞锦靴寒，弄玉吹箫银字暖。", "奉觞阿母年年劝，犹道碧桃香尚浅。", "花开更待几东风，应见年华千岁换。"]'),
('song-ci-980','玉楼春','李朝卿','宋','宋词','song-ci','玉楼春','[]','炉烟不断腾金兽。',64,'宋词/ci.song.20000.json','["炉烟不断腾金兽。", "香雾入帘波影皱。", "秋堂锦席艳群仙，不惜绮罗萦舞袖。", "昼弦素管春风手，娇妙如花轻似柳。", "劝君须尽眼中欢，绿酒十分千秋寿。"]'),
('song-ci-981','玉楼春','李朝卿','宋','宋词','song-ci','玉楼春','[]','厌玉为浆麟作□。',64,'宋词/ci.song.20000.json','["厌玉为浆麟作□。", "玉树琼葩长不谢。", "翠帘绣暖燕归来，宝鸭花香蜂上下。", "沙堤佩马催公驾，月白风清天不夜。", "重来赫赫照岩廊，不动堂堂凝泰华。"]'),
('song-ci-982','小重山','李朝卿','宋','宋词','song-ci','小重山','[]','春正浓时月正圆。',70,'宋词/ci.song.20000.json','["春正浓时月正圆。", "华堂初燕喜，雨真仙。", "霞衣相对旧貂蝉。", "人间少，福寿子孙贤。", "□□佳非烟。", "花光羞粉艳，敢争妍。", "笑歌声里捧金舡。", "深深愿，松柏永同坚。"]'),
('song-ci-983','鹧鸪天','李朝卿','宋','宋词','song-ci','鹧鸪天','[]','万里霜空爽气高。',64,'宋词/ci.song.20000.json','["万里霜空爽气高。", "翩翩天雁薄云霄。", "佳祥已协当年梦，岂但非熊可珥貂。", "金笏带，紫花袍。", "朱衣双引玉宸朝。", "百年富贵须平步，仍有功名信史褒。"]'),
('song-ci-984','西江月','李朝卿','宋','宋词','song-ci','西江月','[]','盛德须知异禀，天教占尽秋光。',58,'宋词/ci.song.20000.json','["盛德须知异禀，天教占尽秋光。", "一轮明月照华堂。", "荐寿笙歌嘹亮。", "座上簪缨并列，庭前兰玉成行。", "只应难老胜松篁。", "五福人间供仰。"]'),
('song-ci-985','踏莎行','李朝卿','宋','宋词','song-ci','踏莎行','[]','月挂琼钩，日添绣线。',68,'宋词/ci.song.20000.json','["月挂琼钩，日添绣线。", "骑花翻浪重帘卷。", "风传环珮晓珊珊，画堂羯鼓催开宴。", "翠缕香凝，玉膏酒滟。", "仙翁莫诉玻璃满。", "凤衔丹诏下云电。", "千秋长在黄金殿。"]'),
('song-ci-986','鹧鸪天','李朝卿','宋','宋词','song-ci','鹧鸪天','[]','九凤箫低彩雾高。',64,'宋词/ci.song.20000.json','["九凤箫低彩雾高。", "鸾车鹤驭下层霄。", "天教来辅长生帝，宝殿千秋侍赭袍。", "飞急召，促归朝。", "沙路稳为马蹄娇。", "功成并画兰台上，奎画重看御赞褒。"]'),
('song-ci-987','青玉案','谈元范','宋','宋词','song-ci','青玉案','[]','虾须帘上银钩小。',78,'宋词/ci.song.20000.json','["虾须帘上银钩小。", "筵内轻寒绕。", "红叶徵香侵语笑。", "金钗珠履，凤萧龟鼓，疑是蓬莱岛。", "萱堂日日春生貌。", "嫩绿休然鬓边好。", "赋得修龄应不少。", "年年长见，画梁双燕，楼外青袍草。"]'),
('song-ci-988','青玉案','倪翼周','宋','宋词','song-ci','青玉案','[]','烟浓水淡荷香浅。',80,'宋词/ci.song.20000.json','["烟浓水淡荷香浅。", "近翠幕、闻弦管。", "逸气棱层冲碧汉。", "绝无风骨，炼成铅鼎，未许童颜换。", "长门深锁文君院。", "前度蛮笺泪痕满。", "为问乘槎人不远。", "只消丹桂，一枝分付，早早随伊愿。"]'),
('song-ci-989','青玉案','倪翼周','宋','宋词','song-ci','青玉案','[]','四时令节惟重九。',80,'宋词/ci.song.20000.json','["四时令节惟重九。", "况此日、逢佳偶。", "金菊已花杯有酒。", "瑶池宴罢，一枝斜插，好作渊朋友。", "翠眉淡淡匀宫柳。", "比似年时更清瘦。", "双绾带儿新结就。", "长情恩爱，随家俭约，素与君同寿。"]'),
('song-ci-990','青玉案','倪翼周','宋','宋词','song-ci','青玉案','[]','薰风解尽吾民愠。',78,'宋词/ci.song.20000.json','["薰风解尽吾民愠。", "正蓬渚芳遍。", "昨夜商周生伊旦。", "从来仁者，仲尼称寿，更捧金杯劝。", "我有诗词三百卷。", "待留取、频频献。", "且看明年秋欲半。", "紫薇花下，绿槐阴外，天语颁新宴。"]'),
('song-ci-991','青玉案','倪翼周','宋','宋词','song-ci','青玉案','[]','熙春堂下花无数。',80,'宋词/ci.song.20000.json','["熙春堂下花无数。", "红紫映、桃溪路。", "蝶往蜂来知几许。", "翠筠亭外，绿阳堤畔，时听娇莺语。", "绮筵罗列开樽俎。", "况总是、神仙侣。", "竞举笙歌持玉醑。", "介公眉寿，年年此日，常与花为主。"]'),
('song-ci-992','醉蓬莱','段倚','宋','宋词','song-ci','醉蓬莱','[]','正星杓首舍，月律开祥，嗣兴芳序。',120,'宋词/ci.song.20000.json','["正星杓首舍，月律开祥，嗣兴芳序。", "梦协长庚，诞清朝仪羽。", "运继姬周，庆流嵩岳，认再生申甫。", "职尹京华，功宣国计，声猷兼著。", "子建文章，懿侯宗范，叔度襟怀，紫芝眉宇。", "燕启佳辰，满东风兰雾，脆管繁弦，绣裀檀板，会饭中仙侣。", "世仰真贤，朝尊大老，长亲尧主。"]'),
('song-ci-993','新荷叶','贺及','宋','宋词','song-ci','新荷叶','[]','莲萼飘香，金风乍扇轻凉。',102,'宋词/ci.song.20000.json','["莲萼飘香，金风乍扇轻凉。", "郁郁葱葱，瑞烟萦绕华堂。", "星辰孕秀，良霄梦、吉协熊祥。", "紫芝眉宇，莹然如峙圭璋。", "忠孝传芳，集庆门、奕世簪裳。", "他日岩廊，致君直上虞唐。", "百千椿算，争期并、鹤老龟长。", "年年今日，会拚一醉觥觞。"]'),
('song-ci-994','沁园春','傅伯达','宋','宋词','song-ci','沁园春','[]','白帝司权，炎宫回驭，一叶报秋。',138,'宋词/ci.song.20000.json','["白帝司权，炎宫回驭，一叶报秋。", "正银河高泻，金风作扇，冰轮将满，火伞初收。", "吴越传芳，斗牛锺秀，间世生贤谁与俦。", "那堪更负，过人才气，济世谋猷。", "风流花县优游，有善政廉名达郡侯。", "鹗书朝荐，泥封暮召，荣登闺籍，平步瀛洲。", "歌驻行云，舞翔回雪，寿酒深倾碧玉瓯。", "从今愿，愿龄齐鼻祖，名在丹丘。"]'),
('song-ci-995','满庭芳','郑达可','宋','宋词','song-ci','满庭芳','[]','肥绽梅红，嫩翻荷绿，微凉时起青萍。',118,'宋词/ci.song.20000.json','["肥绽梅红，嫩翻荷绿，微凉时起青萍。", "人间福艾，都属老人星。", "累建高牙大纛，循良治、是处彬彬。", "棠阴里，丰碑纪德，仁爱浃生民。", "纶巾。", "风物裹，一筇徒倚，傲睨寰瀛。", "况清朝黄发，尤急咨询。", "第恐商山芝客，岂容便、蝉蜕功名。", "他时看，腰横玉带，朱紫列云仍。"]'),
('song-ci-996','念奴娇','郑达可','宋','宋词','song-ci','念奴娇','[]','嫩凉如水，正一天风露，秋容如沐。',120,'宋词/ci.song.20000.json','["嫩凉如水，正一天风露，秋容如沐。", "明日中秋今夜月，千里清辉光足。", "周室姬公，唐家元轨，来享人间福。", "老人星瑞，光芒南照檐曲。", "行看裂土分茅，朱颜青鬓，好称腰横玉。", "便挽银河斟北斗，倾作千锺醽醁。", "子舍荣华，孙枝赫奕，茂盛同松竹。", "尊前欢笑，竞将椿算为祝。"]'),
('song-ci-997','南歌子','臧馀庆','宋','宋词','song-ci','南歌子','[]','桔里风烟好，壶中日月长。',62,'宋词/ci.song.20000.json','["桔里风烟好，壶中日月长。", "松身鹤发自安强。", "应有老人呈瑞、动光芒。", "酒饮无边酒，香烧不断香。", "从今乞与醉为乡。", "更醉百年三万、六千场。"]'),
('song-ci-998','鹧鸪天','臧馀庆','宋','宋词','song-ci','鹧鸪天','[]','天与君王管晏才。',64,'宋词/ci.song.20000.json','["天与君王管晏才。", "尚书两曳履声来。", "今朝望着楼头看，已有台星照斗魁。", "金蹀躞，玉崔嵬。", "天香满袖早朝回。", "中书尚享无穷考，长揖南风醉寿杯。"]'),
('song-ci-999','鹧鸪天','臧馀庆','宋','宋词','song-ci','鹧鸪天','[]','寿菊才开三四葩。',64,'宋词/ci.song.20000.json','["寿菊才开三四葩。", "秋光着意主人家。", "清香未许人间识，先占重阳醉紫霞。", "儿绿绶，母金花。", "斑衣庭下乐无涯。", "要知他日中书考，细数沙堤堤上沙。"]'),
('song-ci-0','感皇恩','臧馀庆','宋','宋词','song-ci','感皇恩','[]','消息近春来，东风还又。',81,'宋词/ci.song.21000.json','["消息近春来，东风还又。", "先借椒盘劝金斗。", "坐间和气，压尽一番梅柳。", "掖庭频寓直，君恩厚。", "天祐两宫，南山齐寿。", "况有仙丹在公手。", "论功医国，合在药王之右。", "不妨千岁饮，长生酒。"]'),
('song-ci-1','感皇恩','臧馀庆','宋','宋词','song-ci','感皇恩','["\u8861\u5c71"]','南岳有真仙，人间祥瑞。',81,'宋词/ci.song.21000.json','["南岳有真仙，人间祥瑞。", "酒量诗豪世无比。", "晚年林下，做个清闲活计。", "诮如千岁鹤，巢云际。", "此日大家，广排筵会。", "酒劝千锺莫辞醉。", "昔时彭祖，寿年八百馀岁。", "十分才一分，那里暨。"]'),
('song-ci-2','感皇恩','臧馀庆','宋','宋词','song-ci','感皇恩','[]','交广出沉香，路遥难致。',81,'宋词/ci.song.21000.json','["交广出沉香，路遥难致。", "何况卑人更不易。", "寿星香帕，我又几曾识置。", "有般祝寿底，忒忔戏。", "剪下一张，池州表纸。", "拈得轻圆更滑腻。", "五双纸拈，管打十个喷嚏。", "□□□□儿，一百岁。"]'),
('song-ci-3','鹧鸪天','胡于','宋','宋词','song-ci','鹧鸪天','[]','去日清霜菊满丛。',64,'宋词/ci.song.21000.json','["去日清霜菊满丛。", "归来高柳絮缠空。", "长驱万里山收瘴，径度层波海不风。", "阴德遍，岭西东。", "天教慈母寿无穷。", "遥知今夕称觞处，衣彩还将衣绣同。"]'),
('song-ci-4','鹧鸪天','胡于','宋','宋词','song-ci','鹧鸪天','[]','阿母蟠桃下记春。',64,'宋词/ci.song.21000.json','["阿母蟠桃下记春。", "长沙星里寿星明。", "金花罗纸新裁诏，具叶傍行别绶经。", "同龙子，祝龟龄。", "天教二老鬓长青。", "明年今日称觞处，更有孙枝满谢庭。"]'),
('song-ci-5','鹧鸪天','胡于','宋','宋词','song-ci','鹧鸪天','[]','楚楚吾家千里驹。',64,'宋词/ci.song.21000.json','["楚楚吾家千里驹。", "老人心事正开渠。", "风流不减庭前玉，爱惜真如掌上珠。", "纡绿绶，荐方壶。", "老人沉醉弟兄扶。", "问将何物为儿寿，付与家传万卷书。"]'),
('song-ci-6','鹧鸪天','胡于','宋','宋词','song-ci','鹧鸪天','[]','袅袅薰风响珮环。',64,'宋词/ci.song.21000.json','["袅袅薰风响珮环。", "广寒仙子跨清鸾。", "谁教瑞世仪周间，自赋多才继小山。", "铃阁静，画堂闲。", "衮衣象服镇团栾。", "年年此日称觞处，留待菖蒲驻玉颜。"]'),
('song-ci-7','鹧鸪天','申国章','宋','宋词','song-ci','鹧鸪天','[]','十载分符衣绣衣。',64,'宋词/ci.song.21000.json','["十载分符衣绣衣。", "裳阴处处浙东西。", "政成已可书银笔，词鹿仍堪付雪儿。", "春未半，日方迟。", "御沟金袅柳如丝。", "凤池留得梅花住，欲与先生荐寿卮。"]'),
('song-ci-8','鹧鸪天','陈日章','宋','宋词','song-ci','鹧鸪天','[]','内乐清虚息万缘。',64,'宋词/ci.song.21000.json','["内乐清虚息万缘。", "逍遥真是地行仙。", "徙他玉带金鱼贵，听我纶巾羽扇便。", "倾九酝，祝长年。", "休辞潋滟十分舡。", "来年此日称觞处，定有重孙戏膝前。"]'),
('song-ci-9','鹧鸪天','李景良','宋','宋词','song-ci','鹧鸪天','[]','清晓祥云绕碧天。',64,'宋词/ci.song.21000.json','["清晓祥云绕碧天。", "老人星忽下南躔。", "庭兰共酌长生酒，持上华堂彩侍前。", "开绮席，舞朱颜。", "轻红莲叶荐金盘。", "沉香小院浑先暑，更有杯传数百年。"]'),
('song-ci-10','鹧鸪天','张思济','宋','宋词','song-ci','鹧鸪天','[]','衣润红绡梅欲黄。',64,'宋词/ci.song.21000.json','["衣润红绡梅欲黄。", "几年欢意属华堂。", "红颜阿母逢占虺，班鬓儿童尽举觞。", "麟作脯，玉为浆。", "从今三万六千场。", "桑麻休说桑田变，自是经门日月长。"]'),
('song-ci-11','减字木兰花','李夫人','宋','宋词','song-ci','减字木兰花','[]','幕天席地。',52,'宋词/ci.song.21000.json','["幕天席地。", "瑞脑香浓笙歌沸。", "白纻衣轻。", "鹓发霜髯照座明。", "轻簪小珥。", "却是人间真富贵。", "好着丹青。", "画与人间作寿星。"]'),
('song-ci-12','蝶恋花','李夫人','宋','宋词','song-ci','蝶恋花','[]','急鼓疏钟声报晓，楼上今朝，卷起重帘早。',70,'宋词/ci.song.21000.json','["急鼓疏钟声报晓，楼上今朝，卷起重帘早。", "环珮珊珊香袅袅。", "尘埃不到如蓬岛。", "何用珠玑相映照。", "韵胜形清，自有天然好。", "莫向尊前辞醉倒。", "松枝鹤骨偏宜老。"]'),
('song-ci-13','瑞鹧鸪','李夫人','宋','宋词','song-ci','瑞鹧鸪','[]','新晴庭院暑风轻。',64,'宋词/ci.song.21000.json','["新晴庭院暑风轻。", "瑞气朝来特地清。", "霞帔羽衣筠竹杖，萱堂真有寿星明。", "自来忠孝传家世，所以芝兰满户庭。", "簪笏成行称寿处，老来皆已鬓星星。"]'),
('song-ci-14','望海潮','张藻','宋','宋词','song-ci','望海潮','[]','露零金井，尘清玉宇，双蓂呈瑞新秋。',129,'宋词/ci.song.21000.json','["露零金井，尘清玉宇，双蓂呈瑞新秋。", "佳气郁葱，祥烟缭绕，玉门初诞风流。", "宾客竞回眸。", "庆虎头食肉，燕颔封侯。", "骨相非凡，便宜谈笑上瀛洲。", "青衫莫欢淹留。", "有儿孙兰玉，不负箕裘。", "莲幕向来，花城今日，不妨小试良筹。", "名姓在金瓯。", "看佩珂鸣玉，促侍宸旒。", "直待功成名遂，归作赤松游。"]'),
('song-ci-15','虞美人','胡文卿','宋','宋词','song-ci','虞美人','[]','枢庭喜庆生辰到。',66,'宋词/ci.song.21000.json','["枢庭喜庆生辰到。", "仙伯离蓬岛。", "鲁台云物正呈祥。", "线绣工夫从此、日添长。", "满斟绿醑深深劝。", "岁岁长相见。", "蟠桃结子几番红。", "笑赏清歌声调、叶黄锺。"]'),
('song-ci-16','虞美人','胡文卿','宋','宋词','song-ci','虞美人','[]','香烟绕遍兰堂宴。',66,'宋词/ci.song.21000.json','["香烟绕遍兰堂宴。", "香鸭珠帘卷。", "香风转后送韶音。", "香酝佳筵今日、庆佳辰。", "香山烧尽禽飞放。", "香袖佳人唱。", "香醪满满十分斟。", "香信传时延寿、保千春。"]'),
('song-ci-17','虞美人','胡文卿','宋','宋词','song-ci','虞美人','[]','寿香烟篆金炉细。',66,'宋词/ci.song.21000.json','["寿香烟篆金炉细。", "寿酒邀宾至。", "寿筵两畔列红妆。", "寿曲仙音一品、舞霓裳。", "寿星高挂生祥瑞。", "寿祝长生意。", "寿杯满劝庆遐龄。", "寿比南山松柏、永长春。"]'),
('song-ci-18','虞美人','胡文卿','宋','宋词','song-ci','虞美人','[]','香云佳气交盘结。',66,'宋词/ci.song.21000.json','["香云佳气交盘结。", "又庆生申节，满堂簪绂奉霞觞。", "瑞应台躔南极、见光芒。", "心田积累阴功足。", "来受人天福。", "从今几度见河清。", "笑傲壶中日月、镇长春。"]'),
('song-ci-19','虞美人','胡文卿','宋','宋词','song-ci','虞美人','[]','昨霄南极星光现。',66,'宋词/ci.song.21000.json','["昨霄南极星光现。", "今日开华宴。", "朱颜翠鬓占春多。", "且向博山香袅、卷金荷。", "龟游鹤舞千年寿。", "更酌千锺酒。", "满庭佳客捧殷勤。", "此日蒲菊新绿、瓮头春。"]'),
('song-ci-20','阮郎归','胡文卿','宋','宋词','song-ci','阮郎归','[]','良辰佳景列华筵。',56,'宋词/ci.song.21000.json','["良辰佳景列华筵。", "笙歌奏管弦。", "位居荣显子孙贤。", "功名事双全。", "庆祝寿，拜尊前。", "重重福禄坚。", "愿如彭祖寿齐年。", "金杯劝寿仙。"]'),
('song-ci-21','阮郎归','胡文卿','宋','宋词','song-ci','阮郎归','[]','谢娘诗礼有家风。',56,'宋词/ci.song.21000.json','["谢娘诗礼有家风。", "吹窗清昼同。", "笑言偕老与梁鸿。", "闺门喜气融。", "来月殿，下珠宫。", "人间春意浓。", "一尊仙酝祝芳丛。", "蟠桃千岁红。"]'),
('song-ci-22','阮郎归','胡文卿','宋','宋词','song-ci','阮郎归','[]','薰风吹尽不多云。',56,'宋词/ci.song.21000.json','["薰风吹尽不多云。", "晓天如水清。", "哦松庭院忽闻笙。", "帘疏香篆明。", "兰玉盛，凤和鸣。", "家声留汉庭。", "狨鞍长傍九重城。", "年年双鬓青。"]'),
('song-ci-23','蝶恋花','杨道居','宋','宋词','song-ci','蝶恋花','[]','气禀五行天与秀。',70,'宋词/ci.song.21000.json','["气禀五行天与秀。", "瑞见枢延，况是黄锺奏。", "日影量来添午昼。", "柳梅消息年时侯。", "红粉吹香帘幕透。", "深院笙歌，劝饮金锺酒。", "乐事赏心千岁有。", "黑头人做三公有。"]'),
('song-ci-24','苏幕遮','史佐尧','宋','宋词','song-ci','苏幕遮','[]','柳垂金，梅褪玉。',76,'宋词/ci.song.21000.json','["柳垂金，梅褪玉。", "昴宿呈祥，符应生公族。", "盖世功名夸九牧。", "黼衮褒扬，庆阀辉南北。", "赐宫醪，分笃耨。", "天与长生，谩把仙椿祝。", "好继平阳腾茂躅。", "富贵千秋，饮听瑶池曲。"]'),
('song-ci-25','满庭芳','徐去非','宋','宋词','song-ci','满庭芳','[]','凤历书元，龟图画泰，瑞蓂两两初开。',118,'宋词/ci.song.21000.json','["凤历书元，龟图画泰，瑞蓂两两初开。", "舞风仙子，飞雪拥春来。", "平荡人间险秽，端为你没点尘埃。", "清明世，冰辉太洁，鸥鹭莫惊猜。", "儿孙，同劝寿，桃添西阆，兰绕南陔。", "看琼玉妆成，万瓦楼台。", "飘洒风流酥满盏，浑疑醉，月影蓬莱。", "从今去，诗高未老，点化尽多才。"]'),
('song-ci-26','锦被堆','徐去非','宋','宋词','song-ci','锦被堆','[]','一种两容仪，红共白、交映南枝。',76,'宋词/ci.song.21000.json','["一种两容仪，红共白、交映南枝。", "紫霞仙指冰翁语，花如醉玉，香同臭雪，别样风姿。", "相守岁寒期。", "春造化、密与天知。", "羞将脂粉隈桃李，独先结实，还同戴胜，归宴瑶池。"]'),
('song-ci-27','卷珠帘・蝶恋花','徐去非','宋','宋词','song-ci','卷珠帘・蝶恋花','[]','祥景飞光衮绣。',69,'宋词/ci.song.21000.json','["祥景飞光衮绣。", "流庆崑台，自是神仙胄。", "谁遣阳和放春透。", "化工重入丹青手。", "云筝锦瑟争为寿。", "玉带金鱼，共愿人长久。", "偷取蟠桃荐芳酒，更看南极星朝斗。"]'),
('song-ci-28','点绛唇','舒大成','宋','宋词','song-ci','点绛唇','[]','祝寿筵开，华堂深映花如绣。',50,'宋词/ci.song.21000.json','["祝寿筵开，华堂深映花如绣。", "瑞烟喷兽。", "帘幕香风透。", "一点台星，化作人间秀。", "韶音奏。", "两行红袖。", "争劝长生酒。"]'),
('song-ci-29','临江仙','贾少卿','宋','宋词','song-ci','临江仙','[]','月寺星轺尘梦断，如今平地仙人。',69,'宋词/ci.song.21000.json','["月寺星轺尘梦断，如今平地仙人。", "烟霞卷起旧精神。", "焚香金鸾鷟，书奏玉麒麟。", "闻道枫宸求侍从，看庆命重新。", "且将风月剩酧身。", "樽中长有酒，花下不辜春。"]'),
('song-ci-30','江城子','陆汉广','宋','宋词','song-ci','江城子','[]','绿莺庭院燕莺啼。',86,'宋词/ci.song.21000.json','["绿莺庭院燕莺啼。", "绣帘垂。", "瑞烟霏。", "一片笙箫，声过彩云低。", "疑是蕊宫仙子降，翻玉袖，舞瑶姬。", "冰姿玉质自清奇。", "看孙枝。", "列班衣。", "画鼓新歌，喜映两疏眉。", "袖里蟠桃花露湿，应不惜，醉金卮。"]'),
('song-ci-31','临江仙','王阜民','宋','宋词','song-ci','临江仙','["\u957f\u6c5f"]','家法从来师静治，赵张高掩前踪。',70,'宋词/ci.song.21000.json','["家法从来师静治，赵张高掩前踪。", "清才八斗继宗风。", "年年正月尾，桃李满城中。", "已把长江成九酝，请将太白浮公。", "更移春槛向房栊。", "有花虽解语，莫负锦薰笼。"]'),
('song-ci-32','感皇恩','霍安人','宋','宋词','song-ci','感皇恩','[]','十月小春天，梅飘香细。',81,'宋词/ci.song.21000.json','["十月小春天，梅飘香细。", "九叶尧蓂已呈瑞。", "寿阳仙子，暂降羽衣环珮。", "林间风味，别人难比。", "齐眉共庆，劝声鼎沸。", "有子知书继家世。", "兼金五福，行被君恩宠贲。", "愿祈龟鹤算，千千岁。"]'),
('song-ci-33','醉蓬莱','霍安人','宋','宋词','song-ci','醉蓬莱','[]','正朱明时侯，院宇清和，庆逢佳节。',120,'宋词/ci.song.21000.json','["正朱明时侯，院宇清和，庆逢佳节。", "梦应熊罴，尧蓂翻三叶，罗绮如云，寿杯争劝，竞起歌新阕。", "瑞气氤氲，祥云缭绕，玉炉频爇。", "溪室封功，几多勋业，首冠今朝，一时英杰。", "得配侯门，岂不惭疏拙。", "彩凤和鸣，早膺荣擢。", "增盛斑衣列。", "福禄无穷，年过卫武，辉光阀阅。"]'),
('song-ci-34','满庭芳','霍安人','宋','宋词','song-ci','满庭芳','[]','桐叶霜乾，芦花风软，晓来一色新秋。',118,'宋词/ci.song.21000.json','["桐叶霜乾，芦花风软，晓来一色新秋。", "碧光无际，良夜月明楼。", "瑞应长庚入梦，锺奇秀、特产贤侯。", "堪夸处，雄姿英发，连箭射双雕。", "回头。", "思往事，皂囊三进，豪气冲牛。", "记前回凤诏，空下南洲。", "冷笑浮云坠甑，鲈鱼美、归老扁舟。", "祝君寿，青山不尽，绿水自悠悠。"]'),
('song-ci-35','瑞鹤仙','希叟','宋','宋词','song-ci','瑞鹤仙','[]','燕堂秋未老。',126,'宋词/ci.song.21000.json','["燕堂秋未老。", "正木犀香散，芙蓉红小。", "门阑瑞烟绕。", "望银河月暗，寿星偏照。", "碧霞道要。", "有真人、亲传最妙。", "况桃源旧约，重寻鬓发，胜如年少。", "缥缈。", "六铢衣降，九转丹成，五云齐到。", "十洲三岛。", "神仙路，终须到。", "对芝兰玉树，宝杯交劝，何惜玉山醉倒。", "看乘鸾跨鹤，归来洞天未晓。"]'),
('song-ci-36','水调歌头','沈元实','宋','宋词','song-ci','水调歌头','[]','金关五云里，玉座太微间。',113,'宋词/ci.song.21000.json','["金关五云里，玉座太微间。", "凌虚新就燕间，宣唤侍臣班。", "丹扆坐移前席，禁漏声传高阁，喜气满龙颜。", "天语眷畴昔，政路稳跻攀。", "酒如渑，香袅穗，寿南山。", "橙黄桔绿，樽前辉映菊花团。", "清晓凉风凝露，晴昼秋光满院，岁岁奉君。", "待看云台画，荣观侈人寰。"]'),
('song-ci-37','满江红','游子蒙','宋','宋词','song-ci','满江红','[]','春玉苍山，屏星暖、佳辰难得。',114,'宋词/ci.song.21000.json','["春玉苍山，屏星暖、佳辰难得。", "看柳眼梅金，全似海沂春色。", "和气欢声俄尔许，祥烟瑞霭今何夕。", "是风流、儒雅黑头公，悬弧日。", "福不尽，贵无敌。", "愿岁岁，见华席。", "捧霞觞称寿，寿如南极。", "见说蟠桃花正发，柔风暖日瑶池碧。", "待他年、结子欲成时，留君摘。"]'),
('song-ci-38','满江红','游子蒙','宋','宋词','song-ci','满江红','[]','雪坞霜林，一夜报、春归消息。',115,'宋词/ci.song.21000.json','["雪坞霜林，一夜报、春归消息。", "看是处、春回柳眼，粉匀梅额。", "和气已欣回北陆，寿星更喜明南极。", "问四井、节物奉谁欢，辽东客。", "熊梦旦，非常日。", "珠履闹，金钗密。", "指双溪千顷，共斟琼液。", "不用殷勤千岁祝，姓名已上神仙籍。", "但时从、王母借蟠桃，躬亲摘。"]'),
('song-ci-39','清平乐','贾逋','宋','宋词','song-ci','清平乐','[]','薰梅染柳。',54,'宋词/ci.song.21000.json','["薰梅染柳。", "借得东君手。", "柳色梅香到樽前，摅写才华八斗。", "当年占梦佳辰。", "今年乐事尤新。", "日侍玉皇香案，钧天日月常春。"]'),
('song-ci-40','蝶恋花','吴文若','宋','宋词','song-ci','蝶恋花','[]','玉宇生凉秋恰半。',71,'宋词/ci.song.21000.json','["玉宇生凉秋恰半。", "月到今霄，分外清光满。", "兔魄呈祥冰�昀谩�", "广寒仙子生华旦。", "聪慧风流天与擅，淑质冰婆，本是飞琼伴。", "□领彩衣椿祝劝。", "蟠桃待熟瑶池宴。"]'),
('song-ci-41','满庭芳','去非','宋','宋词','song-ci','满庭芳','[]','龙角辉春，蛾春惊晓，梦阑金翠屏开。',117,'宋词/ci.song.21000.json','["龙角辉春，蛾春惊晓，梦阑金翠屏开。", "异芬薰室，风送蕊仙来。", "玉女擎香沐浴，人间世、洗彻凡埃。", "梅开后，留花酝染，清味俗难猜。", "东君，尤雅爱，传香芳畹，香发庭陔。", "宁馨满尊前，喜奏瑶台。", "便好纽为佩王，瀛洲路、同赏蓬莱。", "蟠桃宴，从今曼倩，三骋奇材。"]'),
('song-ci-42','南乡子','潘熊飞','宋','宋词','song-ci','南乡子','[]','十日后重阳。',66,'宋词/ci.song.21000.json','["十日后重阳。", "甘菊阶前满意黄。", "生日无钱留贺客，何妨。", "尚有儿曹理寿觞。", "双鬓已沧浪。", "休问金门与玉堂。", "二仲相期三径在，徜徉。", "何用功成似子房。"]'),
('song-ci-43','水调歌头','黄庭佐','宋','宋词','song-ci','水调歌头','[]','露着桂枝晓，霜护菊篱秋。',114,'宋词/ci.song.21000.json','["露着桂枝晓，霜护菊篱秋。", "无尘玉宇南极，一点瑞光浮。", "崧岳精英瑞世，河洛图书寓直，琳馆奉宸游。", "独袖功名手，谁与复神州。", "带垂金，头尚黑，紫绮裘。", "年年今日，灵寿扶出富民侯。", "应为娉婷一笑，烂醉葡萄新熟，明月满西楼。", "西北雨峰峙，端与寿山侔。"]'),
('song-ci-44','失调名','赵□','宋','宋词','song-ci','失调名','[]','寸心千里。',5,'宋词/ci.song.21000.json','["寸心千里。"]'),
('song-ci-45','失调名','吴氏3','宋','宋词','song-ci','失调名','[]','剪新幡儿，斜插真珠髻。',11,'宋词/ci.song.21000.json','["剪新幡儿，斜插真珠髻。"]'),
('song-ci-46','南乡子','吴氏3','宋','宋词','song-ci','南乡子','[]','楼台里，春风淡荡。',9,'宋词/ci.song.21000.json','["楼台里，春风淡荡。"]'),
('song-ci-47','南乡子','吴氏3','宋','宋词','song-ci','南乡子','[]','乍卷珠帘新燕入。',8,'宋词/ci.song.21000.json','["乍卷珠帘新燕入。"]'),
('song-ci-48','多丽','吴氏3','宋','宋词','song-ci','多丽','[]','几声天外归鸿。',7,'宋词/ci.song.21000.json','["几声天外归鸿。"]'),
('song-ci-49','渔家傲','吴氏3','宋','宋词','song-ci','渔家傲','[]','鶗鴂一声初报晓。',8,'宋词/ci.song.21000.json','["鶗鴂一声初报晓。"]'),
('song-ci-0','蓦山溪','向子諲','宋','宋词','song-ci','蓦山溪','[]','一阳才动，万物生春意。',102,'宋词/ci.song.3000.json','["一阳才动，万物生春意。", "试与问宫梅，到东阁、花枝第几。", "疏疏淡淡，冷艳雪中明，无俗调，有真香，正与人相倚。", "非烟非雾，瑞色门阑喜。", "再拜引杯长，看两颊、红潮欲起。", "天教难老，风鬓绿如云，对玉笥，与芗林，岁岁花前醉。"]'),
('song-ci-1','水龙吟','向子諲','宋','宋词','song-ci','水龙吟','[]','华灯明月光中，绮罗弦管春风路。',126,'宋词/ci.song.3000.json','["华灯明月光中，绮罗弦管春风路。", "龙如骏马，车如流水，软红成雾。", "太一池边，葆真宫里，玉楼珠树。", "见飞琼伴侣，霓裳缥缈，星回眼、莲承步。", "笑入彩云深处。", "更冥冥、一帘花雨。", "金钿半落，宝钗斜坠，乘鸾归去。", "醉失桃源，梦回蓬岛，满身风露。", "到而今江上，愁山万叠，鬓丝千缕。"]'),
('song-ci-2','水龙吟','向子諲','宋','宋词','song-ci','水龙吟','[]','梦回寒入衾绸，晓惊忽堕瑶林里。',126,'宋词/ci.song.3000.json','["梦回寒入衾绸，晓惊忽堕瑶林里。", "穿帷透隙，落花飞絮，难穷巧思。", "着帽披裘，挈壶呼友，倚空临水。", "望琼田不尽，银涛无际，浮皓色、来天地。", "遥想吴郎病起。", "政冷窗、微吟拥鼻。", "持笺赠我，新词绝唱，珠零玉碎。", "馀兴追游，清芬坐对，高谈倾耳。", "晚归来，风扫停云，万里月华如洗。"]'),
('song-ci-3','八声甘州','向子諲','宋','宋词','song-ci','八声甘州','[]','恨中秋、多雨及晴景，追赏且探先。',117,'宋词/ci.song.3000.json','["恨中秋、多雨及晴景，追赏且探先。", "纵玉钩初上，冰轮未正，无奈婵娟。", "饮客不来自酌，对影亦清妍。", "任笑芗林老，雪鬓霜髯。", "好在章江西畔，有凌云玉笥，空翠相连。", "懒崎岖林麓，则窈窕溪边。", "自断此生休问，愿瓮中、长有酒如泉。", "人间是，更谁得似，月下尊前。"]'),
('song-ci-4','卜算子','向子諲','宋','宋词','song-ci','卜算子','[]','千古一灵根，本妙元明静。',52,'宋词/ci.song.3000.json','["千古一灵根，本妙元明静。", "道个如如已是差，莫认风番影。", "枯木夜堂深，默坐时观省。", "月落乌鸡出户飞，万里关河冷。"]'),
('song-ci-5','三字令','向子諲','宋','宋词','song-ci','三字令','[]','春尽日，雨馀时。',72,'宋词/ci.song.3000.json','["春尽日，雨馀时。", "红蔌蔌，绿漪漪。", "花满地，水平池。", "烟光里，云影上，画船移。", "纹鸳并，白鸥飞。", "歌韵响，酒行迟。", "将我意，入新诗。", "春欲去，留且住，莫教归。"]'),
('song-ci-6','长相思','向子諲','宋','宋词','song-ci','长相思','[]','年重月，月重光。',44,'宋词/ci.song.3000.json','["年重月，月重光。", "万瓦千林白似霜。", "扁舟入醉乡。", "山苍苍。", "水茫茫。", "严濑当时不是狂。", "高风引兴长。"]'),
('song-ci-7','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','柳眼风前动，梅心雪后寒。',62,'宋词/ci.song.3000.json','["柳眼风前动，梅心雪后寒。", "年光浑似雾中看。", "抱答风光无处、可为欢。", "一曲聊收泪，三杯强自宽。", "新愁不奈上眉端。", "怕见长安归路、懒凭栏。"]'),
('song-ci-8','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','无穷白水。',52,'宋词/ci.song.3000.json','["无穷白水。", "无限芰荷红翠里。", "几点青山。", "半在云烟暗霭间。", "移舟横截。", "卧看碧天流素月。", "此意虚徐。", "好把芗林入画图。"]'),
('song-ci-9','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','江左称岩桂，吴中说木犀。',62,'宋词/ci.song.3000.json','["江左称岩桂，吴中说木犀。", "水沈为骨郁金衣。", "却恨疏梅恼我、得香迟。", "叶借山光润，花蒙水色奇。", "年年勾引赋新诗。", "应笑芗林冷淡、独心知。"]'),
('song-ci-10','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','病著连三月，谁能慰老夫。',62,'宋词/ci.song.3000.json','["病著连三月，谁能慰老夫。", "萧萧短发不胜梳。", "风里支离欲倒、要人扶。", "秋月明如水，岩花忽起予。", "旋篘白酒入盘盂。", "报答风光不醉、更何如。"]'),
('song-ci-11','南歌子','向子諲','宋','宋词','song-ci','南歌子','[]','我入三摩地，人疑小有天。',62,'宋词/ci.song.3000.json','["我入三摩地，人疑小有天。", "君王送老白云边。", "不用丹青图画、上凌烟。", "喜揽澄清辔，能同载酒船。", "相逢忽谩别经年。", "好是两身强健、在尊前。"]'),
('song-ci-12','桂殿秋','向子諲','宋','宋词','song-ci','桂殿秋','[]','秋色里，月明中。',32,'宋词/ci.song.3000.json','["秋色里，月明中。", "红旌翠节下蓬宫。", "蟠桃已结瑶池露，桂子初开玉殿风。"]'),
('song-ci-13','朝中措','向子諲','宋','宋词','song-ci','朝中措','[]','满城腊雪净无埃。',57,'宋词/ci.song.3000.json','["满城腊雪净无埃。", "触处是花开。", "天上琼林珠树，谁知夜半移来。", "黄堂荐寿，请君著意，和气潜回。", "化作一江春酒，都将注入尊罍。"]'),
('song-ci-14','菩萨蛮','向子諲','宋','宋词','song-ci','菩萨蛮','[]','天仙醉把真珠掷。',52,'宋词/ci.song.3000.json','["天仙醉把真珠掷。", "荷翻写入玻璃碧。", "雨过酒尊凉。", "红蕖苒苒香。", "飞来双白鹭。", "屡作僛僛舞。", "山鸟起清歌。", "晚来情更多。"]'),
('song-ci-15','好事近','向子諲','宋','宋词','song-ci','好事近','[]','多病卧江干，过尽春花秋叶。',53,'宋词/ci.song.3000.json','["多病卧江干，过尽春花秋叶。", "又见横斜疏影，弄阶前明月。", "呼儿取酒据胡床，尚喜知时节。", "宜与老夫情厚，有鬓边残雪。"]'),
('song-ci-16','好事近','向子諲','宋','宋词','song-ci','好事近','[]','风劲入平林，扫尽一林黄叶。',53,'宋词/ci.song.3000.json','["风劲入平林，扫尽一林黄叶。", "惟有长松千丈，挂娟娟霜月。", "使君和气动江城，疑是芳菲节。", "忽到小园游戏，见南枝如雪。"]'),
('song-ci-17','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','两峰对起。',52,'宋词/ci.song.3000.json','["两峰对起。", "象阙端门云雾里。", "千嶂排空。", "虎节龙旗指顾中。", "箫韶妙曲。", "我试与听音韵足。", "借问谁传。", "松上清风石上泉。"]'),
('song-ci-18','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','翠鬟双小。',52,'宋词/ci.song.3000.json','["翠鬟双小。", "绿绮朱弦心未了。", "画戟森间。", "玉子纹楸手共谈。", "不妨扶老。", "未说他年无限笑。", "且要忘忧。", "莫问今朝胜几筹。"]'),
('song-ci-19','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','腊前雪里。',52,'宋词/ci.song.3000.json','["腊前雪里。", "几处梅梢初破蕊。", "年后江边。", "是处花开晚更妍。", "绝知春意。", "不耐愁何心与醉。", "更有难忘。", "宋玉墙头婉婉香。"]'),
('song-ci-20','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','谁知莹澈。',52,'宋词/ci.song.3000.json','["谁知莹澈。", "惟有碧天云外月。", "一见风流。", "洗尽胸中万斛愁。", "剩烧蜜炬。", "只恐夜深花睡去。", "想得横陈。", "全是巫山一段云。"]'),
('song-ci-21','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','千山万水。',52,'宋词/ci.song.3000.json','["千山万水。", "望极不知何处是。", "小院回廊。", "梦去相寻未觉长。", "绝怜清瘦。", "雪里梅梢春未透。", "常记分携。", "雨后梨花晓尚啼。"]'),
('song-ci-22','减字木兰花','向子諲','宋','宋词','song-ci','减字木兰花','[]','去年端午。',52,'宋词/ci.song.3000.json','["去年端午。", "共结彩丝长命缕。", "今日重阳。", "同泛黄花九酝觞。", "经时离缺。", "不为莱菔髭似雪。", "一笑逢迎。", "休觅空青眼自明。"]'),
('song-ci-23','满庭芳','向子諲','宋','宋词','song-ci','满庭芳','[]','天宇长闲，飞仙狂醉，挼云碎玉沈空。',118,'宋词/ci.song.3000.json','["天宇长闲，飞仙狂醉，挼云碎玉沈空。", "谢家庭院，争道絮因风。", "不怕寒生宝粟，深调护、犀幕重重。", "瑶林里，疏梅献笑，小萼露轻红。", "瑞龙。", "香绕处，云间弦管，尘外帘栊。", "须烂醉流霞，莫诉千锺。", "闻道蟠桃正好，蓬瀛路、消息潜通。", "飞琼伴，偷将春色，分付入芳容。"]'),
('song-ci-24','水调歌头','向子諲','宋','宋词','song-ci','水调歌头','[]','天公深藏巧，雪里放春回。',114,'宋词/ci.song.3000.json','["天公深藏巧，雪里放春回。", "不到闲花凡草，都付与疏梅。", "独立水边林下，萧萧冰容孤艳，清瘦玉腰支。", "触拨暗香动，风味欲愁谁。", "姮娥携，青女过，夜阑时。", "瑶冠琼佩，粲然一笑亦何奇。", "剩欲举觞对饮，不怕月明霜重，寒色著人衣。", "只恐邻笛起，化作玉尘飞。"]'),
('song-ci-25','梅花引','向子諲','宋','宋词','song-ci','梅花引','[]','花如颊。',140,'宋词/ci.song.3000.json','["花如颊。", "梅如叶。", "小时笑弄阶前月。", "最盈盈。", "最惺惺。", "闲愁未识、无计定深情。", "十年空省春风面。", "花落花开不相见。", "要相逢。", "得相逢。", "须信灵犀，中自有心通。", "同杯勺。", "同斟酌。", "千愁一醉都推却。", "花阴边。", "柳阴边。", "几回拟待、偷怜不成怜。", "伤春玉瘦慵梳掠。", "抛掷琵琶闲处著。", "莫猜疑。", "莫嫌迟。", "鸳鸯翡翠，终是一双飞。"]'),
('song-ci-26','人娇','向子諲','宋','宋词','song-ci','人娇','[]','白似雪花，柔於柳絮。',78,'宋词/ci.song.3000.json','["白似雪花，柔於柳絮。", "胡蝶儿、镇长一处。", "春风骀荡，蓦然吹去。", "得游丝、半空惹住。", "波上精神，掌中态度。", "分明是、彩云团做。", "当年飞燕，从今不数。", "只恐是、高唐梦中神女。"]'),
('song-ci-27','玉楼春','向子諲','宋','宋词','song-ci','玉楼春','[]','记得江城春意动。',64,'宋词/ci.song.3000.json','["记得江城春意动。", "两行疏梅龙脑冻。", "佳人不用辟寒犀，踏雪穿花云鬓重。", "真珠旋滴留人共。", "更爇沈香暖金凤。", "只今梅雪可怜时，都似绿窗前日梦。"]'),
('song-ci-28','玉楼春','向子諲','宋','宋词','song-ci','玉楼春','[]','云窗雾阁春风透。',64,'宋词/ci.song.3000.json','["云窗雾阁春风透。", "蝶绕蜂围花气漏。", "恼人风味恰如梅，倚醉腰肢全是柳。", "细传一曲情偏厚。", "淡扫两山缘底皱。", "归时好月已沈空，只有真香犹满袖。"]'),
('song-ci-29','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','小院深明别有天。',64,'宋词/ci.song.3000.json','["小院深明别有天。", "花能笑语柳能眠。", "雪肌得酒於中暖，莲步凌波分外妍。", "钗燕重，髻荷偏。", "两山斜叠翠连娟。", "朝云无限矜春态，暮雨情知更可怜。"]'),
('song-ci-30','鹧鸪天','向子諲','宋','宋词','song-ci','鹧鸪天','[]','斗帐欢盟不计年。',64,'宋词/ci.song.3000.json','["斗帐欢盟不计年。", "谁知蓦地远如天。", "何曾一霎离心上，怎得而今在眼前。", "鱼不断，雁相连。", "可无小字寄芳笺。", "薄情已是抛人去，更与新愁到酒边。"]'),
('song-ci-31','上西平・金人捧露盘','张元干','宋','宋词','song-ci','上西平・金人捧露盘','[]','卧扁舟，闻寒雨，数佳期。',97,'宋词/ci.song.3000.json','["卧扁舟，闻寒雨，数佳期。", "又还是、轻误仙姿。", "小楼梦冷，觉来应恨我归迟。", "鬓云松处，枕檀斜、露泣花枝。", "名利空萦系，添憔悴，谩孤恓。", "得见了、说与教知。", "偎香倚暖，夜炉围定酒温时。", "任他飞雪洒江天，莫下层梯。"]'),
('song-ci-32','春光好','张元干','宋','宋词','song-ci','春光好','[]','花恨雨，柳嫌风。',52,'宋词/ci.song.3000.json','["花恨雨，柳嫌风。", "客愁浓。", "坐久霜刀飞碎雪，一尊同。", "劳烦玉指春葱。", "未放箸、金盘已空。", "更与个中寻尺素，两情通。"]'),
('song-ci-33','春光好','张元干','宋','宋词','song-ci','春光好','[]','寒食近，踏青时。',52,'宋词/ci.song.3000.json','["寒食近，踏青时。", "画堂西。", "可是春来偏倦绣，乍生儿。", "香绵轻拂胭脂。", "加文褓、初试班衣。", "诮没功夫存问我，且怜伊。"]'),
('song-ci-34','清平乐','张元干','宋','宋词','song-ci','清平乐','[]','乱山深处。',54,'宋词/ci.song.3000.json','["乱山深处。", "雪拥溪桥路。", "晓日乍明催客去。", "惊起玉鸦翻树。", "翠衾香暖檀灰。", "一枝想见疏梅。", "凭仗东风说与，画眉人共春回。"]'),
('song-ci-35','清平乐','张元干','宋','宋词','song-ci','清平乐','[]','明珠翠羽。',54,'宋词/ci.song.3000.json','["明珠翠羽。", "小绾同心缕。", "好去吴松江上路。", "寄与双鱼尺素。", "兰桡飞取归来。", "愁眉待得伊开。", "相见嫣然一笑，眼波先入郎怀。"]'),
('song-ci-36','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','天涯客里秋容晚。',52,'宋词/ci.song.3000.json','["天涯客里秋容晚。", "妖红聊戏思乡眼。", "一朵醉深妆。", "羞渠照鬓霜。", "开时谁断送。", "不待司共花。", "有脚号阳春。", "芳菲属主人。"]'),
('song-ci-37','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','拍堤绿涨桃花水。',52,'宋词/ci.song.3000.json','["拍堤绿涨桃花水。", "画船稳泛东风里。", "丝雨湿苔钱。", "浅寒生禁烟。", "江山留不住。", "却载笙歌去。", "醉倚玉搔头。", "几曾知旅愁。"]'),
('song-ci-38','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','春来春去催人老。',52,'宋词/ci.song.3000.json','["春来春去催人老。", "老夫争肯输年少。", "醉后少年狂。", "白髭殊未妨。", "插花还起舞。", "管领风光处。", "把酒共留春。", "莫教花笑人。"]'),
('song-ci-39','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','雨馀翠袖琼肤润。',52,'宋词/ci.song.3000.json','["雨馀翠袖琼肤润。", "一枝想像伤春困。", "老眼见花时。", "惜花心未衰。", "酿成谁与醉。", "应把流苏缀。", "泪沁枕囊香。", "恼侬归梦长。"]'),
('song-ci-40','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','黄莺啼破纱窗晓。',52,'宋词/ci.song.3000.json','["黄莺啼破纱窗晓。", "兰缸一点窥人小。", "春浅锦屏寒。", "麝煤金博山。", "梦回无处觅。", "细雨梨花湿。", "正是踏青时。", "眼前偏少伊。"]'),
('song-ci-41','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','甘林玉蕊生香雾。',52,'宋词/ci.song.3000.json','["甘林玉蕊生香雾。", "游蜂争采清晨露。", "芳意著人浓。", "微烘曲室中。", "春来瀛海外。", "沈水迎风碎。", "好事富馀熏。", "频分几缕云。"]'),
('song-ci-42','楼上曲','张元干','宋','宋词','song-ci','楼上曲','[]','楼外夕阳明远水。',64,'宋词/ci.song.3000.json','["楼外夕阳明远水。", "楼中人倚东风里。", "何事有情怨别离。", "低鬟背立君应知。", "东望云山君去路。", "断肠迢迢尽愁处。", "明朝不忍见云山。", "从今休傍曲阑干。"]'),
('song-ci-43','楼上曲','张元干','宋','宋词','song-ci','楼上曲','[]','清夜灯前花报喜。',64,'宋词/ci.song.3000.json','["清夜灯前花报喜。", "心随社燕凉风起。", "云路修成宝月时。", "东楼怅望君先归。", "沆瀣秋香生玉井。", "画檐深转梧桐影。", "看君西去侍明光。", "杯中丹桂一枝芳。"]'),
('song-ci-44','豆叶黄・忆王孙','张元干','宋','宋词','song-ci','豆叶黄・忆王孙','[]','冰溪疏影竹边春。',36,'宋词/ci.song.3000.json','["冰溪疏影竹边春。", "翠袖天寒炯暮云。", "雪里精神澹伫人。", "隔重门。", "宝粟生香玉半温。"]'),
('song-ci-45','豆叶黄・忆王孙','张元干','宋','宋词','song-ci','豆叶黄・忆王孙','[]','疏枝冷蕊忽惊春。',36,'宋词/ci.song.3000.json','["疏枝冷蕊忽惊春。", "一点芳心入鬓云。", "风韵情知似玉人。", "笑迎门。", "香暖红炉酒未温。"]'),
('song-ci-46','满庭芳','张元干','宋','宋词','song-ci','满庭芳','[]','梁苑春归，章街雪霁，柳梢华萼初萌。',118,'宋词/ci.song.3000.json','["梁苑春归，章街雪霁，柳梢华萼初萌。", "非烟非雾，新岁乐升平。", "京兆雍容报政，金狨过、九陌尘轻。", "朝回处，青霄路稳，黄色起天庭。", "东风，吹绿鬓，薄罗剪彩，小绾流莺。", "比渭滨甲子，尚父难兄。", "满泛椒觞献寿，斑衣侍、云母分屏。", "明年会，双衣对引，谈笑秉钧衡。"]'),
('song-ci-47','满庭芳','张元干','宋','宋词','song-ci','满庭芳','[]','韩国殊勋，洛都西内，名园甲第相连。',118,'宋词/ci.song.3000.json','["韩国殊勋，洛都西内，名园甲第相连。", "当年绿鬓，独占地行仙。", "文彩风流瑞世，延朱履、丝竹喧阗。", "人皆仰，一门相业，心许子孙贤。", "中兴，方庆会，再逢甲子，重数天元。", "问千龄谁比，五福俱全。", "此去沙堤步稳，调金鼎、七叶貂蝉。", "香檀缓，杯传鹦鹉，新月正娟娟。"]'),
('song-ci-48','满庭芳','张元干','宋','宋词','song-ci','满庭芳','[]','玉叶联芳，天潢分润，寿筵长对熏风。',118,'宋词/ci.song.3000.json','["玉叶联芳，天潢分润，寿筵长对熏风。", "间平襟度，濮邸行尊崇。", "忠孝家传大雅，无喜愠、一种宽容。", "芝兰盛，彩衣嬉戏，亲睦冠西宗。", "丝纶，膺重寄，遥防迁美，本镇恩隆。", "应萱堂齐福，诞月仍同。", "花蕊香浓气暖，凝瑞露、满酌金锺。", "龙光近，星飞驿马，宣入嗣王封。"]'),
('song-ci-49','满庭芳','张元干','宋','宋词','song-ci','满庭芳','[]','三十年来，云游行化，草鞋踏破尘沙。',118,'宋词/ci.song.3000.json','["三十年来，云游行化，草鞋踏破尘沙。", "遍参尊宿，曾记到京华。", "衲子如麻似粟，谁会笑、瞿老拈花。", "经离乱，青山尽处，海角又天涯。", "今宵，闲打睡，明朝粥饭，随分僧家。", "把木佛烧却，除是丹霞。", "撞著门徒施主，蓦然个、喜舍由他。", "庐陵米，还知价例，毫发更无差。"]'),
('song-ci-50','瑞鹤仙','张元干','宋','宋词','song-ci','瑞鹤仙','[]','倚格天峻阁。',126,'宋词/ci.song.3000.json','["倚格天峻阁。", "舞庭槐阴转，盆榴红烁。", "香风泛帘幕。", "拥霞裾琼佩，真珠璎珞。", "华阳庆渥。", "诞兰房、流芳秀萼。", "有赤绳系足，从来相门，自然媒妁。", "游戏人间荣贵，道要元微，水源清浊。", "长生大药。", "彩鸾韵，凤箫鹤。", "对木公金母，子孙三世，妇姑为寿满酌。", "看千龄，举家飞升，玉京更乐。"]'),
('song-ci-51','瑞鹤仙','张元干','宋','宋词','song-ci','瑞鹤仙','[]','喜西园放钥。',125,'宋词/ci.song.3000.json','["喜西园放钥。", "对燕寝香润，棠阴寒薄。", "东风夜来恶。", "禁烟时天气，莺啼花落。", "新晴共约。", "怕韶光、容易过却。", "把铜壶、缓浮金杯，禊游行乐。", "弦索。", "笙簧声里，还记兰房，正垂罗幕。", "初眠弱柳。", "梅如豆，玉如琢。", "向凤凰池上，鸳鸯影里，他年何啻紫橐。", "看流芳，继踵韦平，盛传巩洛。"]'),
('song-ci-52','瑶台第一层','张元干','宋','宋词','song-ci','瑶台第一层','[]','宝历祥开飞练上，青冥万里光。',120,'宋词/ci.song.3000.json','["宝历祥开飞练上，青冥万里光。", "石城形胜，秦淮风景，威凤来翔。", "腊馀春色早，兆钓璜、贤佐兴王。", "对熙旦，正格天同德，全魏分疆。", "荧煌。", "五云深处，化钧独运斗魁旁。", "绣裳龙尾，千官师表，万事平章。", "景锺文瑞世，醉尚方、难老金浆。", "庆垂芳。", "看云屏间坐，象笏堆床。"]'),
('song-ci-53','瑶台第一层','张元干','宋','宋词','song-ci','瑶台第一层','[]','江左风流锺间气，洲分二水长。',120,'宋词/ci.song.3000.json','["江左风流锺间气，洲分二水长。", "凤凰台畔，投怀玉燕，照射神光。", "豆花初秀雨，散暑空、洗出秋凉。", "庆生旦，正圆蟾呈瑞、仙桂飘香。", "肝肠。", "掞文摛锦，驾云乘鹤下鹓行。", "紫枢将命，紫微如绋，常近君王。", "旧山同梓里，荷月旦、久已平章。", "九霞觞。", "荐刀圭丹饵，衮绣朝裳。"]'),
('song-ci-54','望海潮','张元干','宋','宋词','song-ci','望海潮','[]','苍山烟澹，寒溪风定，玉簪罗带绸缪。',129,'宋词/ci.song.3000.json','["苍山烟澹，寒溪风定，玉簪罗带绸缪。", "轻霭暮飞，青冥远净，珠星璧月光浮。", "城际踊层楼。", "正翠帘高卷，绿琐低钩。", "影落尊罍，气和歌管共清游。", "史君冠世风流。", "拥香鬟凭槛，雾鬓凝眸。", "银烛暖宵，花光照席，谯门莫报更筹。", "逸兴醉无休。", "赋探梅芳信，翻曲新讴。", "想见疏枝冷蕊，春意到沙洲。"]'),
('song-ci-55','望海潮','张元干','宋','宋词','song-ci','望海潮','[]','麒麟图画，貂蝉冠冕，青毡自属元勋。',129,'宋词/ci.song.3000.json','["麒麟图画，貂蝉冠冕，青毡自属元勋。", "绿野旧游，平泉雅咏，霞舒烟卷朝昏。", "风月小阳春。", "照玳筵珠履，公子王孙。", "雪度嵩高，影横伊水庆生申。", "早梅长醉芳尊。", "况中兴盛际，宥密宗臣。", "琳馆奉祠，金瓯覆字，和羹妙手还新。", "光射紫微垣。", "看五云朝斗，千载逢辰。", "开取八荒寿域，一气转洪钧。"]'),
('song-ci-56','十月桃','张元干','宋','宋词','song-ci','十月桃','[]','年华催晚，听尊前偏唱，冲暖欺寒。',121,'宋词/ci.song.3000.json','["年华催晚，听尊前偏唱，冲暖欺寒。", "乐府谁知，分付点化金丹。", "中原旧游何在，频入梦、老眼空潸。", "撩人冷蕊，浑似当时，无语低鬟。", "有多情多病文园。", "向雪后寻春，醉里凭阑。", "独步群芳，此花风度天然。", "罗浮淡妆素质，呼翠凤、飞舞斓斑。", "参横月落，留恨醒来，满地香残。"]'),
('song-ci-57','十月桃','张元干','宋','宋词','song-ci','十月桃','[]','蟠桃三熟，正清霜吹冷，爱日烘香。',121,'宋词/ci.song.3000.json','["蟠桃三熟，正清霜吹冷，爱日烘香。", "小试芳菲，时候无限风光。", "洛滨老人星见，□少室、云雾开祥。", "丹青万汇，熊兆崑台，凤举朝阳。", "向元枢会辅岩廊。", "记名著金瓯，位入中堂。", "梦熟钧天，屡惊颠倒衣裳。", "黄发更宜补衮，归去定、军国平章。", "管弦珠翠，兰玉簪缨，岁岁称觞。"]'),
('song-ci-58','感皇恩','张元干','宋','宋词','song-ci','感皇恩','[]','绿发照魁星，平康争看。',81,'宋词/ci.song.3000.json','["绿发照魁星，平康争看。", "锦绣肝肠五千卷。", "出逢熙运，早侍玉皇香案。", "禁涂扬历遍，纡宸眷。", "安养老成，十年萧散。", "天要中兴相公健。", "生朝开宴，长是通宵弦管。", "藕花香不断，南风远。"]'),
('song-ci-59','感皇恩','张元干','宋','宋词','song-ci','感皇恩','[]','年少太平时，名园甲第。',81,'宋词/ci.song.3000.json','["年少太平时，名园甲第。", "谈笑雍容万锺贵。", "姚黄重绽，长对小春天气。", "绮罗丛里惯，今朝醉。", "台衮向贤，元枢虚位。", "壮岁青云自曾致。", "流霞麟脯，难老洛滨风味。", "谢公须再为，苍生起。"]'),
('song-ci-60','感皇恩','张元干','宋','宋词','song-ci','感皇恩','[]','荔子著花繁，清微庭院。',81,'宋词/ci.song.3000.json','["荔子著花繁，清微庭院。", "贺厦双飞画梁燕。", "绮罗丛里，百和炉烟祝愿。", "愿从今日去，身长健。", "檀板竞催，榕阴初转。", "舞袖风前翠翘颤。", "明年开府，锡宴金锺宣劝。", "寿星朝北斗，君王眷。"]'),
('song-ci-61','感皇恩','张元干','宋','宋词','song-ci','感皇恩','[]','豹尾引黄幡，宣麻金殿。',81,'宋词/ci.song.3000.json','["豹尾引黄幡，宣麻金殿。", "雨露恩浓自天遣。", "搢绅交誉，最乐至诚为善。", "信知宗姓喜，君王眷。", "宝炬密香，玉卮波滟。", "醉拥笙歌夜深院。", "西清班近，雅称元戎同燕。", "要看茅土相，貂蝉面。"]'),
('song-ci-62','夏云峰','张元干','宋','宋词','song-ci','夏云峰','[]','涌冰轮，飞沆瀣，霄汉万里云开。',113,'宋词/ci.song.3000.json','["涌冰轮，飞沆瀣，霄汉万里云开。", "南极瑞占象纬，寿应三台。", "锦肠珠唾，锺间气、卓荦天才。", "正暑，有祥光照社，玉燕投怀。", "新堂深处捧杯，乍香泛水芝，空翠风回。", "凉送燕歌缓舞，醉罥瑶钗。", "长生难老，都道是、柏叶仙阶。", "笑傲，且山中宰相，平地蓬莱。"]'),
('song-ci-63','千秋岁','张元干','宋','宋词','song-ci','千秋岁','[]','相门出相，和气浓春酿。',87,'宋词/ci.song.3000.json','["相门出相，和气浓春酿。", "传家冠佩云台上。", "庞眉扶寿杖。", "绿发披仙氅。", "星两两。", "泰阶已应升平象。", "玉砌兰芽长。", "定向东风赏。", "添彩袖，褰罗幌。", "丝簧俱妙手，珠翠争宫样。", "江海量。", "年年醉里翻新唱。"]'),
('song-ci-64','水龙吟','张元干','宋','宋词','song-ci','水龙吟','[]','水晶宫映长城，藕花万顷开浮蕊。',123,'宋词/ci.song.3000.json','["水晶宫映长城，藕花万顷开浮蕊。", "红妆翠盖，生朝时候，湖山摇曳。", "珠露争圆，香风不断，普熏沈水。", "似瑶池侍女，霞裾缓步，寿烟光里。", "霖雨已沾千里。", "兆丰年、十分和气。", "星郎绿鬓，锦波春酿，碧筒宜醉。", "荷橐还朝，青毡奕世，除书将至。", "看巢龟戏叶，蟠桃著子，祝三千岁。"]'),
('song-ci-65','南乡子','张元干','宋','宋词','song-ci','南乡子','[]','山寺辋川图。',66,'宋词/ci.song.3000.json','["山寺辋川图。", "霜叶云林锦绣居。", "寿斝浮春珠翠拥，欢娱。", "满院流泉绕绮疏。", "道气自肤腴。", "几席轻尘一点无。", "天要耆英修相业，清都。", "已有泥书降玉除。"]'),
('song-ci-66','卷珠帘・蝶恋花','张元干','宋','宋词','song-ci','卷珠帘・蝶恋花','[]','祥景飞光盈衮绣。',70,'宋词/ci.song.3000.json','["祥景飞光盈衮绣。", "流庆昆台，自是神仙胄。", "谁遣阳和放春透。", "化工重入丹青手。", "云璈锦瑟争为寿。", "玉带金鱼，共愿人长久。", "偷取蟠桃荐芳酒。", "更看南极星朝斗。"]'),
('song-ci-67','醉蓬莱','张元干','宋','宋词','song-ci','醉蓬莱','[]','对小春桃艳，曲室炉红，乍寒天气。',120,'宋词/ci.song.3000.json','["对小春桃艳，曲室炉红，乍寒天气。", "七叶蓂开，应金章通贵。", "梦草银钩，灿花珠唾，是素来风味。", "满腹经纶，回天议论，昆台仙裔。", "秘殿升华，紫枢勋旧，退步真祠，简心端扆。", "迎日天元，听正衙宣制。", "尽洗中原，遍为霖雨，宴后堂歌吹。", "柏子千秋，丹砂九转，今宵长醉。"]'),
('song-ci-68','陇头泉・多丽','张元干','宋','宋词','song-ci','陇头泉・多丽','[]','少年时，壮怀谁与重论。',173,'宋词/ci.song.3000.json','["少年时，壮怀谁与重论。", "视文章、真成小技，要知吾道称尊。", "奏公车、治安秘计，乐油幕、谈笑从军。", "百镒黄金，一双白璧，坐看同辈上青云。", "事大谬，转头流落，徒走出修门。", "三十载，黄梁未熟，沧海扬尘。", "念向来、浩歌独往，故园松菊犹存。", "送飞鸿、五弦寓目，望爽气、西山忘言。", "整顿乾坤，廓清宇宙，男儿此志会须伸。", "更有几、渭川垂钓，投老策奇勋。", "天难问，何妨袖手，且做闲人。"]'),
('song-ci-69','天仙子','张元干','宋','宋词','song-ci','天仙子','[]','楼外轻阴春澹伫。',80,'宋词/ci.song.3000.json','["楼外轻阴春澹伫。", "数点杏梢寒食雨。", "少年油壁记寻芳，梁苑路。", "今何处。", "千树红云空梦去。", "惊见此花须折取。", "明日满城传侍女。", "情知醉里惜花深，留春住。", "听莺语。", "一段风流天赋与。"]'),
('song-ci-70','鹊桥仙','张元干','宋','宋词','song-ci','鹊桥仙','[]','靓妆艳态，娇波流盼，双靥横涡半笑。',68,'宋词/ci.song.3000.json','["靓妆艳态，娇波流盼，双靥横涡半笑。", "尊前烛畔粉生光，更低唱、新翻转调。", "花房结子，冰枝清瘦。", "醉依香浓寒峭。", "雏莺新啭上林声，惊梦断、池堂春草。"]'),
('song-ci-71','渔父家风・诉衷情令','张元干','宋','宋词','song-ci','渔父家风・诉衷情令','[]','八年不见荔枝红。',54,'宋词/ci.song.3000.json','["八年不见荔枝红。", "肠断故园东。", "风枝露叶新采，怅望冷香浓。", "冰透骨，玉开容。", "想筠笼。", "今宵归去，满颊天浆，更御冷风。"]'),
('song-ci-72','生查子','张元干','宋','宋词','song-ci','生查子','[]','天生几种香，风味因花见。',48,'宋词/ci.song.3000.json','["天生几种香，风味因花见。", "旖旎透香肌，仿佛飞花片。", "雨润惜馀熏，烟断犹相恋。", "不似薄情人，浓淡分深浅。"]'),
('song-ci-73','减字木兰花','张元干','宋','宋词','song-ci','减字木兰花','[]','客亭小会。',52,'宋词/ci.song.3000.json','["客亭小会。", "可惜无欢容易醉。", "归去更阑。", "细雨鸣窗一夜寒。", "昏然独坐。", "举世疏狂谁似我。", "强拨炉烟。", "也道今宵是上元。"]'),
('song-ci-74','眼儿媚','张元干','宋','宋词','song-ci','眼儿媚','[]','萧萧疏雨滴梧桐。',58,'宋词/ci.song.3000.json','["萧萧疏雨滴梧桐。", "人在绮窗中。", "离愁遍绕，天涯不尽，却在眉峰。", "娇波暗落相思泪，流破脸边红。", "可怜瘦似，一枝春柳，不奈东风。"]'),
('song-ci-75','昭君怨','张元干','宋','宋词','song-ci','昭君怨','[]','春院深深莺语。',48,'宋词/ci.song.3000.json','["春院深深莺语。", "花怨一帘烟雨。", "禁火已销魂。", "更黄昏。", "衾暖麝灯落灺。", "雨过重门深夜。", "枕上百般猜。", "未归来。"]'),
('song-ci-76','夜游宫','张元干','宋','宋词','song-ci','夜游宫','[]','半吐寒梅未拆。',71,'宋词/ci.song.3000.json','["半吐寒梅未拆。", "双鱼洗、冰澌初结。", "户外明帘风任揭。", "拥红炉，洒窗间，闻霰雪。", "比去年时节。", "这心事、有人忺说。", "斗帐重熏鸳被叠。", "酒微醺，管灯花，今夜别。"]'),
('song-ci-77','杨柳枝','张元干','宋','宋词','song-ci','杨柳枝','[]','深院今宵枕簟凉。',48,'宋词/ci.song.3000.json','["深院今宵枕簟凉。", "烛花光。", "更筹何事促行觞。", "恼刚肠。", "老去一蓑烟雨里，钓沧浪。", "看君鸣凤向朝阳。", "且腰黄。"]'),
('song-ci-78','彩鸾归令','张元干','宋','宋词','song-ci','彩鸾归令','[]','珠履争围。',53,'宋词/ci.song.3000.json','["珠履争围。", "小立春风趁拍低。", "态闲不管乐催伊。", "整铢衣。", "粉融香润随人劝，玉困花娇越样宜。", "凤城灯夜旧家时。", "数他谁。"]'),
('song-ci-79','江神子・江城子','张元干','宋','宋词','song-ci','江神子・江城子','[]','梦中北去又南来。',86,'宋词/ci.song.3000.json','["梦中北去又南来。", "饱风埃。", "鬓华衰。", "浮木飞蓬，踪迹为谁催。", "自笑自悲还自语，一杯酒，鼻如雷。", "晓舆行处觉春回。", "屑琼瑰。", "糁莓苔。", "病眼冲寒，欲闭又还开。", "水近人家篱落畔，遥认得，一枝梅。"]'),
('song-ci-80','西江月','张元干','宋','宋词','song-ci','西江月','[]','小阁劣容老子，北窗仍递南风。',58,'宋词/ci.song.3000.json','["小阁劣容老子，北窗仍递南风。", "维摩丈室久空空。", "不与散花同梦。", "且作大真游戏，未甘金粟龙锺。", "怜君病后颊颧隆。", "识取小儿戏弄。"]'),
('song-ci-81','诉衷情','张元干','宋','宋词','song-ci','诉衷情','[]','儿时初未识方红。',54,'宋词/ci.song.3000.json','["儿时初未识方红。", "学语问西东。", "对客呼为红蕊，此兴已偏浓。", "嗟白首，抗尘容。", "费牢笼。", "星球何在，鹤顶长丹，谁寄南风。"]'),
('song-ci-82','采桑子','张元干','宋','宋词','song-ci','采桑子','[]','华堂清暑榕阴重，梦里江寒。',52,'宋词/ci.song.3000.json','["华堂清暑榕阴重，梦里江寒。", "火齐星繁。", "兴在冰壶玉井栏。", "风枝露叶谁新采，欲饱防悭。", "遗恨空盘。", "留取香红满地看。"]'),
('song-ci-83','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','山城何岁无风雨。',52,'宋词/ci.song.3000.json','["山城何岁无风雨。", "楼台底事随波去。", "归棹望谯门。", "沙痕炯断云。", "诗成空吊古。", "想像经行处。", "陵谷有馀悲。", "举觞浇别离。"]'),
('song-ci-84','菩萨蛮','张元干','宋','宋词','song-ci','菩萨蛮','[]','微云红衬馀霞绮。',52,'宋词/ci.song.3000.json','["微云红衬馀霞绮。", "明星碧浸银河水。", "猗枕画檐风。", "愁生草际蛩。", "雁行离塞晚。", "不道衡阳远。", "归恨隔重山。", "楼高莫凭栏。"]'),
('song-ci-85','浣溪沙','张元干','宋','宋词','song-ci','浣溪沙','[]','睡起中庭月未蹉。',48,'宋词/ci.song.3000.json','["睡起中庭月未蹉。", "繁香随影上轻罗。", "多情肯放一春过。", "比似雪时犹带韵，不如梅处却缘多。", "酒边枕畔奈愁何。"]'),
('song-ci-86','好事近','张元干','宋','宋词','song-ci','好事近','[]','华烛炯离觞，山吐四更寒月。',53,'宋词/ci.song.3000.json','["华烛炯离觞，山吐四更寒月。", "公子唾花枝玉，尽一时豪杰。", "三冬兰若读书灯，想见太清绝。", "纸帐地炉香暖，傲一窗风月。"]'),
('song-ci-87','南歌子','张元干','宋','宋词','song-ci','南歌子','[]','玉斧修圆了，冰轮分外清。',62,'宋词/ci.song.3000.json','["玉斧修圆了，冰轮分外清。", "共看星向绣衣明。", "元是生朝为寿、对难兄。", "鸿雁翻秋影，埙篪和笑声。", "他年中令彩衣荣。", "记取今宵丹荔、醉瑶觥。"]'),
('song-ci-88','醉花阴','张元干','宋','宋词','song-ci','醉花阴','[]','紫菊红萸开犯早。',62,'宋词/ci.song.3000.json','["紫菊红萸开犯早。", "独占秋光老。", "酝造一般清，比著芝兰，犹自争多少。", "霜刀剪叶呈纤巧。", "手拈迎人笑。", "云鬓一枝斜，小阁幽窗，是处都香了。"]'),
('song-ci-89','点绛唇','张元干','宋','宋词','song-ci','点绛唇','[]','小雨忺晴，坐来池上荷珠碎。',50,'宋词/ci.song.3000.json','["小雨忺晴，坐来池上荷珠碎。", "倬眉浓翠。", "怎不交人醉。", "美盼流觞，白鹭窥秋水。", "天然媚。", "大家休睡。", "笑倚西风里。"]'),
('song-ci-90','花心动','张元干','宋','宋词','song-ci','花心动','[]','水馆风亭，晚香浓、一番芰荷新雨。',126,'宋词/ci.song.3000.json','["水馆风亭，晚香浓、一番芰荷新雨。", "簟枕乍闲，襟裾初试，散尽满天袢暑。", "断云却送轻雷去。", "疏林外、玉钩微吐。", "夜渐永，秋惊败叶，凉生亭户。", "天上佳期久阻。", "银河畔、仙车缥缈云路。", "旧怨未平，幽欢驻，恨入半天风露。", "绮罗人散金猊冷，醉魂到、华胥深处。", "洞户悄、南楼画角自语。"]'),
('song-ci-91','蓦山溪','张元干','宋','宋词','song-ci','蓦山溪','["\u94b1\u5858\u6c5f"]','一番小雨，陡觉添秋色。',102,'宋词/ci.song.3000.json','["一番小雨，陡觉添秋色。", "桐叶下银床，又送个、凄凉消息。", "故乡何处，搔首对西风，衣线断，带围宽，衰鬓添新白。", "钱塘江上，冠盖如云积。", "骑马傍朱门，谁肯念、尘埃墨客。", "佳人信杳，日暮碧云深，楼独倚，镜频看，此意无人识。"]'),
('song-ci-92','西楼月・春晓曲','张元干','宋','宋词','song-ci','西楼月・春晓曲','[]','瑶轩倚槛春风度。',32,'宋词/ci.song.3000.json','["瑶轩倚槛春风度。", "柳垂烟，花带露。", "半闲鸳被怯馀寒，燕子时来窥绣户。"]'),
('song-ci-93','瑞鹧鸪','邓肃','宋','宋词','song-ci','瑞鹧鸪','[]','北书一纸惨天容。',64,'宋词/ci.song.3000.json','["北书一纸惨天容。", "花柳春风不敢秾。", "未学宣尼歌凤德，姑从阮籍哭途穷。", "此身已落千山外，旧事回思一梦中。", "何日中兴烦吉甫，洗开阴翳放晴空。"]'),
('song-ci-94','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','带雨梨花看上马，问人底事匆匆。',70,'宋词/ci.song.3000.json','["带雨梨花看上马，问人底事匆匆。", "于飞有愿恨难从。", "大鹏抟九万，鹦鹉锁金笼。", "忽忽便为千里隔，危岑已接高穹。", "回头那忍问前踪。", "家留烟雨外，人在斗牛中。"]'),
('song-ci-95','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','百尺危楼初过雨，清风凛作轻寒。',70,'宋词/ci.song.3000.json','["百尺危楼初过雨，清风凛作轻寒。", "一声渔笛在云端。", "黄昏帘幕卷，新月半阑干。", "青翼不来音信断，云窗杳隔三山。", "何当携手便骖鸾。", "今宵同胜景，玉斝不留残。"]'),
('song-ci-96','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','春雪一瓯扶醉玉，翩翩两腋生风。',70,'宋词/ci.song.3000.json','["春雪一瓯扶醉玉，翩翩两腋生风。", "柳腰无力殢云踪。", "陈郎投辖意，分袂忍匆匆。", "白玉琢杯龙麝泛，瀼瀼天酒争浓。", "何妨一饮上青骢。", "晴空行夜月，缓辔水晶宫。"]'),
('song-ci-97','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','剑水泠泠行碧玉，扁舟一叶吹风。',70,'宋词/ci.song.3000.json','["剑水泠泠行碧玉，扁舟一叶吹风。", "玉人招手画桥东。", "浩歌随月去，春在小楼中。", "帘幕低垂围笃耨，雕觞笑捧春葱。", "谩将雨意作云浓。", "单于吹未彻，门外响玲珑。"]'),
('song-ci-98','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','雨过荼縻春欲放，轻寒约住馀芳。',70,'宋词/ci.song.3000.json','["雨过荼縻春欲放，轻寒约住馀芳。", "南园今日被朝阳。", "琼葩开万点，尘世满天香。", "百卉丛中红紫乱，玉肌自笑孤光。", "清风翦翦过纱窗。", "馀酲空一洗，不数寿阳妆。"]'),
('song-ci-99','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','独宿禅房清梦断，鸡声唤起晨钟。',70,'宋词/ci.song.3000.json','["独宿禅房清梦断，鸡声唤起晨钟。", "出门晓月耿寒空。", "小池凝翡翠，竹外跨飞虹。", "梅坞不知何处了，傍篱临水重重。", "啸歌都在冷香中。", "人间那有此，天上广寒宫。"]'),
('song-ci-100','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','夜饮不知更漏永，馀酣困染朝阳。',70,'宋词/ci.song.3000.json','["夜饮不知更漏永，馀酣困染朝阳。", "庭前莺燕乱丝簧。", "醉眠犹未起，花影满晴窗。", "帘外报言天色好，水沈已染罗裳。", "檀郎欲起趁春狂。", "佳人嗔不语，劈面噀丁香。"]'),
('song-ci-101','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','夜静黄云承宝袜，九疑人到羊家。',70,'宋词/ci.song.3000.json','["夜静黄云承宝袜，九疑人到羊家。", "蕊宫仙曲送流霞。", "东陵分玉井，远胜隔荷花。", "绰约旗亭沾一笑，众惊食枣如瓜。", "画桥烟柳忽翻鸦。", "醉鬟倾绿醑，参月共横斜。"]'),
('song-ci-102','临江仙','邓肃','宋','宋词','song-ci','临江仙','[]','楼北楼南青不断，晴空总是春容。',70,'宋词/ci.song.3000.json','["楼北楼南青不断，晴空总是春容。", "先来无处问郎踪。", "那堪风不定，雨尽一窗红。", "初恨水中徒捉月，而今水月俱空。", "谩将雨意伴云浓。", "临风千点泪，不到浙江东。"]'),
('song-ci-103','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','雨入空阶滴夜长。',48,'宋词/ci.song.3000.json','["雨入空阶滴夜长。", "月行云外借孤光。", "独将心事步长廊。", "深锁重门飞不去，巫山何日梦襄王。", "一床衾枕冷凄香。"]'),
('song-ci-104','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','傍竹柴门俯碧流。',48,'宋词/ci.song.3000.json','["傍竹柴门俯碧流。", "见人无语眼横秋。", "鸣机轧轧弄纤柔。", "定有回文传窦子，何时银汉渡牵牛。", "归来风雨夜飕飕。"]'),
('song-ci-105','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','宿雨潜回海宇春。',48,'宋词/ci.song.3000.json','["宿雨潜回海宇春。", "晓风徐散日边云。", "熙熙人意一番新。", "破睡海棠能媚客，舞风垂柳似招人。", "春衫归去马蹄轻。"]'),
('song-ci-106','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','阑外彤云已满空。',48,'宋词/ci.song.3000.json','["阑外彤云已满空。", "帘旌不动石榴红。", "谁将秋色到楼中。", "玛瑙一泓浮翠玉，瓠犀终日凛天风。", "炎洲人到广寒宫。"]'),
('song-ci-107','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','高会横山酒八仙。',48,'宋词/ci.song.3000.json','["高会横山酒八仙。", "烟云不减九华妍。", "暖风琼树倚楼前。", "妙唱一声尘暗落，靓妆四座玉相连。", "骖鸾何日共翩翩。"]'),
('song-ci-108','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','二八佳人宴九仙。',48,'宋词/ci.song.3000.json','["二八佳人宴九仙。", "华堂清静斗春妍。", "琼枝相倚妙无前。", "良夜黄云来缥缈，东风碧酒意留连。", "花间蝶梦想翩翩。"]'),
('song-ci-109','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','半醉倚人落珥簪。',48,'宋词/ci.song.3000.json','["半醉倚人落珥簪。", "天香不数海南沈。", "时倾秋水话春心。", "已觉吹箫归碧落，从今禊饮笑山阴。", "金杯休惜十分深。"]'),
('song-ci-110','浣溪沙','邓肃','宋','宋词','song-ci','浣溪沙','[]','海畔山如碧玉簪。',48,'宋词/ci.song.3000.json','["海畔山如碧玉簪。", "天涯消息叹鱼沈。", "赖逢倾国洗愁心。", "莫为世情生旅况，且因乐事惜光阴。", "明朝红雨已春深。"]'),
('song-ci-111','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','隔窗瑟瑟闻飞雪。',52,'宋词/ci.song.3000.json','["隔窗瑟瑟闻飞雪。", "洞房半醉回春色。", "银烛照更长。", "罗屏围夜香。", "玉山幽梦晓。", "明日天涯杳。", "倚户黯芙蓉。", "涓涓秋露浓。"]'),
('song-ci-112','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','萋萋欲遍池塘草。',52,'宋词/ci.song.3000.json','["萋萋欲遍池塘草。", "轻寒却怕春光老。", "微雨湿昏黄。", "梨花啼晚妆。", "低垂帘四面。", "沈水环深院。", "太白困鸳鸯。", "天风吹梦长。"]'),
('song-ci-113','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','飞红欲带春风去。',52,'宋词/ci.song.3000.json','["飞红欲带春风去。", "柳丝却织春风住。", "去住任春风。", "只愁尊俎空。", "今朝鞭马去。", "又得高阳侣。", "半醉踏花归。", "霜蹄骄欲飞。"]'),
('song-ci-114','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','帘旌不动薰馀热。',52,'宋词/ci.song.3000.json','["帘旌不动薰馀热。", "高堂谁送能言雪。", "一笑下人间。", "天风袭坐寒。", "歌声云外去。", "句句苏仙语。", "曲罢一尊空。", "飘然欲驭风。"]'),
('song-ci-115','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','廉纤细雨连天远。',52,'宋词/ci.song.3000.json','["廉纤细雨连天远。", "纱窗不隔斜风冷。", "花柳自生春。", "无聊空闭门。", "双双携手处。", "回首烟汀暮。", "嬉笑在高楼。", "知人牢落否。"]'),
('song-ci-116','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','垂杨袅袅腰肢软。',52,'宋词/ci.song.3000.json','["垂杨袅袅腰肢软。", "寒溪练练琉璃浅。", "短艇卧吹风。", "生涯一叶中。", "五湖须径去。", "何用若耶女。", "烟雨暝沙汀。", "花香唤酒醒。"]'),
('song-ci-117','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','腰肢欲趁杨花去。',52,'宋词/ci.song.3000.json','["腰肢欲趁杨花去。", "歌声能遏行云住。", "杯酒醉东风。", "羁愁一洗空。", "谪仙清饮露。", "意在飞琼侣。", "未醉即求归。", "新词句欲飞。"]'),
('song-ci-118','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','归心谩逐飞云去。',52,'宋词/ci.song.3000.json','["归心谩逐飞云去。", "欢情却为芳菲住。", "翠袖拥香风。", "宁辞玉斝空。", "主人承湛露。", "元是皋夔侣。", "早晚定遄归。", "商霖四海飞。"]'),
('song-ci-119','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','["\u957f\u6c5f"]','骑鲸好向云端去。',52,'宋词/ci.song.3000.json','["骑鲸好向云端去。", "踏花偶为狂朋住。", "笑语凛生风。", "眼高四海空。", "羊裘冲雨露。", "我是渔樵侣。", "已趁白鸥归。", "长江自在飞。"]'),
('song-ci-120','菩萨蛮','邓肃','宋','宋词','song-ci','菩萨蛮','[]','一心唯欲南园去。',52,'宋词/ci.song.3000.json','["一心唯欲南园去。", "东山著意留难住。", "曾惯识追风。", "马群今已空。", "金盘盛玉露。", "情绝鸳鸯侣。", "破贼凯还归。", "冲天看一飞。"]'),
('song-ci-121','南歌子','邓肃','宋','宋词','song-ci','南歌子','[]','竹影窥灯暗，泉声语夜长。',62,'宋词/ci.song.3000.json','["竹影窥灯暗，泉声语夜长。", "小窗无梦到高唐。", "独引三杯长啸、步修廊。", "月午衣衫冷，莲开风露香。", "阑干西角下银潢。", "我欲乘槎天上、泛寒光。"]'),
('song-ci-122','南歌子','邓肃','宋','宋词','song-ci','南歌子','[]','皓月明腮雪，冷风乱鬓云。',62,'宋词/ci.song.3000.json','["皓月明腮雪，冷风乱鬓云。", "高楼帘幕夜生春。", "半醉倚人秋水、欲斜倾。", "晓雨双溪涨，归舟一叶轻。", "杳无青翼寄殷勤。", "目断烟波渔火、又黄昏。"]'),
('song-ci-123','南歌子','邓肃','宋','宋词','song-ci','南歌子','[]','云绕风前鬓，春开槛里妆。',62,'宋词/ci.song.3000.json','["云绕风前鬓，春开槛里妆。", "凤屏清昼蔼龙香。", "浅画娥眉新样、远山长。", "比翼曾同梦，双鱼隔异乡。", "玉楼依旧暗垂杨。", "楼下落花流水、自斜阳。"]'),
('song-ci-124','南歌子','邓肃','宋','宋词','song-ci','南歌子','[]','驿畔争撏草，车前自喂牛。',62,'宋词/ci.song.3000.json','["驿畔争撏草，车前自喂牛。", "凤城一别几经秋。", "身在天涯海角、忍回头。", "旅梦惊残月，劳生寄小舟。", "都人应也望宸游。", "早晚葱葱佳气、满皇州。"]'),
('song-ci-125','诉衷情','邓肃','宋','宋词','song-ci','诉衷情','[]','乘鸾缥缈过三山。',54,'宋词/ci.song.3000.json','["乘鸾缥缈过三山。", "游戏下人间。", "金尊不辞频倒，春色上朱颜。", "依暖玉，掠风鬟。", "语关关。", "惟愁漏短，雨散云飞，骑月空还。"]'),
('song-ci-126','诉衷情','邓肃','宋','宋词','song-ci','诉衷情','[]','龙头一语定闽山。',54,'宋词/ci.song.3000.json','["龙头一语定闽山。", "黄色上眉间。", "诏书促归金阙，玉带侍天颜。", "拢象板，亸宫鬟。", "唱阳关。", "从容禁闼，若念林泉，应寄书还。"]'),
('song-ci-127','诉衷情','邓肃','宋','宋词','song-ci','诉衷情','[]','从来云雨过巫山。',54,'宋词/ci.song.3000.json','["从来云雨过巫山。", "只托梦魂间。", "何如醉逢倾国，春到一瓢颜。", "歌窈窕，舞双鬟。", "掩云关。", "重城五鼓，月下西楼，不忍轻还。"]'),
('song-ci-128','长相思令・长相思','邓肃','宋','宋词','song-ci','长相思令・长相思','[]','一重山。',44,'宋词/ci.song.3000.json','["一重山。", "两重山。", "山远天高烟水寒。", "相思枫叶丹。", "菊花开，菊花残。", "雁已西飞人未还。", "一帘风月闲。"]'),
('song-ci-129','长相思令・长相思','邓肃','宋','宋词','song-ci','长相思令・长相思','[]','一重溪。',44,'宋词/ci.song.3000.json','["一重溪。", "两重溪。", "溪转山回路欲迷。", "朱阑出翠微。", "梅花飞。", "雪花飞。", "醉卧幽亭不掩扉。", "冷香寻梦归。"]'),
('song-ci-130','长相思令・长相思','邓肃','宋','宋词','song-ci','长相思令・长相思','[]','红花飞。',44,'宋词/ci.song.3000.json','["红花飞。", "白花飞。", "郎与春风同别离。", "春归郎不归。", "雨霏霏。", "雪霏霏。", "又是黄昏独掩扉。", "孤灯隔翠帷。"]'),
('song-ci-131','西江月','邓肃','宋','宋词','song-ci','西江月','[]','腊雪犹埋石巘，春风已入梅梢。',58,'宋词/ci.song.3000.json','["腊雪犹埋石巘，春风已入梅梢。", "冷香随马上琼瑶。", "不与时人同到。", "拍手恐惊星斗，高歌已在烟霄。", "醉呼玉女解金貂。", "笑问何如蓬岛。"]'),
('song-ci-132','西江月','邓肃','宋','宋词','song-ci','西江月','[]','风荐荷香翦翦，月行竹影徐徐。',58,'宋词/ci.song.3000.json','["风荐荷香翦翦，月行竹影徐徐。", "微闻环佩过庭除。", "恐是阳台行雨。", "玉笋轻笼乐句，流莺夜转诗馀。", "酒酣风劲露凝珠。", "我欲骖鸾归去。"]'),
('song-ci-133','水调歌头','林淳','宋','宋词','song-ci','水调歌头','[]','湖波涨新绿，环绕越王山。',114,'宋词/ci.song.3000.json','["湖波涨新绿，环绕越王山。", "棠斋清昼馀暇，赢得静中观。", "四面屏围碧玉，十里障开云锦，冰鉴倒晴澜。", "目送孤鸿远，心与白鸥闲。", "隘游人，喧鼓吹，杂歌欢。", "晓天澄霁，花羞柳妒怯春寒。", "好在风光满眼，只恐阳春有脚，催诏下天关。", "剩写鹅溪幅，归去凤池看。"]'),
('song-ci-134','水调歌头','林淳','宋','宋词','song-ci','水调歌头','[]','疏水绕城郭，农利遍三山。',114,'宋词/ci.song.3000.json','["疏水绕城郭，农利遍三山。", "使君重本，雅志初不在游观。", "化出玉壶境界，挥洒锦囊词翰，笔下涌波澜。", "天巧无馀蕴，意匠自舒闲。", "拥鳌头，民同乐，颂声欢。", "养花天气，云柔烟腻护朝寒。", "桃李满城阴合，杨柳绕堤绿暗，幽鸟语间关。", "似诉风光好，留与后人看。"]'),
('song-ci-135','水调歌头','林淳','宋','宋词','song-ci','水调歌头','[]','螺水亘千古，鳌顶冠三山。',114,'宋词/ci.song.3000.json','["螺水亘千古，鳌顶冠三山。", "年丰帅阃尘静，栏槛纵遐观。", "四望潮登浦溆，万顷绿浮原野，堤岸溢波澜。", "畎浍皆沾足，日永桔槔闲。", "肆华筵，鱼鸟乐，众宾欢。", "良辰好景，年年莫放此盟寒。", "且念新湖遗爱，莫作故园遐想，到处是乡关。", "勋业知非晚，聊把镜频看。"]'),
('song-ci-136','菩萨蛮','林淳','宋','宋词','song-ci','菩萨蛮','[]','鹅溪净称烟笼月。',52,'宋词/ci.song.3000.json','["鹅溪净称烟笼月。", "澄心白称光浮雪。", "净白两俱宜。", "天然浓淡枝。", "花光神意远。", "吮墨含毫浅。", "依约有香来。", "春风随手开。"]'),
('song-ci-137','减字木兰花','林淳','宋','宋词','song-ci','减字木兰花','[]','嫣然笑粲。',52,'宋词/ci.song.3000.json','["嫣然笑粲。", "醉靥融滋春意烂。", "侍宴终宵。", "欢动帘帏酒易消。", "尊前狂客。", "惊见蕊仙新谪籍。", "珠阁深关。", "丹就同归海上山。"]'),
('song-ci-138','减字木兰花','林淳','宋','宋词','song-ci','减字木兰花','[]','烛花呈灿。',52,'宋词/ci.song.3000.json','["烛花呈灿。", "瑞气满筵春欲烂。", "月色中宵。", "疑是阶前雪未消。", "骚人词客。", "魂断蜡梅香已籍。", "谁更情关。", "一点新愁入远山。"]'),
('song-ci-139','浣溪沙','林淳','宋','宋词','song-ci','浣溪沙','[]','冒雪休寻访戴船。',48,'宋词/ci.song.3000.json','["冒雪休寻访戴船。", "红炉剩爇宝香然。", "阁儿煨暖两三椽。", "更有玉杯传素手，梅花相对两争妍。", "停杯听唱月娟娟。"]'),
('song-ci-140','洞仙歌','廖行之','宋','宋词','song-ci','洞仙歌','[]','虞弦挥按，甫奏熏风曲。',105,'宋词/ci.song.3000.json','["虞弦挥按，甫奏熏风曲。", "两两尧蓂长新绿。", "揖鳌峰、连雁峤，轇轕圆融，总里许、北郭门围全属。", "年年才见夏，喜溢枌榆，龙穴霏烟霭晴谷。", "向氤氲和气里，岁奉瑶觞，试屈指、几阅梅林初熟。", "待一品官高见玄孙，算八十彩衣，更饶遐福。"]'),
('song-ci-141','念奴娇','廖行之','宋','宋词','song-ci','念奴娇','[]','薰风庭院，报槐阴拥翠，池波凝绿。',120,'宋词/ci.song.3000.json','["薰风庭院，报槐阴拥翠，池波凝绿。", "瑞气葱葱浮燕寝，羽仗霓旌相属。", "鸑鷟开祥，长庚入梦，诧列仙图箓。", "林泉高迈，肯应轩冕尘俗。", "好是妙舞清歌，浮瓜沈李，荐杯中醽醁。", "鹊尾炉生香篆细，又作如何祈祝。", "试问蓬莱，丹崖胜处，几摘蟠桃熟。", "东方何在，凛然能继高躅。"]'),
('song-ci-142','贺新郎','廖行之','宋','宋词','song-ci','贺新郎','[]','玉宇□蓬户。',142,'宋词/ci.song.3000.json','["玉宇□蓬户。", "渺凉声、箾槮梧井，乱零枫浦。", "得得西山朝来爽，碧瘦千崖万树。", "清兴在、烟霞深处。", "拄笏风流今谁是，但闻鸡、夜半犹狂舞。", "试举看，渠多许。", "青云万里君夷路。", "肯区区、輈张兔穴，沈迷金坞。", "流水高山真难料，休把朱弦浪抚。", "任展转、翻云覆雨。", "且对佳时随意乐，更从今、莫问惊人句。", "算万事，总天赋。"]'),
('song-ci-143','贺新郎','廖行之','宋','宋词','song-ci','贺新郎','[]','修月三千户。',142,'宋词/ci.song.3000.json','["修月三千户。", "拥冰轮、同游碧落，问津牛浦。", "上界真仙多才思，乞与瑶阶玉树。", "渺万里、人间何处。", "云叶依依分清荫，忆当时、掩映霓裳舞。", "算万木，宁如许。", "年年萧爽幽岩路。", "倚西风、吹香金粟，超然云坞。", "一洗纷纷凡花尽，堪写清商对抚。", "为豁散、蛮烟瘴雨。", "脱俗高标谁能领，向骚人、正欠题新句。", "须大手，与君赋。"]'),
('song-ci-144','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','林梢挂弦月，江路粲寒梅。',114,'宋词/ci.song.3000.json','["林梢挂弦月，江路粲寒梅。", "一年清绝，好是造物巧安排。", "今日不知何日，佳气更随喜气，满室已春回。", "欢事一时足，黄色两眉开。", "紫髯公，平日事，亦高哉。", "都将功业，分付兰玉满庭阶。", "慈爱浑嗤张傅，信义更高吴李，别是一襟怀。", "岁岁长生酒，剩□紫霞杯。"]'),
('song-ci-145','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','天下伟人物，荆楚号名流。',114,'宋词/ci.song.3000.json','["天下伟人物，荆楚号名流。", "幅员千里，英气磅礴岳南州。", "雁峤高参翼轸，石鼓下盘朱府，衮衮应公侯。", "常记生申旦，明日是中秋。", "挈明月，翳翔凤，驷飞虬。", "东南一尉，何事三载漫淹留。", "谈笑洞庭青草，从此阆风阊阖，高处看鳌头。", "更种阶庭玉，慈母念方稠。"]'),
('song-ci-146','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','祥起玉龙甲，庆衍紫枢垣。',114,'宋词/ci.song.3000.json','["祥起玉龙甲，庆衍紫枢垣。", "奎文得岁，佳气磅礴斗牛间。", "天意方扶兴运，贤业更看奕世，衮衮照英躔。", "四海具瞻久，膏泽满湘川。", "岁六月，苏大旱，作丰年。", "喁喁百万生齿，何处不沾恩。", "此是鸿钧事业，那更青毡步武，早晚即调元。", "混一车书了，还领赤松仙。"]'),
('song-ci-147','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','黄色起犀表，紫绶照金章。',114,'宋词/ci.song.3000.json','["黄色起犀表，紫绶照金章。", "两朝耆德，应是南国旧龚黄。", "曾上方壶蓬岛，万里鲸波不作，炎海赖清凉。", "缓造鹓鸿地，高卧水云乡。", "近新来，春色好，遍潇湘。", "不知今日何日，佳气拥高堂。", "竞把芳尊为寿，细祝遐龄难老，福禄未渠央。", "国栋欠元老，仙桂看诸郎。"]'),
('song-ci-148','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','凉吹起空阔，疏雨敛轻阴。',114,'宋词/ci.song.3000.json','["凉吹起空阔，疏雨敛轻阴。", "潇湘江上秋色，佳处不胜清。", "拄笏西山一望，气与千崖高爽，天意属奇英。", "威凤下瑶阙，丹桂矗云根。", "汉元侯，流德厚，在云孙。", "金昆玉季，曾共接武上青云。", "堂上瑶池仙姥，庭下芝兰玉树，好事萃于门。", "剩讲经纶事，早晚自公卿。"]'),
('song-ci-149','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','苍立箨龙秀，青压雨梅肥。',114,'宋词/ci.song.3000.json','["苍立箨龙秀，青压雨梅肥。", "清和天气，无限佳景属斯时。", "试听虞弦初理，便有熏兮入奏，风物正熙熙。", "此日定何日，香篆袅金猊。", "记当年，蓂两荚，应熊罴。", "男儿壮志，端在伊傅与皋夔。", "况是从容书史，养就经纶功业，早晚帝王师。", "但了公家事，方与赤松期。"]'),
('song-ci-150','水调歌头','廖行之','宋','宋词','song-ci','水调歌头','[]','韩国武中令，公望乃云孙。',114,'宋词/ci.song.3000.json','["韩国武中令，公望乃云孙。", "平生壮志，凛凛长剑倚天门。", "郁积胸中谋虑，慷慨尊前谈笑，袖手看风云。", "唾手功名事，诗句自朝昏。", "况高怀，吾所敬，果难能。", "千金生产，一笑推尽与诸昆。", "所至才成辄去，不为区区芥蒂，此意有谁论。", "且举杯中酒，今日是生辰。"]'),
('song-ci-151','沁园春','廖行之','宋','宋词','song-ci','沁园春','[]','直下承当，本来能解，莫遣乾休。',139,'宋词/ci.song.3000.json','["直下承当，本来能解，莫遣乾休。", "算如今蹉过，峥嵘岁月，分阴可惜，一日三秋。", "闹里偷声，日中逃影，用尽机关无少留。", "争知道，是沤生即水，水外无沤。", "世人等是悠悠。", "谁著个工夫向里求。", "但掩耳窃钟，将泥洗块，觅花空里，舐蜜刀头。", "何以忙中，尻舆浸假，邀取三彭同载游。", "真如界，向毗庐顶上，荐取无忧。"]'),
('song-ci-152','千秋岁','廖行之','宋','宋词','song-ci','千秋岁','[]','腊馀时候，天意收寒早。',87,'宋词/ci.song.3000.json','["腊馀时候，天意收寒早。", "梅信动，春先到。", "晓来湘水上，有底风光好。", "春有意，惯随仙仗来蓬岛。", "一念到人间，依约瑶池道。", "心好在，慈为宝。", "蟠桃多岁月，不数如瓜枣。", "千岁也，朱颜绿鬓人难老。"]'),
('song-ci-153','青玉案','廖行之','宋','宋词','song-ci','青玉案','[]','片帆稳送扁舟去。',80,'宋词/ci.song.3000.json','["片帆稳送扁舟去。", "又还踏、江湖路。", "回首京城旧游处。", "断魂南浦，满怀装恨，别后凭谁诉。", "长歌击剑论心素。", "有志功名未应暮。", "自诵百僚端复许。", "归来犹记，东坡诗语，但草凌云赋。"]'),
('song-ci-154','青玉案','廖行之','宋','宋词','song-ci','青玉案','[]','家山此去无多路。',80,'宋词/ci.song.3000.json','["家山此去无多路。", "久没个、音书去。", "一别而今佳节度。", "黄花开未，白衣到否，篱落荒凉处。", "峥嵘岁月远秋暮。", "空腹便便无好句。", "菊意愆期浑未许。", "那堪惹恨，年来此日，长是潇潇雨。"]'),
('song-ci-155','满庭芳','廖行之','宋','宋词','song-ci','满庭芳','[]','五甲科名，半生蹭蹬，胸中可谓忘奇。',118,'宋词/ci.song.3000.json','["五甲科名，半生蹭蹬，胸中可谓忘奇。", "荣华外物，算岂是人为。", "自有吾身事业，最难得、□养亲时。", "萱堂好，紫鸾重诰，寿与岳山齐。", "世间，欢乐事，争名蜗角，伐性蛾眉。", "谩须臾变化，苍狗云衣。", "那似千秋寿母，功名事、分付吾儿。", "从今去，捧觞戏彩，双绶更相宜。"]'),
('song-ci-156','凤栖梧・蝶恋花','廖行之','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','吾母慈祥膺上寿。',70,'宋词/ci.song.3000.json','["吾母慈祥膺上寿。", "福庇吾家，近世真希有。", "丘嫂今年逾六九。", "康宁可嗣吾慈母。", "我愿慈闱多福厚。", "更祝遐龄，与母齐长久。", "鸾诰联翩双命妇。", "华堂千岁长生酒。"]'),
('song-ci-157','凤栖梧・蝶恋花','廖行之','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','破腊先春梅有意。',70,'宋词/ci.song.3000.json','["破腊先春梅有意。", "管领年华，总在清香蕊。", "不逐浮花红与紫。", "岁寒来寿仙翁醉。", "衮衮诸公名又利。", "谁似高标，摆却人间事。", "长对南枝添兴致。", "尊前好在三千岁。"]'),
('song-ci-158','临江仙','廖行之','宋','宋词','song-ci','临江仙','[]','春意茫茫春色里，又还几度花期。',70,'宋词/ci.song.3000.json','["春意茫茫春色里，又还几度花期。", "淡晴时候尽融怡。", "梅腮翻白后，柳眼弄青时。", "正是江城天气好，楼台灯火星移。", "相逢无处不相宜。", "轻狂行乐处，明月夜深归。"]'),
('song-ci-159','西江月','廖行之','宋','宋词','song-ci','西江月','[]','绀滑一篙春水，云横几里江山。',58,'宋词/ci.song.3000.json','["绀滑一篙春水，云横几里江山。", "一番烟雨洗晴岚。", "向晓碧天如鉴。", "客枕谩劳魂梦，心旌长系乡关。", "封姨悭与送归帆。", "愁对绿波肠断。"]'),
('song-ci-160','西江月','廖行之','宋','宋词','song-ci','西江月','[]','试数阶蓂有几，昨朝看到今朝。',58,'宋词/ci.song.3000.json','["试数阶蓂有几，昨朝看到今朝。", "南薰早动舜琴谣。", "端为熊罴梦兆。", "学粹昔人经制，文高古乐箫韶。", "天风从此上扶摇。", "回首不劳耕钓。"]'),
('song-ci-161','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','飞尽林花绿叶丝。',64,'宋词/ci.song.3000.json','["飞尽林花绿叶丝。", "十分春色在荼䕷。", "多情几日风朝雨，留恋东风未许归。", "天意好，与君期。", "如今且醉□蛾眉。", "明年上国春风里，赏遍名花得意时。"]'),
('song-ci-162','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','腊月今朝恰一旬。',64,'宋词/ci.song.3000.json','["腊月今朝恰一旬。", "梅花开遍陇头春。", "篆烟起处人称寿，从昔家和福自生。", "新喜事，得佳姻。", "贤郎顺妇正充庭。", "从今更祝千千岁，要与邦人作典型。"]'),
('song-ci-163','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','细数元正隔两朝。',64,'宋词/ci.song.3000.json','["细数元正隔两朝。", "眼看杨柳又新条。", "岁寒独有江梅耐，曾伴瑶池下绛霄。", "香篆袅，烛花烧。", "团栾喜气沸欢谣。", "慈祥自是长生乐，不用春醪飶与椒。"]'),
('song-ci-164','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','送了春归雨未收。',64,'宋词/ci.song.3000.json','["送了春归雨未收。", "雨肥梅子满枝头。", "心知办此和羹品，正为和羹国手谋。", "蓂两荚，岁千秋。", "崧高神气禀公侯。", "好将一卷周公礼，起佐皇家定九州。"]'),
('song-ci-165','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','曾宴瑶池万玉宫。',64,'宋词/ci.song.3000.json','["曾宴瑶池万玉宫。", "鸾骖此日自从容。", "杓携鹑首坤维外，岁在降娄虎坎中。", "生指李，寿方瞳。", "云仍今有鹊巢风。", "传家自得长年诀，安用人祈鹤与松。"]'),
('song-ci-166','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','兰谷清香入岭梅。',64,'宋词/ci.song.3000.json','["兰谷清香入岭梅。", "多根应尔暖先回。", "腊前似得真消息，争逐尧蓂十叶开。", "春满室，酒盈杯。", "百花宁许到尊罍。", "仙姿要是仙家伴，长为遐龄岁一来。"]'),
('song-ci-167','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','[]','畴昔君王庆诞辰。',64,'宋词/ci.song.3000.json','["畴昔君王庆诞辰。", "欢传金母下瑶城。", "祗应仙子陪仙仗，却向人间作寿星。", "萧史伴，更和鸣。", "殷勤好嗣太夫人。", "直须同饮长生酒，剩看芝兰照谢庭。"]'),
('song-ci-168','卜算子','廖行之','宋','宋词','song-ci','卜算子','[]','云破露新晴，月上输清气。',52,'宋词/ci.song.3000.json','["云破露新晴，月上输清气。", "最是江城有底佳，灯火人烟沸。", "行乐尽欢娱，眼界尤妍媚。", "多少江滨解佩人，邂逅无穷意。"]'),
('song-ci-169','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','屈指家山，匆匆又数今朝过。',50,'宋词/ci.song.3000.json','["屈指家山，匆匆又数今朝过。", "客情那可。", "愁似天来大。", "烟雨濛濛，细浥轻尘堕。", "君知麽。", "却成甚个。", "春暮犹江左。"]'),
('song-ci-170','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','秋兴连天，又还不分秋光老。',50,'宋词/ci.song.3000.json','["秋兴连天，又还不分秋光老。", "莼鲈犹好。", "莫落秋归后。", "有底从人，上马皆东首。", "君知否。", "阳关三奏。", "消黯情多少。"]'),
('song-ci-171','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','音信西来，匆匆思作东归计。',50,'宋词/ci.song.3000.json','["音信西来，匆匆思作东归计。", "别怀萦系。", "为个人留滞。", "尊酒团栾，莫惜通宵醉。", "还来未。", "满期君至。", "只在初三四。"]'),
('song-ci-172','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','年少清新，襟裾那受红尘污。',50,'宋词/ci.song.3000.json','["年少清新，襟裾那受红尘污。", "还他礼数。", "莫遣衣冠粗。", "拟倩东风，西逐轮蹄去。", "泠然御。", "飘飘仙趣。", "直到骖鸾处。"]'),
('song-ci-173','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','此去何之，骈阗车马朝来起。',50,'宋词/ci.song.3000.json','["此去何之，骈阗车马朝来起。", "扬鞭西指。", "意气眉间是。", "闾里儿童，竞瞩秦萧史。", "归时几。", "快瞻行李。", "还看如云喜。"]'),
('song-ci-174','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','玳席华筵，嘉宾环集三千履。',50,'宋词/ci.song.3000.json','["玳席华筵，嘉宾环集三千履。", "兰膏芬芷。", "一簇红莲里。", "花覆玉郎，苒苒青衫媺。", "咸倾企。", "小登科第。", "有底新桃李。"]'),
('song-ci-175','点绛唇','廖行之','宋','宋词','song-ci','点绛唇','[]','玉树芝兰，冰清况有闺房秀。',50,'宋词/ci.song.3000.json','["玉树芝兰，冰清况有闺房秀。", "画堂如昼。", "相对倾醇酎。", "合卺同牢，二姓欢佳耦。", "凭谁手。", "鬓丝同纽。", "共祝齐眉寿。"]'),
('song-ci-176','丑奴儿・采桑子','廖行之','宋','宋词','song-ci','丑奴儿・采桑子','[]','一春底事多佳气，非雾非云。',52,'宋词/ci.song.3000.json','["一春底事多佳气，非雾非云。", "郁郁氲氲。", "端为君家诞阿兴。", "庆源衮衮由高密，福有多根。", "百子千孙。", "此是元侯嫡耳孙。"]'),
('song-ci-177','如梦令','廖行之','宋','宋词','song-ci','如梦令','[]','雨歇凉生枕簟。',40,'宋词/ci.song.3000.json','["雨歇凉生枕簟。", "不梦大槐宫殿。", "惟对谪仙人，一笑高情眷眷。", "离恨。", "离恨。", "无奈晓窗鸡啭。"]'),
('song-ci-178','如梦令','廖行之','宋','宋词','song-ci','如梦令','[]','应是南枝向暖。',40,'宋词/ci.song.3000.json','["应是南枝向暖。", "那更青春未晚。", "竹外见红腮，芳意与香撩乱。", "肠断。", "肠断。", "无奈东风独占。"]'),
('song-ci-179','鹧鸪天','廖行之','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','九日东篱已泛觞。',64,'宋词/ci.song.3000.json','["九日东篱已泛觞。", "陇头犹待返魂香。", "那知此日花神约，得得同登君子堂。", "迎腊雪，傲晴霜。", "西湖风韵接柴桑。", "寿潭更酌长生水，岁岁和羹入帝乡。"]'),
('song-ci-180','减字木兰花','廖行之','宋','宋词','song-ci','减字木兰花','[]','相从归去。',52,'宋词/ci.song.3000.json','["相从归去。", "行尽江吴到湘楚。", "欲话离怀。", "万事须凭酒一杯。", "临歧握手。", "赠子一言君听否。", "舌在何忧。", "莫作人间儿女愁。"]'),
('song-ci-181','醉落魄・一斛珠','京镗','宋','宋词','song-ci','醉落魄・一斛珠','[]','芳尘休扑。',67,'宋词/ci.song.3000.json','["芳尘休扑。", "名花唤我相追逐。", "浅妆不比梅敧竹。", "深注朱颜，娇面称红烛。", "阿娇合贮黄金屋。", "是谁却遣来空谷。", "酡颜遍倚阑干曲。", "一段风流，不枉到西蜀。"]'),
('song-ci-182','好事近','京镗','宋','宋词','song-ci','好事近','[]','急雨逐骄阳，洗出长空新月。',53,'宋词/ci.song.3000.json','["急雨逐骄阳，洗出长空新月。", "更对银河风露，觉今宵都别。", "不须乞巧拜中庭，枉共天孙说。", "且信平生拙极，耐岁寒霜雪。"]'),
('song-ci-183','好事近','京镗','宋','宋词','song-ci','好事近','[]','杰阁耸层霄，几度晓风残月。',53,'宋词/ci.song.3000.json','["杰阁耸层霄，几度晓风残月。", "同是鹓行旧侣，慰十年离别。", "一杯相属莫留残，试倚阑干说。", "趁取簪花绿鬓，未骎骎如雪。"]'),
('song-ci-184','定风波','京镗','宋','宋词','song-ci','定风波','[]','何必穿针上彩楼。',73,'宋词/ci.song.3000.json','["何必穿针上彩楼。", "剖瓜插竹诉穷愁。", "闻道天孙相会处，银汉无津，不待泛兰舟。", "动是隔年寻素约，何似，每逢清梦且嬉游。", "但得举杯开笑口，对月临风，总胜鹊桥秋。"]'),
('song-ci-185','定风波','京镗','宋','宋词','song-ci','定风波','[]','休卧元龙百尺楼。',73,'宋词/ci.song.3000.json','["休卧元龙百尺楼。", "眼高照破古今愁。", "若不擎天为八柱，且学鸱夷，归泛五湖舟。", "万里西南天一角，骑气乘风，也作等闲游。", "莫道玉关人老矣，壮志凌云，依旧不惊秋。"]'),
('song-ci-186','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','杨卢万人杰，见我眼俱青。',114,'宋词/ci.song.3000.json','["杨卢万人杰，见我眼俱青。", "锦官城里胜概，在在款经行。", "笔底烟云飞走，胸次乾坤吐纳，议论总纵横。", "觉我形秽处，相并玉壶清。", "二使者，弦样直，水般平。", "岷峨洗净凄怆，威与惠相并。", "闻道东来有诏，却恐西留无计，顿使雪山轻。", "滚滚蜀江水，不尽是声名。"]'),
('song-ci-187','满江红','京镗','宋','宋词','song-ci','满江红','[]','乘兴西来，问谁是、平生相识。',115,'宋词/ci.song.3000.json','["乘兴西来，问谁是、平生相识。", "算惟有、瑶台明月，照人如昔。", "万里清凉银世界，放教千丈冰轮出。", "便招邀、我辈上层楼，横孤笛。", "阴晴事，人难必。", "欢乐处，天常惜。", "幸星稀河澹，云收风息。", "更著两贤陪胜赏，此身如与尘寰隔。", "笑谪仙、对影足成三，空孤寂。"]'),
('song-ci-188','满江红','京镗','宋','宋词','song-ci','满江红','[]','喜见中秋，急载酒、登楼邀月。',115,'宋词/ci.song.3000.json','["喜见中秋，急载酒、登楼邀月。", "谁料得、狂风作祟，浮云为孽。", "孤负阑干凝望眼，不教宝鉴悬银阙。", "但筵前、依旧舞腰斜，歌喉咽。", "阴与霁，圆并缺，难指准，休分别。", "况赏心乐事，从来磨折。", "常把一尊陪笑语，也胜虚度佳时节。", "怪坡仙、底事太愁生，惊华发。"]'),
('song-ci-189','满江红','京镗','宋','宋词','song-ci','满江红','[]','才近重阳，喜风露、酝成爽气。',115,'宋词/ci.song.3000.json','["才近重阳，喜风露、酝成爽气。", "应料有、悲秋情绪，澹妆慵试。", "黄菊篱边开遍否，紫鸿塞外归来未。", "但倚阑、高处望长空，无穷意。", "名利鼎，从渠沸。", "穷达路，非人致。", "又何须咄咄，向空书字。", "西风正好狂吹帽，庾尘那解关吾事。", "纵嬉游、也不学山翁，如泥醉。"]'),
('song-ci-190','木兰花慢','京镗','宋','宋词','song-ci','木兰花慢','[]','算秋来景物，皆胜赏、况重阳。',122,'宋词/ci.song.3000.json','["算秋来景物，皆胜赏、况重阳。", "正露冷欲霜，烟轻不雨，玉宇开张。", "蜀人从来好事，遇良辰、不肯负时光。", "药市家家帘幕，酒楼处处丝簧。", "婆娑老子兴难忘。", "聊复与平章。", "也随分登高，茱萸缀席，菊蕊浮觞。", "明年未知谁健，笑杜陵、底事独凄凉。", "不道频开笑口，年年落帽何妨。"]'),
('song-ci-191','绛都春','京镗','宋','宋词','song-ci','绛都春','[]','升平似旧。',122,'宋词/ci.song.3000.json','["升平似旧。", "正锦里元夕，轻寒时候。", "十里轮蹄，万户帘帷香风透。", "火城灯市争辉照。", "谁撒□、满空星斗。", "玉箫声里，金莲影下，月明如画。", "知否。", "良辰美景，□丰岁乐国，从来希有。", "坐上两贤，白玉为山联翩秀。", "笙歌一片围红袖。", "切莫遣、铜壶催漏。", "杯行且与邦人，共开笑口。"]'),
('song-ci-192','满江红','京镗','宋','宋词','song-ci','满江红','[]','锦里先生，草堂筑、浣花溪上。',115,'宋词/ci.song.3000.json','["锦里先生，草堂筑、浣花溪上。", "料饱看、阶前雀食，篱边渔网。", "跨鹄骑鲸归去后，桥西潭北留佳赏。", "况依然、一曲抱村流，江痕涨。", "鱼龙戏，相浩荡。", "禽鸟乐，增舒畅。", "更绮罗十里，棹歌来往。", "上坐英贤今李郭，邦人应作仙舟想。", "但□呼、落日未西时，船休放。"]'),
('song-ci-193','念奴娇','京镗','宋','宋词','song-ci','念奴娇','[]','扪参历井，恰匆匆三见，西州七夕。',120,'宋词/ci.song.3000.json','["扪参历井，恰匆匆三见，西州七夕。", "怪得骄阳回避晚，犹去新秋两日。", "天上良宵，人间佳节，初不分今昔。", "夜来急雨，洗成风露清绝。", "因念万里飘零，君平何在，谁识乘槎客。", "插竹剖瓜休妄想，巧处那容人乞。", "院宇初凉，楼台不夜，漫说经年隔。", "引杯长啸，醉看天地空阔。"]'),
('song-ci-194','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','明月四时好，何事喜中秋。',114,'宋词/ci.song.3000.json','["明月四时好，何事喜中秋。", "瑶台宝鉴，宜挂玉宇最高头。", "放出白毫千丈，散作太虚一色，万象入吾眸。", "星斗避光彩，风露助清幽。", "等闲来，天一角，岁三周。", "东奔西走，在处依旧若从游。", "照我尊前只影，催我镜中华发，蟾兔漫悠悠。", "连璧有佳客，乘兴且登楼。"]'),
('song-ci-195','洞仙歌','京镗','宋','宋词','song-ci','洞仙歌','[]','三年锦里，见重阳药市。',101,'宋词/ci.song.3000.json','["三年锦里，见重阳药市。", "车马喧阗管弦沸。", "笑篱边孤寂，台上疏狂，争得似，此日西南都会。", "痴儿官事了，乐与民同，况值高秋好天气。", "□不羞华发，不照衰颜，聊满插、黄花一醉。", "道物外、高人有时来，问混杂龙蛇，个中谁是。"]'),
('song-ci-196','水龙吟','京镗','宋','宋词','song-ci','水龙吟','[]','夜来井络参躔，使星一点明如昼。',125,'宋词/ci.song.3000.json','["夜来井络参躔，使星一点明如昼。", "谁将天上麒麟，锺作人间英秀。", "从橐仪刑，御屏名姓，暂烦衣绣。", "问西川父老，新来喜跃，缘何事、曾知否。", "今代澄清妙手。", "为公家、忧心如疚。", "几年繁赋，一朝输代，恩民特厚。", "初度佳辰，恰逢长至，从来希有。", "但只将一部，欢声百万，与公为寿。"]'),
('song-ci-197','汉宫春','京镗','宋','宋词','song-ci','汉宫春','[]','看透尘寰。',118,'宋词/ci.song.3000.json','["看透尘寰。", "更禅心似水，道力如山。", "前身青冥跨鹄，紫府乘鸾。", "世缘一念，便等闲、游戏人间。", "须信道，云霄步武，不应权牧西南。", "此日重临初度，正绣衣辉映，彩服斓斑。", "人生显途易到，容养难攀。", "一时庆事，问谁家、得似门阑。", "知未艾，百千寿算，慈闱长奉亲欢。"]'),
('song-ci-198','汉宫春','京镗','宋','宋词','song-ci','汉宫春','[]','暖律初回。',118,'宋词/ci.song.3000.json','["暖律初回。", "又烧灯市井，卖酒楼台。", "谁将星移万点，月满千街。", "轻车细马，隘通衢、蹴起香埃。", "今岁好，土牛作伴，挽留春色同来。", "不是天公省事，要一时壮观，特地安排。", "何妨彩楼鼓吹，绮席尊罍。", "良宵胜景，语邦人、莫惜徘徊。", "休笑我，痴顽不去，年年烂醉金钗。"]'),
('song-ci-199','洞仙歌','京镗','宋','宋词','song-ci','洞仙歌','[]','东皇著意，妙出妆春手。',102,'宋词/ci.song.3000.json','["东皇著意，妙出妆春手。", "点缀名花胜於绣。", "向鱼凫国里，琴鹤堂前，仍共赏，蜀锦堆红炫昼。", "娇娆真绝艳，尽是天然，莫恨无香欠檀口。", "幸今年风雨，不苦摧残，还肯为、游人再三留否。", "算魏紫姚黄号花王，若定价收名，未应居右。"]'),
('song-ci-200','念奴娇','京镗','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','锦城城北，有平湖、仿佛西湖西畔。',120,'宋词/ci.song.3000.json','["锦城城北，有平湖、仿佛西湖西畔。", "载酒郊坰修禊事，雅称兰舟同泛。", "麦垅黄轻，桤林绿重，莫厌春光晚。", "棹歌声发，飞来鸥鹭惊散。", "好是水涨弥漫，山围周币，不尽青青岸。", "除却钱塘门外见，只说此间奇观。", "句引游人，追陪佳客，三载成留恋。", "古今陈迹，从教分付弦管。"]'),
('song-ci-201','满江红','京镗','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','雨后晴初，觉春在、桤村柳陌。',115,'宋词/ci.song.3000.json','["雨后晴初，觉春在、桤村柳陌。", "修禊事、郊坰寻胜，特邀君出。", "缭绕群山疑虎踞，弥漫一水容鲸吸。", "怪西湖、底事却移来，龟城北。", "酬令节，逢佳日。", "风递暖，烟凝碧。", "趁兰舟游玩，尽杯中物。", "十里轮蹄尘不断，几多粉黛花无色。", "笑杜陵、昔赋丽人行，空遗迹。"]'),
('song-ci-202','念奴娇','京镗','宋','宋词','song-ci','念奴娇','[]','郎闱夙望，问何因袖手，双流溪畔。',120,'宋词/ci.song.3000.json','["郎闱夙望，问何因袖手，双流溪畔。", "忆昔班行曾接武，今喜一尊同泛。", "骥枥难淹，鹏程方远，大器成须晚。", "等闲访我，又惊云雨分散。", "最是游子悲乡，小人怀土，梦绕江南岸。", "楚尾吴头家住处，满自山川遐观。", "归兴虽浓，俞音尚閟，此地非贪恋。", "东西惟命，去留迟速休管。"]'),
('song-ci-203','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','百堞龟城北，江势远连空。',114,'宋词/ci.song.3000.json','["百堞龟城北，江势远连空。", "杠梁济涉，浑似溪涧饮长虹。", "覆以翬飞华宇，载以鱼浮叠石，守护有神龙。", "好看发源水，滚滚尽流东。", "司马氏，凌云气，盖群公。", "当年题柱，从此奏赋动天容。", "果驾轺车使蜀，能致诸蛮臣汉，邛筰道仍通。", "寄语登桥者，努力继前功。"]'),
('song-ci-204','念奴娇','京镗','宋','宋词','song-ci','念奴娇','[]','绣天锦地，浣花溪风物，尤为奇绝。',120,'宋词/ci.song.3000.json','["绣天锦地，浣花溪风物，尤为奇绝。", "无限兰舟相荡漾，缯彩重重装结。", "冀国遗踪，杜陵陈迹，疑信俱休说。", "笙歌丛里，旌旗光映林樾。", "自笑与蜀缘多，沧浪亭下，饱看烟波阔。", "屡疏求归才请得，知我家山心切。", "已是行人，犹陪佳客，莫放回船发。", "来年今日，相思惟共明月。"]'),
('song-ci-205','洞庭春色・沁园春','京镗','宋','宋词','song-ci','洞庭春色・沁园春','[]','命驾访嵇，泛舟思戴，此兴甚浓。',137,'宋词/ci.song.3000.json','["命驾访嵇，泛舟思戴，此兴甚浓。", "料情侔杨恽，乌乌拊缶，意轻殷浩，咄咄书空。", "莫讶群芳淹速异，到时序推排元自同。", "休怅望，任春来桃李，秋后芙蓉。", "因嗟锦城四载，漫赢得、齿豁头童。", "叹里门密迩，易成间阔，诗筒频寄，难续新工。", "我已怀归今得请，念此地迟回谁似公。", "经济手，看鸾台凤阁，晚节收功。"]'),
('song-ci-206','满江红','京镗','宋','宋词','song-ci','满江红','[]','雨洗新秋，遣凉意、驱除残暑。',115,'宋词/ci.song.3000.json','["雨洗新秋，遣凉意、驱除残暑。", "还又是、天孙河鼓，一番相遇。", "银汉桥成乌鹊喜，金奁丝巧蜘蛛吐。", "见几多、结彩拜楼前，穿针女。", "舟楫具，将归去。", "尊俎胜，休匆遽。", "被西川七夕，四回留住。", "此地关心能几辈，他年会面知何处。", "更倚阑、豪饮莫辞频，歌金缕。"]'),
('song-ci-207','贺新郎','京镗','宋','宋词','song-ci','贺新郎','[]','试与姮娥语。',142,'宋词/ci.song.3000.json','["试与姮娥语。", "问因何、年年此夜，月明如许。", "万顷熔成银世界，是处玉壶风露。", "又岂比、寻常三五。", "变化乾坤同一色，觉星躔、斗柄皆回互。", "须要我，共分付。", "平生脚踏红尘处。", "漫纷纷、鸡虫厚薄，燕鸿来去。", "只有婵娟多情在，依旧当时雅素。", "空自叹、归心难住。", "留取清光岷江畔，照扁舟、送我章江路。", "频引满，莫匆遽。"]'),
('song-ci-208','雨中花・夜行船','京镗','宋','宋词','song-ci','雨中花・夜行船','[]','玉局祠前，铜壶阁畔，锦城药市争奇。',117,'宋词/ci.song.3000.json','["玉局祠前，铜壶阁畔，锦城药市争奇。", "正紫萸缀席，黄菊浮卮。", "巷陌联镳并辔，楼台吹竹弹丝。", "登高望远，一年好景，九日佳期。", "自怜行客，犹对佳宾，留连岂是贪痴。", "谁会得、心驰北阙，兴寄东篱。", "惜别未催鹢首，追欢且醉蛾眉。", "明年此会，他乡今日，总是相思。"]'),
('song-ci-209','雨中花・夜行船','京镗','宋','宋词','song-ci','雨中花・夜行船','[]','跨鹤仙姿，掣鲸老手，从来眼赤腰黄。',117,'宋词/ci.song.3000.json','["跨鹤仙姿，掣鲸老手，从来眼赤腰黄。", "更词源峡水，才刃干将。", "处处欢谣载路，时时秀句盈囊。", "牛头山畔，烦公敛惠，许我分光。", "逢迎锦里，话旧从容，谁知各整行装。", "况正好、登高怀古，择胜寻芳。", "少缓红莲开幕，何妨黄菊浮觞。", "等闲分首，征尘去后，目断斜阳。"]'),
('song-ci-210','瑞鹤仙','京镗','宋','宋词','song-ci','瑞鹤仙','[]','鸳行旧俦侣。',126,'宋词/ci.song.3000.json','["鸳行旧俦侣。", "问底事、迟回西州西处。", "闲居久如许。", "相邻翁对饮，诗人联句。", "夤缘会遇。", "过高轩、相逢喜舞。", "正菊天、景物澄鲜，切莫趣归言去。", "看取。", "星扉月户。", "雾阁云窗，非公孰住。", "从容笑语。", "人生易别难聚。", "恨分违有日，留连无计，满目离愁忍觑。", "若他时、鱼雁南来，把书寄与。"]'),
('song-ci-211','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','身去日华远，举首望长安。',114,'宋词/ci.song.3000.json','["身去日华远，举首望长安。", "四年留蜀，那复有梦到金銮。", "遥想将芜三径，自笑己穷五技，无语倚阑干。", "欲作天涯别，犹对俎尊闲。", "秋意晚，风色厉，叶声乾。", "阳关三叠缓唱，一醉且酡颜。", "聚散燕鸿南北，得失触蛮左右，莫较去仍还。", "后日相思处，烟水与云山。"]'),
('song-ci-212','水龙吟','京镗','宋','宋词','song-ci','水龙吟','[]','四年留蜀惭无补，好是求归得去。',125,'宋词/ci.song.3000.json','["四年留蜀惭无补，好是求归得去。", "风帆百尺，烟波万里，宁辞掀舞。", "楚尾吴头，我家何在，西山南浦。", "想珠帘画栋，倚阑凝望，依然卷云飞雨。", "最好九霞光处。", "见当时、结知明主。", "冰霜节操，斗星词采，羽仪朝路。", "邂逅开怀，等闲分手，满斟绿醑。", "道日边好语，相将飞下，有人知否。"]'),
('song-ci-213','满江红','京镗','宋','宋词','song-ci','满江红','[]','外省抡才，诏书下、芝泥犹湿。',115,'宋词/ci.song.3000.json','["外省抡才，诏书下、芝泥犹湿。", "应料得、出奇锦绣，争辉金碧。", "三级浪高鱼已化，九霄路远鹏方息。", "有宗工、此地独持衡，将专席。", "岁月晚，霜风急。", "嗟老子，为行客。", "念昔陪班缀，今亲辞色。", "握手方成同社款，消魂又作歧亭别。", "也不须、因赋大刀头，归心折。"]'),
('song-ci-214','念奴娇','京镗','宋','宋词','song-ci','念奴娇','[]','文章太守，问何事、犹带天庭黄色。',120,'宋词/ci.song.3000.json','["文章太守，问何事、犹带天庭黄色。", "上界一时官府足，聊下神仙宫阙。", "剖竹新游，握兰旧梦，此意谁人识。", "千军笔阵，争先曾夺矛槊。", "好是万里相逢，一尊同醉，倾吐平边策。", "聚散人生浑惯见，莫为分襟呜咽。", "借箸机筹，著鞭功业，只合从君说。", "明朝回首，天涯何处风月。"]'),
('song-ci-215','水调歌头','京镗','宋','宋词','song-ci','水调歌头','["\u957f\u6c5f"]','衮衮长江水，策策晓霜风。',114,'宋词/ci.song.3000.json','["衮衮长江水，策策晓霜风。", "求归得请，特地送我布帆东。", "出处何关轻重，去住不拘淹速，社燕与秋鸿。", "父老休相恋，四载愧无功。", "谁知有，楼百尺，卧元龙。", "来从天上，一麾游戏斗牛中。", "闻道君王前席，见说从臣虚位，变化待鲲鸿。", "一笑同锦里，万事付金锺。"]'),
('song-ci-216','水龙吟','京镗','宋','宋词','song-ci','水龙吟','[]','推移随牒红尘里，试问几时肩息。',126,'宋词/ci.song.3000.json','["推移随牒红尘里，试问几时肩息。", "家乡何在，烟迷波渺，云横山屹。", "分阃无功，临民有愧，裤今襦昔。", "想征帆万里，阳关三叠，肠空断、人谁忆。", "多谢殷勤绮席。", "苦留连、不容浮鹢。", "九霞光外，五云深畔，君宜鹄立。", "自笑衰迟，未能轩轾，漫劳嘘吸。", "愿锋车趣召，吴天楚地，相逢他日。"]'),
('song-ci-217','酹江月・念奴娇','京镗','宋','宋词','song-ci','酹江月・念奴娇','[]','蟆颐江畔，问收拾多少，山光水色。',120,'宋词/ci.song.3000.json','["蟆颐江畔，问收拾多少，山光水色。", "此是朝宗东去路，准拟鸣鼍浮鹢。", "儒馆英游，侯藩贤望，便合还丹极。", "九重渴想，甘泉闻道虚席。", "因念北阙同朝，西州联事，久矣心相得。", "邂逅天涯拼一笑，洗我尘胸俗臆。", "报国无功，归田有兴，寤寐松坡侧。", "他时音问，且凭来信鳞翼。"]'),
('song-ci-218','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','与蜀有缘法，见我眼俱青。',114,'宋词/ci.song.3000.json','["与蜀有缘法，见我眼俱青。", "征车到处，弦管无限作离声。", "自笑四年留滞，漫说三边安静，分阃愧长城。", "一念天地阔，万事羽毛轻。", "欲归去，诗入社，酒寻盟。", "骎骎双鬓，老矣祗觉壮心惊。", "虽是东西惟命，已断行藏在己，何必问君平。", "举似铜梁守，怀抱好同倾。"]'),
('song-ci-219','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','雪岭倚空白，霜柏傲寒青。',114,'宋词/ci.song.3000.json','["雪岭倚空白，霜柏傲寒青。", "千岩万壑奇秀，禽鸟寂无声。", "好是群贤四集，同访宝仙九室，中有玉京城。", "眼底尘嚣远，胸次利名轻。", "云山旁，烟水畔，肯渝盟。", "传呼休要喝道，方外恐猜惊。", "雅羡林泉胜概，倘遂田园归计，志愿足平生。", "此意只自解，聊复为君倾。"]'),
('song-ci-220','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','数月已办去，今日始成行。',114,'宋词/ci.song.3000.json','["数月已办去，今日始成行。", "天公怜我，特地趁晓作霜晴。", "万里奔驰为米，四载淹留为豆，自笑太劳生。", "父老漫遮道，抚字愧阳城。", "君有命，难俟驾，合兼程。", "故山心切，猿鹤应是怨仍惊。", "多谢使华追路，不忍客亭分袂，已醉酒犹倾。", "莫久西南往，汉代急公卿。"]'),
('song-ci-221','满江红','京镗','宋','宋词','song-ci','满江红','[]','道骨仙风，合笞凤、鞭鸾归去。',115,'宋词/ci.song.3000.json','["道骨仙风，合笞凤、鞭鸾归去。", "底事为、三峨九顶，等闲留住。", "揽辔聊施经济手，凝旒屡出褒嘉语。", "算只今、人物更谁归，心如许。", "嗟我拙，才不武。", "惭我陋，文非古。", "纵策迟鞭钝，也难追步。", "虽喜故人逢异县，却嫌游子贪行路。", "但著公、西掖北门中，相期处。"]'),
('song-ci-222','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','四载分蜀阃，万里下吴樯。',114,'宋词/ci.song.3000.json','["四载分蜀阃，万里下吴樯。", "老怀易感，厌听催别笛横羌。", "自愧谋非经远，更笑才非任剧，安得召公棠。", "有志但碌碌，无绩可章章。", "汉嘉守，明似月，洁如霜。", "邦人鼓舞，爱戴惟恐趣归忙。", "况是水曹宗派，仍得苏州句法，燕寝昼凝香。", "且趁东风去，步武近明光。"]'),
('song-ci-223','水调歌头','京镗','宋','宋词','song-ci','水调歌头','[]','挺挺祖风烈，再岁滞偏州。',114,'宋词/ci.song.3000.json','["挺挺祖风烈，再岁滞偏州。", "元龙豪气，宜卧百尺最高楼。", "万丈文章光焰，一段襟怀洒落，风露玉壶秋。", "乱石惊涛处，也作等闲游。", "适相逢，君去骑，我归舟。", "清都绛阙密迩，切莫小迟留。", "趁取亲庭强健，好向圣朝倾吐，事业肯悠悠。", "回首藩宣地，恩与大江流。"]'),
('song-ci-224','蝶恋花','张震','宋','宋词','song-ci','蝶恋花','[]','梅子初青春已暮。',70,'宋词/ci.song.3000.json','["梅子初青春已暮。", "芳草连云，绿遍西池路。", "小院绣垂帘半举。", "衔泥紫燕双飞去。", "人在赤阑桥畔住。", "不解伤春，还解相思否。", "清梦欲寻犹间阻。", "沙窗一夜萧萧雨。"]'),
('song-ci-225','鹧鸪天','张震','宋','宋词','song-ci','鹧鸪天','[]','宽尽香罗金缕衣。',64,'宋词/ci.song.3000.json','["宽尽香罗金缕衣。", "心情不似旧家时。", "万丝柳暗才飞絮，一点梅酸已着枝。", "金底背，玉东西。", "前欢赢得两相思。", "伤心不及风前燕，犹解穿帘度幕飞。"]'),
('song-ci-226','鹧鸪天','张震','宋','宋词','song-ci','鹧鸪天','[]','横素桥边景最佳。',64,'宋词/ci.song.3000.json','["横素桥边景最佳。", "绿波清浅见琼沙。", "衔泥燕子迎风絮，得食鱼儿趁浪花。", "春已暮，日初斜。", "画船箫鼓是谁家。", "兰桡欲去空留恋，醉倚阑干看晚霞。"]'),
('song-ci-227','蓦山溪','张震','宋','宋词','song-ci','蓦山溪','[]','青梅如豆，断送春归去。',102,'宋词/ci.song.3000.json','["青梅如豆，断送春归去。", "小绿间长红，看几处、云歌柳舞。", "偎花识面，对月共论心，携素手，采香游，踏遍西池路。", "水边朱户。", "曾记销魂处。", "小立背秋千，空怅望、娉婷韵度。", "杨花扑面，香糁一帘风，情脉脉，酒厌厌，回首斜阳暮。"]'),
('song-ci-228','蓦山溪','张震','宋','宋词','song-ci','蓦山溪','[]','春光如许。',102,'宋词/ci.song.3000.json','["春光如许。", "春到江南路。", "柳眼弄晴晖，笑梅老、落英无数。", "峭寒庭院，罗幕护窗纱，金鸭暖，锦屏深，曾记看承处。", "云边尺素。", "何计传心缕。", "无处说相思，空惆怅、朝云暮雨。", "曲阑干外，小立近黄昏，心下事，眼边愁，借问春知否。"]'),
('song-ci-229','水调歌头','张','宋','宋词','song-ci','水调歌头','[]','雨后烟景绿，春水涨桃花。',114,'宋词/ci.song.3000.json','["雨后烟景绿，春水涨桃花。", "系舟溪上，笋舆十里达平沙。", "路转峰回胜处，无数青荧玉树，飘缈羽人家。", "楼观倚空碧，水竹湛清华。", "纵幽寻，携蜡屐，上苍霞。", "古仙何在，空馀药灶委岩洼。", "他日倘然归老，乞取一庵云卧，随分了生涯。", "底用更辛苦，九转炼黄芽。"]'),
('song-ci-230','蝶恋花','王炎2','宋','宋词','song-ci','蝶恋花','[]','纤手行杯红玉润。',70,'宋词/ci.song.3000.json','["纤手行杯红玉润。", "满眼花枝，雨过胭脂嫩。", "新月一眉生浅晕。", "酒阑无奈添春困。", "唤起醉魂君不问。", "憔悴颜容，羞与花相近。", "人自无情花有韵。", "风光易老何须恨。"]'),
('song-ci-231','蝶恋花','王炎2','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','柳暗西湖春欲暮。',70,'宋词/ci.song.3000.json','["柳暗西湖春欲暮。", "无数青丝，不系行人住。", "一点心情千万绪。", "落花寂寂风吹雨。", "唤起声中人独睡。", "千里明驼，不踏山间路。", "谩道遣愁除是醉。", "醉还易醒愁难去。"]'),
('song-ci-232','点绛唇','王炎2','宋','宋词','song-ci','点绛唇','[]','雨湿东风，谁家燕子穿庭户。',50,'宋词/ci.song.3000.json','["雨湿东风，谁家燕子穿庭户。", "孤村薄暮。", "花落春归去。", "浪走天涯，归思萦心绪。", "家何处。", "乱山无数。", "不记来时路。"]'),
('song-ci-233','水调歌头','王炎2','宋','宋词','song-ci','水调歌头','[]','江月冷如水，江水碧於空。',114,'宋词/ci.song.3000.json','["江月冷如水，江水碧於空。", "晚来一霎过雨，为我洗秋容。", "悄悄四山人静，凛凛三更露下，天阔叫孤鸿。", "唤醒蓬窗梦，身在水晶宫。", "揖湘妃，招月娣，御清风。", "素琴韵远，不觉醉眼杏花红。", "禹穴骑鲸仙去，东海钓鳌人远，此意与谁同。", "倚柁一长啸，出壑舞鱼龙。"]'),
('song-ci-234','水调歌头','王炎2','宋','宋词','song-ci','水调歌头','[]','千里倦游客，老眼厌尘烟。',114,'宋词/ci.song.3000.json','["千里倦游客，老眼厌尘烟。", "蒸湘平远，他处无此好江山。", "把酒一听欸乃，过了黄花时节，水国倍生寒。", "输与沧浪叟，长伴白鸥闲。", "傍江亭，穷杳霭，踞巉岩。", "水深石冷，闻道别有洞中天。", "待倩灵妃调曲，唤起冯夷短舞，从此问群仙。", "云海渺无际，波涌缓移船。"]'),
('song-ci-235','念奴娇','王炎2','宋','宋词','song-ci','念奴娇','[]','小妆朱槛，护秋英千点，金钿如簇。',120,'宋词/ci.song.3000.json','["小妆朱槛，护秋英千点，金钿如簇。", "黄叶白苹朝露冷，只有孤芳幽馥。", "华发苍头，宦情羁思，来伴花幽独。", "巡檐无语，清愁何啻千斛。", "因念爱酒渊明，东篱雅意，千载无人续。", "身在花边须一醉，小覆杯中醽醁。", "过了重阳，捻枝嗅蕊，休叹年华速。", "明年春到，陈根更有新绿。"]'),
('song-ci-236','鹧鸪天','王炎2','宋','宋词','song-ci','鹧鸪天','[]','淡淡疏疏不惹尘。',64,'宋词/ci.song.3000.json','["淡淡疏疏不惹尘。", "暗香一点静中闻。", "人间怪有晴时雪，天上偷回腊里春。", "疑浅笑，又轻颦。", "虽然无语意相亲。", "老来尚可花边饮，惆怅相携失玉人。"]'),
('song-ci-237','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','一柱中擎远碧，两峰旁依高寒。',58,'宋词/ci.song.3000.json','["一柱中擎远碧，两峰旁依高寒。", "横陈削就短长山。", "莫把一分增减。", "我望云烟目断，人言风景天悭。", "被公诗笔尽追还。", "更上层楼一览。"]'),
('song-ci-238','西江月','辛弃疾','宋','宋词','song-ci','西江月','[]','堂上谋臣帷幄，边头猛将干戈。',58,'宋词/ci.song.3000.json','["堂上谋臣帷幄，边头猛将干戈。", "天时地利与人和。", "燕可伐与曰可。", "此日楼台鼎鼐，他时剑履山河。", "都人齐和大风歌。", "管领群臣来贺。"]'),
('song-ci-239','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','青山招不来，偃蹇谁怜汝。',50,'宋词/ci.song.3000.json','["青山招不来，偃蹇谁怜汝。", "岁晚太寒生，唤我溪边住。", "山头明月来，本在高高处。", "夜夜入清溪，听读《离骚》去。"]'),
('song-ci-240','生查子','辛弃疾','宋','宋词','song-ci','生查子','[]','高人千丈崖，千古储冰雪。',48,'宋词/ci.song.3000.json','["高人千丈崖，千古储冰雪。", "六月火云时，一见森毛发。", "俗人如盗泉，照眼多昏浊。", "高处挂吾瓢，不饮吾宁渴。"]'),
('song-ci-241','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','盗跖傥名丘，孔子还名跖。',52,'宋词/ci.song.3000.json','["盗跖傥名丘，孔子还名跖。", "跖圣丘愚直至今，美恶无真实。", "简册写虚名，蝼蚁侵枯骨。", "千古光阴一霎时，且进杯中物。"]'),
('song-ci-242','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','一个去学仙，一个去学佛。',52,'宋词/ci.song.3000.json','["一个去学仙，一个去学佛。", "仙饮千杯醉似泥，皮骨如金石。", "不饮便康强，佛寿须千百。", "八十馀年入涅槃，且进杯中物。"]'),
('song-ci-243','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','一饮动连宵，一醉长三日。',52,'宋词/ci.song.3000.json','["一饮动连宵，一醉长三日。", "废尽寒暄不写书，富贵何由得。", "请看冢中人，冢似当时笔。", "万札千书只恁休，且进杯中物。"]'),
('song-ci-244','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','刚者不坚牢，柔者难摧挫。',52,'宋词/ci.song.3000.json','["刚者不坚牢，柔者难摧挫。", "不信张开口了看，舌在牙先堕。", "已阙两边厢，又豁中间个。", "说与儿曹莫笑翁，狗窦从君过。"]'),
('song-ci-245','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','一以我为牛，一以吾为马。',52,'宋词/ci.song.3000.json','["一以我为牛，一以吾为马。", "人与之名受不辞，善学庄周者。", "江海任虚舟，风雨从飘瓦。", "醉者乘车坠不伤，全得於天也。"]'),
('song-ci-246','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','夜雨醉瓜庐，春水行秧马。',52,'宋词/ci.song.3000.json','["夜雨醉瓜庐，春水行秧马。", "点检田间快活人，未有如翁者。", "秃尽兔豪锥，磨透铜台瓦。", "谁伴扬雄作解嘲，乌有先生也。"]'),
('song-ci-247','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','珠玉作泥沙，山谷量牛马。',52,'宋词/ci.song.3000.json','["珠玉作泥沙，山谷量牛马。", "试上累累丘垅看，谁是强梁者。", "水浸浅深檐，山压高低瓦。", "山水朝来笑问人，翁早归来也。"]'),
('song-ci-248','卜算子','辛弃疾','宋','宋词','song-ci','卜算子','[]','千古李将军，夺得胡儿马。',52,'宋词/ci.song.3000.json','["千古李将军，夺得胡儿马。", "李蔡为人在下中，却是封侯者。", "芸草去阵根，笕竹添新瓦。", "万一朝家举力田，舍我其谁也。"]'),
('song-ci-249','哨遍','辛弃疾','宋','宋词','song-ci','哨遍','[]','池上主人，人适忘鱼，鱼适还忘水。',243,'宋词/ci.song.3000.json','["池上主人，人适忘鱼，鱼适还忘水。", "洋洋乎，翠藻青萍里。", "想鱼兮、无便於此。", "尝试思，庄周正谈两事。", "一明豕虱一羊蚁。", "说蚁慕於膻，於蚁弃知，又说於羊弃意。", "甚虱焚於豕独忘之。", "却骤说於鱼为得计。", "千古遗文，我不知言，以我非子。", "子固非鱼，噫。", "鱼之为计子焉知。", "河水深且广，风涛万倾堪依。", "有网罟如云，鹈鹕成阵，过而留泣计应非。", "其外海茫茫，下有龙伯，饥时一啖千里。", "更任公五十犗为饵。", "使海上人人厌腥味。", "似鲲鹏、变化能几。", "东游入海，此计直以命为嬉。", "古来谬算狂图，五鼎烹死，指为平地。", "嗟鱼欲事远游时。", "请三思而行可矣。"]'),
('song-ci-250','兰陵王','辛弃疾','宋','宋词','song-ci','兰陵王','[]','恨之极。',158,'宋词/ci.song.3000.json','["恨之极。", "恨极销磨不得。", "苌弘事，人道后来，其血三年化为碧。", "郑人缓也泣。", "吾父攻儒助墨。", "十年梦，沈痛化余，秋柏之间既为实。", "相思重相忆。", "被怨结中肠，潜动精魄。", "望夫江上岩岩立。", "嗟一念中变，后期长绝。", "君看启母愤所激。", "又俄倾为石。", "难敌。", "最多力。", "甚一忿沈渊，精气为物。", "依然困斗牛磨角。", "便影入山骨，至今雕琢。", "寻思人间，只合化，梦中蝶。"]'),
('song-ci-251','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','著厌霓裳素。',141,'宋词/ci.song.3000.json','["著厌霓裳素。", "染胭脂、苎罗山下，浣沙溪渡。", "谁与流霞千古酝，引得东风相误。", "从臾入、吴宫深处。", "鬓乱钗横浑不醒，转越江、剗地迷归路。", "烟艇小，五湖去。", "当时倩得春留住。", "就锦屏一曲，种种断肠风度。", "才是清明三月近，须要诗人妙句。", "笑援笔、殷勤为赋。", "十样蛮笺纹错绮，粲珠玑、渊掷惊风雨。", "重唤酒，共花语。"]'),
('song-ci-252','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','碧海成桑野。',142,'宋词/ci.song.3000.json','["碧海成桑野。", "笑人间，江翻平陆，水云高下。", "自是三山颜色好，更著雨婚烟嫁。", "料未必、龙眠能画。", "拟向诗人求幼妇，倩诸君、妙手皆谈马。", "须进酒，为陶写。", "回头鸥鹭瓢泉社。", "莫吟诗、莫抛尊酒，是吾盟也。", "千骑而今遮白发，忘却沧浪亭榭。", "但记得、灞陵呵夜。", "我辈从来文字饮，怕壮怀、激烈须歌者。", "蝉噪也，绿阴夏。"]'),
('song-ci-253','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','鸟倦飞还矣。',142,'宋词/ci.song.3000.json','["鸟倦飞还矣。", "笑渊明、瓶中储粟，有无能几。", "莲社高人留翁语，我醉宁论许事。", "试沽酒、重斟翁喜。", "一见箫然音韵古，想东篱、醉卧参差是。", "千载下，竟谁似。", "元龙百尺高楼里。", "把新诗、殷勤问我，停云情味。", "北夏门高从拉攞，何事须人料理。", "翁曾道、繁华朝起。", "尘土人言宁可用，顾青山、与我何如耳。", "歌且和，楚狂子。"]'),
('song-ci-254','贺新郎','辛弃疾','宋','宋词','song-ci','贺新郎','[]','肘后俄生柳。',142,'宋词/ci.song.3000.json','["肘后俄生柳。", "叹人生、不如意事，十常八九。", "右手淋浪才有用，闲却持螯左手。", "谩赢得、伤今感旧。", "投阁先生惟寂寞，笑是非、不了身前后。", "持此语，问乌有。", "青山幸自重重秀。", "问新来、萧萧木落，颇堪秋否。", "总被西风都瘦损，依旧千岩万岫。", "把万事、无言搔首。", "翁比渠侬人谁好，是我常、与我周旋久。", "宁作我，一杯酒。"]'),
('song-ci-255','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','风狂雨横，是邀勒园林，几多桃李。',120,'宋词/ci.song.3000.json','["风狂雨横，是邀勒园林，几多桃李。", "待上层楼无气力，尘满栏干谁倚。", "就火添衣，移香傍枕，莫卷朱帘起。", "元宵过也，春寒犹自如此。", "为问几日新晴，鸠鸣屋上，鹊报檐前喜。", "揩试老来诗句眼，要看拍堤春水。", "月下凭肩，花边系马，此兴今休矣。", "溪南酒贱，光阴只在弹指。"]'),
('song-ci-256','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','["\u6d1e\u5ead\u6e56"]','洞庭春晚，旧传恐是，人间尤物。',119,'宋词/ci.song.3000.json','["洞庭春晚，旧传恐是，人间尤物。", "收拾瑶池倾国艳，来向朱栏一壁。", "透户龙香，隔帘莺语，料得肌如血。", "月妖真态，是谁教避人杰。", "酒罢归对寒窗，相留昨夜，应是梅花发。", "赋了高唐犹想像，不管孤灯明灭。", "半面难期，多情易感，愁点星星发。", "绕梁声在，为伊忘味三月。"]'),
('song-ci-257','念奴娇','辛弃疾','宋','宋词','song-ci','念奴娇','[]','是谁调护，岁寒枝、都把苍苔封了。',120,'宋词/ci.song.3000.json','["是谁调护，岁寒枝、都把苍苔封了。", "茅舍疏篱江上路，清夜月高山小。", "摸索应知，曹刘沈谢，何况霜天晓。", "芬芳一世，料君长被花恼。", "惆怅立马行人，一枝最爱，竹外横斜好。", "我向东邻曾醉里，唤起诗家二老。", "拄杖而今，婆娑雪里，又识商山皓。", "请君置酒，看渠与我倾倒。"]'),
('song-ci-258','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','老子平生，笑尽人间，儿女怨恩。',139,'宋词/ci.song.3000.json','["老子平生，笑尽人间，儿女怨恩。", "况白头能几，定应独往，青云得意，见说长存。", "抖擞衣冠，怜渠无恙，合挂当年神武门。", "都如梦，算能争几许，鸡晓钟昏。", "此心无有新冤。", "况抱瓮年来自灌园。", "但凄凉顾影，频悲往事，殷勤对佛，欲问前因。", "却怕青山，也妨贤路，休斗尊前见在身。", "山中友，试高吟楚些，重与招魂。"]'),
('song-ci-259','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','有美人兮，玉佩琼踞，吾梦见之。',139,'宋词/ci.song.3000.json','["有美人兮，玉佩琼踞，吾梦见之。", "问斜阳犹照，渔樵故里，长桥谁记，今故期思。", "物化苍茫，神游仿佛，春与猿吟秋鹤飞。", "还惊笑，向晴波忽见，千丈虹霓。", "觉来西望崔嵬。", "更上有青枫下有溪。", "待空山自荐，寒泉秋菊，中流却送，桂棹兰旗。", "万事长嗟，百年双鬓，吾非斯人谁与归。", "凭阑久，正清愁未了，醉墨休题。"]'),
('song-ci-260','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','我试评君，君定何如，玉川似之。',139,'宋词/ci.song.3000.json','["我试评君，君定何如，玉川似之。", "记李花初发，乘云共语，梅花开后，对月相思。", "白发重来，画桥一望，秋水长天孤鹜飞。", "同吟处，看佩摇明月，衣卷青霓。", "相君高节崔嵬。", "是此处耕岩与钓溪。", "被西风吹尽，村箫社鼓，青山留得，松盖云旗。", "吊古愁浓，怀人日暮，一片心从天外归。", "新词好，似凄凉楚些，字字堪题。"]'),
('song-ci-261','沁园春','辛弃疾','宋','宋词','song-ci','沁园春','[]','我醉狂吟，君作新声，倚歌和之。',139,'宋词/ci.song.3000.json','["我醉狂吟，君作新声，倚歌和之。", "算芬芳定向，梅间得意，轻清多是，雪里寻思。", "朱雀桥边，何人会道，野草斜阳春燕飞。", "都休问，甚元无霁雨，却有晴霓。", "诗坛千丈崔嵬。", "更有笔如山墨作溪。", "看君才未数，曹刘敌手，风骚合受，屈宋降旗。", "谁识相如，平生自许，慷慨须乘驷马归。", "长安路，问垂虹千柱，何处曾题。"]'),
('song-ci-262','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','落日古城角，把酒劝君留。',116,'宋词/ci.song.3000.json','["落日古城角，把酒劝君留。", "长安路远，何事风雪敝貂裘。", "散尽黄金身世，不管秦楼人怨，归计狎沙鸥。", "明夜扁舟去，和月载离愁。", "功名事，身未老，几时休。", "诗书万卷，致身须到古伊周。", "莫学班超投笔，纵得封侯万里，憔悴老边州。", "何处依刘客，寂寞赋《登楼》。"]'),
('song-ci-263','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','官事未易了，且向酒边来。',114,'宋词/ci.song.3000.json','["官事未易了，且向酒边来。", "君如无我，问君怀抱向谁开。", "但放平生丘壑，莫管旁人嘲骂，深蛰要惊雷。", "白发还自笑，何地置衰颓。", "五车书，千古饮，百篇才。", "新词未到，琼瑰先梦满吾怀。", "已过西风重九，且要黄花入手，诗兴未关梅。", "君要花满县，桃李趁时栽。"]'),
('song-ci-264','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','千里渥洼种，名动帝王家。',114,'宋词/ci.song.3000.json','["千里渥洼种，名动帝王家。", "金銮当日奏草，落笔万龙蛇。", "带得无边春下，等待江山都老，教看鬓方鸦。", "莫管钱流地，且拟醉黄花。", "唤双成，歌弄玉，舞绿华。", "一觞为饮千岁，江海吸流霞。", "闻道清都帝所，要挽银河仙浪，西北洗胡沙。", "回首日边去，云里认飞车。"]'),
('song-ci-265','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','千古老蟾口，云洞插天开。',114,'宋词/ci.song.3000.json','["千古老蟾口，云洞插天开。", "涨痕当日何事，汹涌到崔嵬。", "攫土抟沙儿戏，翠谷苍崖几变，风雨化人来。", "万里须臾耳，野马骤空埃。", "笑年来，蕉鹿梦，画蛇杯。", "黄花憔悴风露，野碧涨荒莱。", "此会明年谁健，后日犹今视昔，歌舞只空台。", "爱酒陶元亮，无酒正徘徊。"]'),
('song-ci-266','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','文字觑天巧，亭榭定风流。',114,'宋词/ci.song.3000.json','["文字觑天巧，亭榭定风流。", "平生丘壑，岁晚也作稻粱谋。", "五亩园中秀野，一水田将绿绕，䆉稏不胜秋。", "饭饱对花竹，可是便忘忧。", "吾老矣，探禹穴，欠东游。", "君家风月几许，白鸟去悠悠。", "插架牙签万轴，射虎南山一骑，容我揽鬚不。", "更欲劝君酒，百尺卧高楼。"]'),
('song-ci-267','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','日月如磨蚁，万事且浮休。',118,'宋词/ci.song.3000.json','["日月如磨蚁，万事且浮休。", "君看檐外江水，滚滚自东流。", "风雨瓢泉夜半，花草雪楼春到，老子已菟裘。", "岁晚问无恙，归计橘千头。", "梦连环，歌《弹铗》，赋《登楼》。", "黄鸡白酒，君去村社一番秋。", "长剑倚天谁问，夷甫诸人堪笑，西北有神州。", "此事君自了，千古一扁舟。"]'),
('song-ci-268','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','说与西湖客，观水更观山。',116,'宋词/ci.song.3000.json','["说与西湖客，观水更观山。", "淡妆浓抹西子，唤起一时观。", "种柳人今天上，对酒歌翻《水调》，醉墨卷秋澜。", "老子兴不浅，歌舞莫教闲。", "看尊前，轻聚散，少悲欢。", "城头无限今古，落日晓霜寒。", "谁唱黄鸡白酒，犹记红旗清夜，千骑月临关。", "莫说西州路，且尽一杯看。"]'),
('song-ci-269','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','万事一杯酒，长叹复长歌。',114,'宋词/ci.song.3000.json','["万事一杯酒，长叹复长歌。", "杜陵有客，刚赋云外筑婆娑。", "须信功名儿辈，谁识年来心事，古井不生波。", "种种看余发，积雪就中多。", "二三子，问丹桂，倩素娥。", "平生萤雪，男儿无奈五车何。", "看取长安得意，莫恨春风看尽，花柳自蹉砣。", "今夕且欢笑，明月镜新磨。"]'),
('song-ci-270','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','岁岁有黄菊，千载一东篱。',114,'宋词/ci.song.3000.json','["岁岁有黄菊，千载一东篱。", "悠然政须两字，长笑退之诗。", "自古此山元有，何事当时才见，此意有谁知。", "君起更斟酒，我醉不须辞。", "回首处，云正出，鸟倦飞。", "重来楼上，一句端的与君期。", "都把轩窗写遍，更使儿童诵得，归去来兮辞。", "万卷有时用，植杖且耘耔。"]'),
('song-ci-271','水调歌头','辛弃疾','宋','宋词','song-ci','水调歌头','[]','渊明最爱菊，三径也栽松。',114,'宋词/ci.song.3000.json','["渊明最爱菊，三径也栽松。", "何人收拾，千载风味此山中。", "手把离骚读遍，自扫落英餐罢，杖屦晓霜浓。", "皎皎太独立，更插万芙蓉。", "水潺湲，云澒洞，石巃嵸。", "素琴浊酒唤客，端有古人风。", "却怪青山能巧，政尔横看成岭，转面已成峰。", "诗句得活法，日月有新工。"]'),
('song-ci-272','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','美景良辰，算只是、可人风月。',114,'宋词/ci.song.3000.json','["美景良辰，算只是、可人风月。", "况素节扬辉，长是十分清彻。", "著意登楼瞻玉兔，何人张幕遮银阙。", "倩飞帘、得得为吹开，凭谁说。", "弦与望，从园缺。", "今与昨，何区别。", "羡夜来手把，桂花堪折。", "安得便登天柱上，从容陪伴酬佳节。", "更如今，不听麈谈清，愁如发。"]'),
('song-ci-273','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','点火樱桃，照一架、荼䕷如雪。',116,'宋词/ci.song.3000.json','["点火樱桃，照一架、荼䕷如雪。", "春正好，见龙孙穿破，紫苔苍壁。", "乳燕引雏飞力弱，流莺唤友娇声怯。", "问春归、不肯带愁归，肠千结。", "层楼望，春山叠。", "家何在，烟波隔。", "把古今遗恨，向他谁说。", "蝴碟不传千里梦，子规叫断三更月。", "听声声、枕上劝人归，归难得。"]'),
('song-ci-274','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','汉水东流，都洗尽、髭胡膏血。',115,'宋词/ci.song.3000.json','["汉水东流，都洗尽、髭胡膏血。", "人尽说、君家飞将，旧时英烈。", "破敌金城雷过耳，谈兵玉帐冰生颊。", "想王郎、结发赋从戎，传遗业。", "腰间剑，聊弹铗。", "尊中酒，堪为别。", "况故人新拥，汉坛旌节。", "马革裹尸当自誓，蛾眉伐性休重说。", "但从今、记取楚楼风，裴台月。"]'),
('song-ci-275','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','风卷庭梧，黄叶坠、新凉如洗。',115,'宋词/ci.song.3000.json','["风卷庭梧，黄叶坠、新凉如洗。", "一笑折、秋英同赏，弄香挼蕊。", "天远难穷休久望，楼高欲下还重倚。", "拼一襟、寂寞泪弹秋，无人会。", "今古恨，沈荒垒。", "悲欢事，随流水。", "想登楼青鬓，未堪憔悴。", "极目烟横山数点，孤舟月淡人千里。", "对婵娟、从此话离愁，金尊里。"]'),
('song-ci-276','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','紫陌飞尘，望十里、雕鞍绣毂。',115,'宋词/ci.song.3000.json','["紫陌飞尘，望十里、雕鞍绣毂。", "春未老、已惊台榭，瘦红肥绿。", "睡雨海棠犹倚醉，舞风杨柳难成曲。", "问流莺、能说故园无，曾相熟。", "岩泉上，飞凫浴。", "巢林下，栖禽宿。", "恨荼䕷开晚，谩翻船玉。", "莲社岂堪谈昨梦，兰亭何处寻遗墨。", "但羁怀、空自倚秋千，无心蹴。"]'),
('song-ci-277','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','汉节东南，看驷马、光华周道。',115,'宋词/ci.song.3000.json','["汉节东南，看驷马、光华周道。", "须信是、七闽还有，福星来到。", "庭草自生心意足，榕阴不动秋光好。", "问不知，何处著君侯，蓬莱岛。", "还自笑，人今老。", "空有恨，萦怀抱。", "记江湖十载，厌持旌纛。", "濩落我材无所用，易除殆类无根潦。", "但欲搜、好语谢新词，羞琼报。"]'),
('song-ci-278','满江红','辛弃疾','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','半山佳句，最好是、吹香隔屋。',115,'宋词/ci.song.3000.json','["半山佳句，最好是、吹香隔屋。", "又还怪、冰霜侧畔，蜂儿成簇。", "更把香来薰了月，却教影去斜侵竹。", "似神清、骨冷住西湖，何由俗。", "根老大，穿坤轴。", "枝夭袅，蟠龙斛。", "快酒兵长俊，诗坛高筑。", "一再人来风味恶，两三杯后花缘熟。", "记五更、联句失弥明，龙衔烛。"]'),
('song-ci-279','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','老子平生，原自有、金盘华屋。',115,'宋词/ci.song.3000.json','["老子平生，原自有、金盘华屋。", "还又要、万间寒士，眼前突兀。", "一舸归来轻似叶，两翁相对清如鹄。", "道如今、吾亦爱吾庐，多松菊。", "人道是，荒年毂。", "还又似，丰年玉。", "甚等闲却为，鲈鱼归速。", "野鹤溪边留杖屦，行人墙外听丝竹。", "问近来、风月几篇诗，三千轴。"]'),
('song-ci-280','满江红','辛弃疾','宋','宋词','song-ci','满江红','[]','两峡崭岩，问谁占、清风旧筑。',115,'宋词/ci.song.3000.json','["两峡崭岩，问谁占、清风旧筑。", "更满眼、云来鸟去，涧红山绿。", "世上无人供笑傲，门前有客休迎肃。", "怕凄凉、无物伴君时，多栽竹。", "风采妙，凝冰玉。", "诗句好，馀膏馥。", "叹只今人物，一夔应足。", "人似秋鸿无定住，事如飞弹须园熟。", "笑君侯、陪酒又陪歌，阳春曲。"]'),
('song-ci-281','永遇乐','辛弃疾','宋','宋词','song-ci','永遇乐','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','千古江山，英雄无觅，孙仲谋处。',128,'宋词/ci.song.3000.json','["千古江山，英雄无觅，孙仲谋处。", "舞榭歌台，风流总被，雨打风吹去。", "斜阳草树，寻常巷陌，人道寄奴曾住。", "想当年，金戈铁马，气吞万里如虎。", "元嘉草草，封狼居胥，赢得仓皇北顾。", "四十三年，望中犹记，烽火扬州路。", "可堪回首，佛狸祠下，一片神鸦社鼓。", "凭谁问，廉颇老矣，尚能饭否。"]'),
('song-ci-282','归朝欢','辛弃疾','宋','宋词','song-ci','归朝欢','[]','见说岷峨千古雪。',122,'宋词/ci.song.3000.json','["见说岷峨千古雪。", "都作岷峨山上石。", "君家右史老泉公，千金费尽勤收拾。", "一堂真石室。", "空庭更与添突兀。", "记当时，长编笔砚，日日云烟湿。", "野老时逢山鬼泣。", "谁夜持山去难觅。", "有人依样入明光，玉阶之下岩岩立。", "琅玕无数碧。", "风流不数平原物。", "欲重吟，青葱玉树，须倩子云笔。"]'),
('song-ci-283','瑞鹤仙','辛弃疾','宋','宋词','song-ci','瑞鹤仙','[]','雁霜寒透幕。',126,'宋词/ci.song.3000.json','["雁霜寒透幕。", "正护月云轻，嫩冰犹薄。", "溪奁照梳掠。", "想含香弄粉，艳妆难学。", "玉肌瘦弱。", "更重重、龙绡衬著。", "倚东风，一笑嫣然，转盼万花羞落。", "寂寞。", "家山何在，雪后园林，水边楼阁。", "瑶池旧约。", "鳞鸿更杖谁托。", "粉蝶儿只解，寻桃觅柳，开遍南枝未觉。", "但伤心，冷落黄昏，数声画角。"]'),
('song-ci-284','声声慢','辛弃疾','宋','宋词','song-ci','声声慢','[]','东南形胜，人物风流，白头见君恨晚。',119,'宋词/ci.song.3000.json','["东南形胜，人物风流，白头见君恨晚。", "便觉君家叔度，去人未远。", "长怜士元骥足，道直须、别驾方展。", "问个里，待怎生销杀，胸中万卷。", "况有星辰剑履，是传家合在，玉皇香案。", "零落新诗，我欠可人消遣。", "留君再三不住，便直饶、万家泪眼。", "怎抵得，这眉间、黄色一点。"]'),
('song-ci-285','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','[]','秦望山头，看乱云急雨，倒立江湖。',118,'宋词/ci.song.3000.json','["秦望山头，看乱云急雨，倒立江湖。", "不如云者为雨，雨者云乎。", "长空万里，被西风、变灭须臾。", "回首听，月明天籁，人间万窍号呼。", "谁向若耶溪上，倩美人西去，麋鹿姑苏。", "至今故国人望，一舸归欤。", "岁云暮矣，问何不、鼓瑟吹竽。", "君不间，王亭谢馆，冷烟寒树啼乌。"]'),
('song-ci-286','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','[]','亭上秋风，记去年袅袅，曾到吾庐。',118,'宋词/ci.song.3000.json','["亭上秋风，记去年袅袅，曾到吾庐。", "山河举目虽异，风景非殊。", "功成者去，觉团扇、便与人疏。", "吹不断，斜阳依旧，茫茫禹迹都无。", "千古茂陵词在，甚风流章句，解拟相如。", "只今木落江冷，眇眇愁余。", "故人书报，莫因循、忘却莼鲈。", "谁念我，新凉灯火，一编太史公书。"]'),
('song-ci-287','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','[]','心似孤僧，更茂林修竹，山上精庐。',120,'宋词/ci.song.3000.json','["心似孤僧，更茂林修竹，山上精庐。", "维摩定自非病，谁遣文殊。", "白头自昔，叹相逢、语密情疏。", "倾盖处，论心一语，只今还有公无。", "最喜《阳春》妙句，被西风吹堕，金玉铿如。", "夜来归梦江上，父老欢予。", "荻花深处，唤儿童、吹火烹鲈。", "归去也，绝交何必，更修山巨源书。"]'),
('song-ci-288','汉宫春','辛弃疾','宋','宋词','song-ci','汉宫春','[]','达则青云，便玉堂金马，穷则茅庐。',118,'宋词/ci.song.3000.json','["达则青云，便玉堂金马，穷则茅庐。", "逍遥小大自适，鹏鷃何殊。", "君如星斗，灿中天、密密疏疏。", "荒草外，自怜萤火，清光暂有还无。", "千古季鹰犹在，向松江道我，问讯何如。", "白头爱山下去，翁定嗔予。", "人生谩尔，岂食鱼、必鲙之鲈。", "还自笑，君诗顿觉，胸中万卷藏书。"]'),
('song-ci-289','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','冰姿玉骨，自是清凉〔态〕。',107,'宋词/ci.song.3000.json','["冰姿玉骨，自是清凉〔态〕。", "此度浓妆为谁改。", "向竹篱茅舍，几误佳期。", "招伊怪，满脸颜红微带。", "寿阳妆鉴里，应是承恩，纤手重匀异香在。", "怕等闲、春未到，雪里先开，风流㬠、说与群芳不解。", "更总做、北人未识伊，据品调，难作杏花看待。"]'),
('song-ci-290','洞仙歌','辛弃疾','宋','宋词','song-ci','洞仙歌','[]','贤愚相去，算其间能几。',100,'宋词/ci.song.3000.json','["贤愚相去，算其间能几。", "差以毫厘缪千里。", "细思量义利，舜跖之分，孳孳者，等是鸡鸣而起。", "味甘终易坏，岁晚还知，君子之交淡如水。", "一饷聚飞蚊，其响如雷，深自觉、昨非今是。", "羡安乐窝中泰和汤，更剧饮，无过半醺而已。"]'),
('song-ci-291','上西平・金人捧露盘','辛弃疾','宋','宋词','song-ci','上西平・金人捧露盘','[]','九衢中，杯逐马，带随车。',99,'宋词/ci.song.3000.json','["九衢中，杯逐马，带随车。", "问谁解、爱惜琼华。", "何如竹外，静听窣窣蟹行沙。", "自怜是，海山头，种玉人家。", "纷如斗，娇如舞，才整整，又斜斜。", "要图画，还我渔蓑。", "冻吟应笑，羔儿无分谩煎茶。", "起来极目，向弥茫、数尽归鸦。"]'),
('song-ci-292','上西平・金人捧露盘','辛弃疾','宋','宋词','song-ci','上西平・金人捧露盘','[]','恨如新，新恨了，又重新。',97,'宋词/ci.song.3000.json','["恨如新，新恨了，又重新。", "看天上、多少浮云。", "江南好景，落花时节又逢君。", "夜来风雨，春归似欲留人。", "尊如海，人如玉，诗如锦，笔如神。", "能几字、尽殷勤。", "江天日暮，何时重与细论文。", "绿杨阴里，听阳关、门掩黄昏。"]'),
('song-ci-293','婆罗门引','辛弃疾','宋','宋词','song-ci','婆罗门引','[]','不堪鶗鴂，早教百草放春归。',93,'宋词/ci.song.3000.json','["不堪鶗鴂，早教百草放春归。", "江头愁杀吾累。", "却觉君侯雅句，千载共心期。", "便留春甚乐，乐了须悲。", "琼而素而。", "被花恼、只莺知。", "正要千锺角酒，五字栽诗。", "江东日暮，道绣斧、人去未多时。", "还又要、玉殿论思。"]'),
('song-ci-294','千年调','辛弃疾','宋','宋词','song-ci','千年调','[]','卮酒向人时，和气先倾倒。',93,'宋词/ci.song.3000.json','["卮酒向人时，和气先倾倒。", "最要然然可可，万事称好。", "滑稽坐上，更对鸱夷笑。", "寒与热，总随人，甘国老。", "少年使酒，出口人嫌拗。", "此个和合道理，近日方晓。", "学人言语，未会十分巧。", "看他门，得人怜，秦吉了。"]'),
('song-ci-295','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','暗香横路雪垂垂。',86,'宋词/ci.song.3000.json','["暗香横路雪垂垂。", "晚风吹。", "晓风吹。", "花意争春，先出岁寒枝。", "毕竟一年春事了，缘太早，却成迟。", "未应全是雪霜姿。", "欲开时。", "未开时。", "粉面朱唇，一半点胭脂。", "醉里谤花花莫恨，浑冷淡，有谁知。"]'),
('song-ci-296','江神子・江城子','辛弃疾','宋','宋词','song-ci','江神子・江城子','[]','五云高处望西清。',88,'宋词/ci.song.3000.json','["五云高处望西清。", "玉阶升。", "棣华荣。", "筑屋溪头，楼观画难成。", "长夜笙歌还起问，谁放月，又西沉。", "家传《鸿宝》旧知名。", "看长生。", "奉严宸。", "且把风流，水北画耆英。", "咫尺西风诗酒社，石鼎句，要弥明。"]'),
('song-ci-297','一翦梅','辛弃疾','宋','宋词','song-ci','一翦梅','[]','忆对中秋丹桂丛。',72,'宋词/ci.song.3000.json','["忆对中秋丹桂丛。", "花在杯中。", "月在杯中。", "今宵楼上一尊同。", "云湿纱窗。", "雨湿纱窗。", "浑欲乘风问化工。", "路也难通。", "信也难通。", "满堂惟有烛花红。", "杯且从容。", "歌且从容。"]'),
('song-ci-298','踏莎行','辛弃疾','宋','宋词','song-ci','踏莎行','[]','夜月楼台，秋香院宇。',68,'宋词/ci.song.3000.json','["夜月楼台，秋香院宇。", "笑吟吟地人来去。", "是谁秋到便凄凉，当年宋玉悲如许。", "随分杯盘，等闲歌舞。", "问他有甚堪悲处。", "思量却也有悲时，重阳节近多风雨。"]'),
('song-ci-299','踏莎行','辛弃疾','宋','宋词','song-ci','踏莎行','[]','弄影阑干，吹香岩谷。',70,'宋词/ci.song.3000.json','["弄影阑干，吹香岩谷。", "枝枝点点黄金粟。", "未堪收拾付薰炉，窗前且把《离骚》读。", "奴仆葵花，儿曹金菊。", "一秋风露清凉足。", "傍边只欠个姮娥，分明身在蟾宫宿。"]'),
('song-ci-300','踏莎行','辛弃疾','宋','宋词','song-ci','踏莎行','[]','吾道悠悠，忧心悄悄。',68,'宋词/ci.song.3000.json','["吾道悠悠，忧心悄悄。", "最无聊处秋光到。", "西风林外有啼鸦，斜阳山下多衰草。", "长忆商山，当年四老。", "尘埃也走咸阳道。", "为谁书到便幡然，至今此意无人晓。"]'),
('song-ci-301','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','金印累累佩陆离。',73,'宋词/ci.song.3000.json','["金印累累佩陆离。", "河梁更赋断肠诗。", "莫拥旌旗真个去。", "何处。", "玉堂元自要论思。", "且约风流三学士。", "同醉。", "春风看试几枪旗。", "从此酒酣明月夜。", "耳热。", "那边应是说侬时。"]'),
('song-ci-302','定风波','辛弃疾','宋','宋词','song-ci','定风波','[]','野草闲花不当春。',70,'宋词/ci.song.3000.json','["野草闲花不当春。", "杜鹃却是旧知闻。", "谩道不如归去住。", "梅雨。", "石榴花又是离魂。", "前殿群臣深殿女。", "赭袍一点万红巾。", "莫问兴亡今几主。", "听取。", "花前毛羽已羞人。"]'),
('song-ci-303','破阵子','辛弃疾','宋','宋词','song-ci','破阵子','[]','菩萨丛中惠眼，硕人诗里娥眉。',72,'宋词/ci.song.3000.json','["菩萨丛中惠眼，硕人诗里娥眉。", "天上人间真福相，画就描成好靥儿。", "行时娇更迟。", "劝酒偏他最劣，笑时犹有些痴。", "更著十年君看取，两国夫人更是谁。", "殷勤秋水词。"]'),
('song-ci-304','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','小靥人怜都恶瘦，曲眉天与长颦。',70,'宋词/ci.song.3000.json','["小靥人怜都恶瘦，曲眉天与长颦。", "沈思欢事惜腰身。", "枕添离别泪，粉落却深匀。", "翠袖盈盈浑力薄，玉笙袅袅愁新。", "夕阳依旧倚窗尘。", "叶红苔郁碧，深院断无人。"]'),
('song-ci-305','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','逗晓莺啼声昵昵，掩关高树冥冥。',72,'宋词/ci.song.3000.json','["逗晓莺啼声昵昵，掩关高树冥冥。", "小渠春浪细无声。", "井床听夜雨，出藓辘轳青。", "碧草旋荒金谷路，乌丝重记《兰亭》。", "强扶残醉绕云屏。", "一枝风露湿，花重入疏棂。"]'),
('song-ci-306','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','春色饶君白发了，不妨倚绿偎红。',70,'宋词/ci.song.3000.json','["春色饶君白发了，不妨倚绿偎红。", "翠鬟催唤出房栊。", "垂肩金缕窄，蘸甲宝杯浓。", "睡起鸳鸯飞燕子，门前沙暖泥融。", "画楼人把玉西东。", "舞低花外月，唱澈柳边风。"]'),
('song-ci-307','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','金谷无烟宫树绿，嫩寒生怕春风。',70,'宋词/ci.song.3000.json','["金谷无烟宫树绿，嫩寒生怕春风。", "博山微透暖薰笼。", "小楼春色里，幽梦雨声中。", "别浦鲤鱼何日到，锦书封恨重重。", "海棠花下去年逢。", "也应随分瘦，忍泪觅残红。"]'),
('song-ci-308','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','手种门前乌桕树，而今千尺苍苍。',70,'宋词/ci.song.3000.json','["手种门前乌桕树，而今千尺苍苍。", "田园只是旧耕桑。", "杯盘风月夜，箫鼓子孙忙。", "七十五年无事客，不妨两鬓如霜。", "绿窗剗地调红妆。", "更从今日醉，三万六千场。"]'),
('song-ci-309','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','手拈黄花无意绪，等闲行尽回廊。',70,'宋词/ci.song.3000.json','["手拈黄花无意绪，等闲行尽回廊。", "卷帘芳桂散馀香。", "枯荷难睡鸭，疏雨暗池塘。", "忆得旧时携手处，如今水远山长。", "罗巾浥泪别残妆。", "旧欢新梦里，闲处却思量。"]'),
('song-ci-310','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','冷雁寒云渠有恨，春风自满余怀。',70,'宋词/ci.song.3000.json','["冷雁寒云渠有恨，春风自满余怀。", "更教无日不花开。", "未须愁菊尽，相次有梅来。", "多病近来浑止酒，小槽空压新醅。", "青山却自要安排。", "不须连日醉，且进两三杯。"]'),
('song-ci-311','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','六十三年无限事，从头悔恨难追。',70,'宋词/ci.song.3000.json','["六十三年无限事，从头悔恨难追。", "已知六十二年非。", "只应今日是，后日又寻思。", "少是多非惟有酒，何须过后方知。", "从今休似去年时。", "病中留客饮，醉里和人诗。"]'),
('song-ci-312','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','窄样金杯教换了，房栊试听珊珊。',70,'宋词/ci.song.3000.json','["窄样金杯教换了，房栊试听珊珊。", "莫教秋扇雪团团。", "古今悲笑事，长付后人看。", "记取桔槔春雨后，短畦菊艾相连。", "拙於人处巧于天。", "君看流水地，难得正方园。"]'),
('song-ci-313','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','醉帽吟鞭花不住，却招花共商量。',70,'宋词/ci.song.3000.json','["醉帽吟鞭花不住，却招花共商量。", "人生何必醉为乡。", "从教斟酒浅，休更和诗忙。", "一斗百篇风月地，饶他老子当行。", "从今三万六千场。", "青青头上发，还作柳丝长。"]'),
('song-ci-314','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','祗恐牡丹留不住，与春约束分明。',70,'宋词/ci.song.3000.json','["祗恐牡丹留不住，与春约束分明。", "未开微雨半开晴。", "要花开定准，又更与花盟。", "魏紫朝来将进酒，玉盘盂样先呈。", "鞓红似向舞腰横。", "风流人不见，锦绣夜间行。"]'),
('song-ci-315','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','老去浑身无著处，天教只住山林。',70,'宋词/ci.song.3000.json','["老去浑身无著处，天教只住山林。", "百年光景百年心。", "更欢须叹息，无病也呻吟。", "试向浮瓜沈李处，清风散发披襟。", "莫嫌浅后更频斟。", "要他诗句好，须是酒杯深。"]'),
('song-ci-316','临江仙','辛弃疾','宋','宋词','song-ci','临江仙','[]','偶向停云堂上坐，晓猿夜鹤惊猜。',70,'宋词/ci.song.3000.json','["偶向停云堂上坐，晓猿夜鹤惊猜。", "主人何事太尘埃。", "低头还说向，被召又重来。", "多谢北山山下老，殷勤一语佳哉。", "借君竹杖与芒鞋。", "径须从此去，深入白云堆。"]'),
('song-ci-317','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','泪眼送君倾似雨。',70,'宋词/ci.song.3000.json','["泪眼送君倾似雨。", "不折垂杨，只倩愁随去。", "有底风光留不住。", "烟波万顷春江橹。", "老马临流痴不渡。", "应惜障泥，忘了寻春路。", "身在稼轩安稳处。", "书来不用多行数。"]'),
('song-ci-318','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','燕语莺啼人乍远。',70,'宋词/ci.song.3000.json','["燕语莺啼人乍远。", "却恨西园，依旧莺和燕。", "笑语十分愁一半。", "翠围特地春光暖。", "只道书来无过雁。", "不道柔肠，近日无肠断。", "柄玉莫摇湘泪点。", "怕君唤作秋风扇。"]'),
('song-ci-319','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','洗尽机心随法喜。',70,'宋词/ci.song.3000.json','["洗尽机心随法喜。", "看取尊前，秋思如春意。", "谁与先生宽发齿。", "醉时惟有歌而已。", "岁月何须溪上记。", "千古黄花，自有渊明比。", "高卧石龙呼不起。", "微风不动天如醉。"]'),
('song-ci-320','蝶恋花','辛弃疾','宋','宋词','song-ci','蝶恋花','[]','何物能令公怒喜。',70,'宋词/ci.song.3000.json','["何物能令公怒喜。", "山要人来，人要山无意。", "恰似哀筝弦下齿。", "千情万意无时已。", "自要溪堂韩作记。", "今代机云，好语花难比。", "老眼狂花空处起。", "银钩未见心先醉。"]'),
('song-ci-321','南乡子','辛弃疾','宋','宋词','song-ci','南乡子','["\u957f\u6c5f"]','何处望神州。',66,'宋词/ci.song.3000.json','["何处望神州。", "满眼风光北固楼。", "千古兴亡多少事，悠悠。", "不尽长江衮衮流。", "年少万兜鍪。", "坐断东南战未休。", "天下英雄谁敌手。", "曹刘。", "生子当如孙仲谋。"]'),
('song-ci-322','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','别恨妆成白发新。',64,'宋词/ci.song.3000.json','["别恨妆成白发新。", "空教儿女笑阵人。", "醉寻夜雨旗亭酒，梦断东风辇路尘。", "骑騄駬，籋青云。", "看公冠佩玉阶春。", "忠言句句唐虞际，便是人间要路津。"]'),
('song-ci-323','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','樽俎风流有几人。',64,'宋词/ci.song.3000.json','["樽俎风流有几人。", "当年未遇已心亲。", "金陵种柳欢娱地，庾岭逢梅寂寞滨。", "樽似海，笔如神。", "故人南北一般春。", "玉人好把新妆样，淡画眉儿浅注唇。"]'),
('song-ci-324','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','指点斋尊特地开。',64,'宋词/ci.song.3000.json','["指点斋尊特地开。", "风帆莫引酒船回。", "方惊共折津头柳，却喜重寻岭上梅。", "催月上，唤风来。", "莫愁瓶罄耻金罍。", "只愁画角楼头起，急管哀弦次第催。"]'),
('song-ci-325','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','困不成眠奈夜何。',64,'宋词/ci.song.3000.json','["困不成眠奈夜何。", "情知归未转愁多。", "暗将往事思量遍，谁把多情恼乱他。", "些底事，误人哪。", "不成真个不思家。", "娇痴却妒香香睡，唤起醒松说梦些。"]'),
('song-ci-326','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','梦断京华故倦游。',64,'宋词/ci.song.3000.json','["梦断京华故倦游。", "只今芳草替人愁。", "阳关莫作三叠唱，越女应须为我留。", "看逸韵，自名流。", "青衫司马且江州。", "君家兄弟真堪笑，个个能修五凤楼。"]'),
('song-ci-327','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','一夜清霜变鬓丝。',64,'宋词/ci.song.3000.json','["一夜清霜变鬓丝。", "怕愁刚把酒禁持。", "玉人今夜相思不，想见频将翠枕移。", "真个恨，未多时。", "也应香雪减些儿。", "菱花照面须频记，曾道偏宜浅画眉。"]'),
('song-ci-328','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','木落山高一夜霜。',64,'宋词/ci.song.3000.json','["木落山高一夜霜。", "北风驱雁又离行。", "无言每觉情怀好，不饮能令兴味长。", "频聚散，试思量。", "为谁春草梦池塘。", "中年长作东山恨，莫遣离歌苦断肠。"]'),
('song-ci-329','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','抛却山中诗酒窠。',64,'宋词/ci.song.3000.json','["抛却山中诗酒窠。", "却来官府听笙歌。", "闲愁做弄天来大，白发栽埋日许多。", "新剑戟，旧风波。", "天生予懒奈予何。", "此身已觉浑无事，却教儿童莫恁麽。"]'),
('song-ci-330','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','桃李漫山过眼空。',64,'宋词/ci.song.3000.json','["桃李漫山过眼空。", "也宜恼损杜陵翁。", "若将玉骨冰姿比，李蔡为人在下中。", "寻驿使，寄芳容。", "垅头休放马蹄松。", "吾家离落黄昏后，剩有西湖处士风。"]'),
('song-ci-331','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','晚岁躬耕不怨贫。',64,'宋词/ci.song.3000.json','["晚岁躬耕不怨贫。", "只鸡斗酒聚比邻。", "都无晋宋之间事，自是羲皇以上人。", "千载后，百篇存。", "更无一字不清真。", "若教王谢诸郎在，未抵柴桑陌上尘。"]'),
('song-ci-332','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','发底青青无限春。',64,'宋词/ci.song.3000.json','["发底青青无限春。", "落红飞雪谩纷纷。", "黄花也伴秋光老，何事尊前见在身。", "书万卷，笔如神。", "眼看同辈上青云。", "个中不许儿童会，只恐功名更逼人。"]'),
('song-ci-333','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','老退何曾说著官。',64,'宋词/ci.song.3000.json','["老退何曾说著官。", "今朝放罪上恩宽。", "便支香火真侍俸，更缀文书旧殿班。", "扶病脚，洗衰颜。", "快从老病借衣冠。", "此身忘世浑容易，使世相忘却自难。"]'),
('song-ci-334','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','绿鬓都无白发侵。',64,'宋词/ci.song.3000.json','["绿鬓都无白发侵。", "醉时拈笔越精神。", "爱将芜语追前事，更把梅花比那人。", "回急雪，遏行云。", "近时歌舞旧时情。", "君侯要识谁轻重，看取金杯几许深。"]'),
('song-ci-335','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','泉上长吟我独清。',64,'宋词/ci.song.3000.json','["泉上长吟我独清。", "喜君来共雪争明。", "已惊并水鸥无色，更怪行沙蟹有声。", "添爽气，动雄情。", "奇因六出忆陈平。", "却嫌鸟雀投林去，触破当楼云母屏。"]'),
('song-ci-336','鹧鸪天','辛弃疾','宋','宋词','song-ci','鹧鸪天','[]','莫殢春光花下游。',64,'宋词/ci.song.3000.json','["莫殢春光花下游。", "便须准备落花愁。", "百年雨打风吹却，万事三平二满休。", "将扰扰，付悠悠。", "此生於世百无忧。", "新愁次第相抛舍，要伴春归天尽头。"]'),
('song-ci-337','瑞鹧鸪','辛弃疾','宋','宋词','song-ci','瑞鹧鸪','[]','暮年不赋短长词。',66,'宋词/ci.song.3000.json','["暮年不赋短长词。", "和得渊明数首诗。", "君自不归归甚易，今犹未足足何时。", "偷闲定向山中老，此意须教鹤辈知。", "闻道只今秋水上，故人曾榜《北山移》。"]'),
('song-ci-338','瑞鹧鸪','辛弃疾','宋','宋词','song-ci','瑞鹧鸪','[]','声名少日畏人知。',64,'宋词/ci.song.3000.json','["声名少日畏人知。", "老去行藏与愿违。", "山草旧曾呼远志，故人今又寄当归。", "何人可觅安心法，有客来观杜德机。", "却笑使君那得似，清江万顷白鸥飞。"]'),
('song-ci-339','瑞鹧鸪','辛弃疾','宋','宋词','song-ci','瑞鹧鸪','[]','胶胶扰扰几时休。',64,'宋词/ci.song.3000.json','["胶胶扰扰几时休。", "一出山来不自由。", "秋水观中山月夜，停云堂下菊花秋。", "随缘道理应须会，过分功名莫强求。", "先自一身愁不了，那堪愁上更添愁。"]'),
('song-ci-340','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','["\u897f\u6e56"]','向天涯、水流云散，依依往事非旧。',140,'宋词/ci.song.3000.json','["向天涯、水流云散，依依往事非旧。", "西湖见说鸥飞去，知有海翁来否。", "风雨后。", "甚客里逢春，尚记花间酒。", "空嗟皓首。", "对茂苑残红，携歌占地，相趁小垂手。", "归时候。", "花径青红尚有。", "好游何事诗瘦。", "龟蒙未肯寻幽兴，曾恋志和渔叟。", "吟啸久。", "爱如此清奇，岁晚忘年友。", "呼船渡口。", "叹西出阳关，故人何处，愁在渭城柳。"]'),
('song-ci-341','南乡子','张炎','宋','宋词','song-ci','南乡子','[]','风月似孤山。',66,'宋词/ci.song.3000.json','["风月似孤山。", "千树斜横水一环。", "天与清香心独领，怡颜。", "冰雪中间屋数间。", "庭户隔尘寰。", "自有云封底用关。", "却笑桃源深处隐，跻攀。", "引得渔翁见不难。"]'),
('song-ci-342','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','["\u897f\u6e56"]','一见又天涯。',74,'宋词/ci.song.3000.json','["一见又天涯。", "人生可叹嗟。", "想难忘、江上琵琶。", "诗酒一瓢风雨外，都莫问，是谁家。", "怜我鬓先华。", "何愁归路赊。", "向西湖、重隐烟霞。", "说与山童休放鹤，最零落，是梅花。"]'),
('song-ci-343','醉落魄・一斛珠','张炎','宋','宋词','song-ci','醉落魄・一斛珠','[]','镂花镌叶。',67,'宋词/ci.song.3000.json','["镂花镌叶。", "满枝风露和香撷。", "引将芳思归吟箧。", "梦与魂同，闲了弄香蝶。", "小楼帘卷歌声歇。", "幽篁独处泉呜咽。", "短笺空在愁难说。", "霜角寒梅，吹碎半江月。"]'),
('song-ci-344','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','["\u897f\u6e56"]','西秦倦旅。',120,'宋词/ci.song.3000.json','["西秦倦旅。", "是几年不听，西湖风雨。", "我托长镵垂短发，心事时看天语。", "吟箧空随，征衣休换，薜荔犹堪补。", "山能招隐，一瓢闲挂烟树。", "方叹旧国人稀，花间忽见，倾盖浑如故。", "客里不须谈世事，野老安知今古。", "海上盟鸥，门深款竹，风月平分取。", "陶然一醉，此时愁在何处。"]'),
('song-ci-345','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','鬟丝湿雾，扇锦翻桃，尊前乍识欧苏。',119,'宋词/ci.song.3000.json','["鬟丝湿雾，扇锦翻桃，尊前乍识欧苏。", "赋笔吟笺，光动万颗骊珠。", "英英岁华未老，怨歌长、空击铜壶。", "细看取，有飘然清气，自与尘疏。", "两水犹存三径，叹绿窗窈窕，谩长新浦。", "茂苑扁舟，底事夜雨江湖。", "当年柳枝放却，又不知、樊素何如。", "向醉里，暗传香、还记也无。"]'),
('song-ci-346','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','黑云飞起。',54,'宋词/ci.song.3000.json','["黑云飞起。", "夜月啼湘鬼。", "魂返灵根无二纸。", "千古不随流水。", "香心淡染清华。", "似花还似非花。", "要与闲梅相处，孤山山下人家。"]'),
('song-ci-347','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','几年槐市槐花冷，天风又还吹起。',123,'宋词/ci.song.3000.json','["几年槐市槐花冷，天风又还吹起。", "故箧重寻，闲书再整，犹记灯窗滋味。", "浑如梦里。", "见说道如今，早催行李。", "快买扁舟，第一桥边趁流水。", "阳关须是醉酒，柳条休要折，争似攀桂。", "旧有家声，荣看世美，方了平生英气。", "琼林宴喜。", "带雪絮归来，满庭春意。", "事业方新，大鹏九万里。"]'),
('song-ci-348','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','万尘自远，径松存、彷佛斜川深意。',120,'宋词/ci.song.3000.json','["万尘自远，径松存、彷佛斜川深意。", "乌石罔边犹记得，竹里吟安一字。", "暗叶禽幽，虚阑荷近，暑薄迟花气。", "行行且止，枯瓢枝上闲寄。", "不恨老却流光，可怜归未得，翻恨流水。", "落落岭头云尚在，一笑生涯如此。", "树老梅荒，山孤人共，隔浦船归未。", "划然长啸，海风吹下空翠。"]'),
('song-ci-349','如梦令','张炎','宋','宋词','song-ci','如梦令','[]','隐隐烟痕轻注。',40,'宋词/ci.song.3000.json','["隐隐烟痕轻注。", "拂拂脂香微度。", "十二小红楼，人与玉箫何处。", "归去。", "归去。", "醉插一枝风露。"]'),
('song-ci-350','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','路重寻，门半掩、苔老旧时树。',95,'宋词/ci.song.3000.json','["路重寻，门半掩、苔老旧时树。", "采药云深，童子更无语。", "怪他流水迢迢，湖天日暮，想只在、芦花多处。", "谩延伫。", "姓名题上芭蕉，凉夜未风雨。", "赋了秋声，还赋断肠句。", "几回独立长桥，扁舟欲唤，待招取、白鹤归去。"]'),
('song-ci-351','如梦令','张炎','宋','宋词','song-ci','如梦令','["\u6d1e\u5ead\u6e56"]','不是潇湘风雨。',40,'宋词/ci.song.3000.json','["不是潇湘风雨。", "不是洞庭烟树。", "醉倒古乾坤，人在孤篷来处。", "休去。", "休去。", "见说桃源无路。"]'),
('song-ci-352','桂枝香','张炎','宋','宋词','song-ci','桂枝香','["\u897f\u6e56"]','琴书半室。',124,'宋词/ci.song.3000.json','["琴书半室。", "向桂边偶然，一见秋色。", "老树香迟，清露缀花疑滴。", "山翁翻笑如泥醉，笑生平、无此狂逸。", "晋人游处，幽情付与，酒尊吟笔。", "任萧散、披襟岸帻。", "叹千古犹今，休问何夕。", "发短霜浓，却恐浩歌消得。", "明年野客重来此，探枝头、几分消息。", "望西楼远，西湖更远，也寻梅驿。"]'),
('song-ci-353','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','春树江东。',119,'宋词/ci.song.3000.json','["春树江东。", "吟正远、清气竟入崆峒。", "问余栖处，只在缥缈山中。", "此去山中何所有，芰荷制了集芙蓉。", "且扶筇。", "倦游万里，独对青松。", "行藏也须在我，笑晋人为菊，出岫方浓。", "淡然无心，古意且许谁同。", "飞符夜深润物，自呼起苍龙雨太空。", "舒还卷，看满楼依旧，霁日光风。"]'),
('song-ci-354','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','近水横斜。',119,'宋词/ci.song.3000.json','["近水横斜。", "先得月、玉树宛若笼纱。", "散迹苔裀，墨晕净洗铅华。", "误入罗浮身外梦，似花又却似非花。", "探寒葩。", "倩人醉里，扶过溪沙。", "竹篱几番倦倚，看乍无乍有，如寄生涯。", "更好一枝，时到素壁檐牙。", "香深与春暗却，且休把江头千树夸。", "东家女，试淡妆颠倒，难胜西家。"]'),
('song-ci-355','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','老圃堪嗟。',119,'宋词/ci.song.3000.json','["老圃堪嗟。", "深夜雨、紫英犹傲霜华。", "暖宿篱根，飞去想怯寒沙。", "采摘浮杯如戏水，晚香淡似夜来些。", "背风斜。", "翠苔径里，描绣人夸。", "白头共开笑口，看试妆满插，云髻双丫。", "蝶也休愁，不是旧日疏葩。", "连枝愿为比翼，问因甚寒城独自花。", "悠然意，对九江山色，还醉陶家。"]'),
('song-ci-356','西江月','张炎','宋','宋词','song-ci','西江月','[]','花气烘人尚暖，珠光出海犹寒。',58,'宋词/ci.song.3000.json','["花气烘人尚暖，珠光出海犹寒。", "如今贺老见应难。", "解道江南肠断。", "谩击铜壶浩叹，空存锦瑟谁弹。", "庄生蝴蝶梦春还。", "帘外一声莺唤。"]'),
('song-ci-357','霜叶飞','张炎','宋','宋词','song-ci','霜叶飞','["\u897f\u6e56"]','绣屏开了。',132,'宋词/ci.song.3000.json','["绣屏开了。", "惊诗梦、娇声啼破春悄。", "隐将谱字转清圆，正杏梁声绕。", "看帖帖、蛾眉淡扫。", "不知能聚愁多少。", "叹客里凄凉，尚记得当年雅音，低唱还好。", "同是流落殊乡，相逢何晚，坐对被真花恼。", "贞元朝士已无多，但暮烟衰草。", "未忘得春风窈窕。", "却怜张绪如今老。", "且慰我留连意，莫说西湖，那时苏小。"]'),
('song-ci-358','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','济楚衣裳眉目秀。',70,'宋词/ci.song.3000.json','["济楚衣裳眉目秀。", "活脱梨园，子弟家声旧。", "诨砌随机开笑口。", "筵前戏谏从来有。", "戛玉敲金裁锦绣。", "引得传情，恼得娇娥瘦。", "离合悲欢成正偶。", "明珠一颗盘中走。"]'),
('song-ci-359','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','见梅花、斜倚竹篱边。',119,'宋词/ci.song.3000.json','["见梅花、斜倚竹篱边。", "休道北枝寒。", "□□□翠袖，情随眼盼，愁接眉弯。", "一串歌珠清润，绾结玉连环。", "苏小无寻处，元在人间。", "何事凄凉蚓窍，向尊前一笑，歌倒狂澜。", "叹从来古雅，欲觅赏音难。", "有如此、和声软语，甚韩湘、风雪度蓝关。", "君知否，挽樱评柳，却是香山。"]'),
('song-ci-360','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','["\u5e90\u5c71", "\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','俯长江、不占洞庭波，山拔地形高。',119,'宋词/ci.song.3000.json','["俯长江、不占洞庭波，山拔地形高。", "对扶疏古木，浮图倒影，势压雄涛。", "门掩翠微僧院，应有月明敲。", "物换堂安在，断碣闲抛。", "不识庐山真面，是谁将此屋，突兀林坳。", "上层台回首，万境入诗豪。", "响天心、数声长啸，任清风、吹顶发萧骚。", "凭栏久，青琴何处，独立琼瑶。"]'),
('song-ci-361','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','屋上青山。',119,'宋词/ci.song.3000.json','["屋上青山。", "青未了、凌虚试一凭栏。", "乱峰叠嶂，无限古色苍寒。", "正喜云闲云又去，片云未识我心闲。", "对林峦。", "底须谢屐，何用跻攀。", "三十六梯眺远，任半空笑语，飞落人间。", "赋笔吟笺，尘事竟不相关。", "朝来自然气爽，更好是秋屏宜晚看。", "蓬壶里，有天开图画，休唤边鸾。"]'),
('song-ci-362','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','长流万里。',120,'宋词/ci.song.3000.json','["长流万里。", "与沈沈沧海，平分一水。", "孤白争流蟾不没，影落潜蛟惊起。", "莹玉悬秋，绿房迎晓，楼观光疑洗。", "紫箫声袅，四檐吹下清气。", "遥睇浪擎空明，古愁休问，消长盈虚理。", "风入芦花歌忽断，知有渔舟闲舣。", "露已沾衣，鸥犹栖草，一片潇湘意。", "人方酣梦，长翁元自如此。"]'),
('song-ci-363','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','翠屏缺处添奇观，修眉远浮孤碧。',123,'宋词/ci.song.3000.json','["翠屏缺处添奇观，修眉远浮孤碧。", "天影微茫，烟痕黯淡，不与千峰同色。", "凭高望极。", "向帘幕中间，冷光流入。", "料得吟僧，数株松下坐苍石。", "泉源犹是故迹。", "煮茶曾味古，还记游历。", "调水符闲，登山屐在，却倚阑干斜日。", "轻阴易□。", "看飘忽风云，晦明朝夕。", "为我飞来，傍江横峭壁。"]'),
('song-ci-364','江城子','张炎','宋','宋词','song-ci','江城子','[]','下临无地手扪天。',86,'宋词/ci.song.3000.json','["下临无地手扪天。", "上云烟。", "俯山川。", "栖止危巢，不隔道林禅。", "坐处清高风雨隔，全万境，一壶悬。", "我来直欲挟飞仙。", "海为田。", "是何年。", "如此江声，啸咏白鸥前。", "老树无根云懵懂，凭寄语、米家船。"]'),
('song-ci-365','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','风雷开万象，散天影、入虚坛。',124,'宋词/ci.song.3000.json','["风雷开万象，散天影、入虚坛。", "看峭壁重云，奇峰献玉，光洗琅玕。", "青苔古痕暗裂，映参差、石乳倒悬山。", "那得虚无幻境，元来透澈玄关。", "跻攀。", "竟日忘还。", "空翠滴、逼衣寒。", "想邃宇阴阴，炉存太乙，难觅飞丹。", "泠然洞灵去远，甚千年、都不到人间。", "见说寻真有路，也须容我清闲。"]'),
('song-ci-366','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','["\u6d1e\u5ead\u6e56"]','扁舟忽过芦花浦。',123,'宋词/ci.song.3000.json','["扁舟忽过芦花浦。", "闲情便随鸥去。", "水国吹箫，虹桥问月，西子如今何许。", "危栏谩抚。", "正独立苍茫，半空飞露。", "倒影虚明，洞庭波映广寒府。", "鱼龙吹浪自舞。", "渺然凌万顷，如听风雨。", "夜气浮山，晴晖荡日，一色无寻秋处。", "惊凫自语。", "尚记得当时，故人来否。", "胜景平分，此心游太古。"]'),
('song-ci-367','月下笛','张炎','宋','宋词','song-ci','月下笛','[]','千里行秋，支筇背锦，顿怀清友。',121,'宋词/ci.song.3000.json','["千里行秋，支筇背锦，顿怀清友。", "殊乡聚首。", "爱吟犹自诗瘦。", "山人不解思猿鹤，笑问我、韦娘在否。", "记长堤画舫，花柔春闹，几番携手。", "别后都依旧。", "但靖节门前，近来无柳。", "盟鸥尚有。", "可怜西塞渔叟。", "断肠不恨江南老，恨落叶、飘零最久。", "倦游处，减羁愁，犹未消磨是酒。"]'),
('song-ci-368','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','桃花零落玄都观，刘郎此情谁语。',123,'宋词/ci.song.3000.json','["桃花零落玄都观，刘郎此情谁语。", "鬓发萧疏，襟怀淡薄，空赋天涯羁旅。", "离情万缕。", "第一是难招，旧鸥今雨。", "锦瑟年华，梦中犹记艳游处。", "依依心事最苦。", "片帆浑是月，独抱凄楚。", "屋破容秋，床空对雨，迷却青门瓜圃。", "初荷未暑。", "叹极目烟波，又歌南浦。", "燕忽归来，翠帘深几许。"]'),
('song-ci-369','惜红衣','张炎','宋','宋词','song-ci','惜红衣','[]','两翦秋痕，平分水影，炯然冰洁。',108,'宋词/ci.song.3000.json','["两翦秋痕，平分水影，炯然冰洁。", "未识新愁，眉心倩人贴。", "无端醉里，通一笑、柔花盈睫。", "痴绝。", "不解送情，倚银屏斜瞥。", "长歌短舞，换羽移宫，飘飘步回雪。", "扶娇倚扇，欲把艳怀说。", "□□杜郎重到，只虑空江桃叶。", "但数峰犹在，如傍那家风月。"]'),
('song-ci-370','满江红','张炎','宋','宋词','song-ci','满江红','[]','江上相逢，更秉烛、浑疑梦里。',115,'宋词/ci.song.3000.json','["江上相逢，更秉烛、浑疑梦里。", "寂寞久，瑟弦尘断，为君重理。", "紫绶金章都莫问，醉中□送揶揄鬼。", "看满头、白雪欲消难，春风起。", "云一片，身千里。", "漂泊地，东西水。", "叹十年不见，我生能几。", "慷慨悲歌惊泪落，古人未必皆如此。", "想今人、愁似古人多，如何是。"]'),
('song-ci-371','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','奚囊谢屐。',120,'宋词/ci.song.3000.json','["奚囊谢屐。", "向芙蓉城下，□□游历。", "江上沙鸥何所似，白发飘飘行客。", "旷海乘风，长波垂钓，欲把珊瑚拂。", "近来杨柳，却怜浑是秋色。", "日暮空想佳人，楚芳难赠，烟水分明隔。", "老病孤舟天地里，惟有歌声消得。", "故国荒城，斜阳古道，可奈花狼藉。", "他时一笑，似曾何处相识。"]'),
('song-ci-372','红情・暗香','张炎','宋','宋词','song-ci','红情・暗香','[]','无边香色。',119,'宋词/ci.song.3000.json','["无边香色。", "记涉江自采，锦机云密。", "翦翦红衣，学舞波心旧曾识。", "一见依然似语，流水远、几回空忆。", "看□□、倒影窥妆，玉润露痕湿。", "闲立。", "翠屏侧。", "爱向人弄芳，背酣斜日。", "料应太液。", "三十六宫土花碧。", "清与凌风更爽，无数满汀洲如昔。", "泛片叶、烟浪里，卧横紫笛。"]'),
('song-ci-373','绿意・疏影','张炎','宋','宋词','song-ci','绿意・疏影','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','碧圆自洁。',134,'宋词/ci.song.3000.json','["碧圆自洁。", "向浅洲远渚，亭亭清绝。", "犹有遗簪，不展秋心，能卷几多炎热。", "鸳鸯密语同倾盖，且莫与、浣纱人说。", "恐怨歌、忽断花风，碎却翠云千叠。", "回首当年汉舞，怕飞去、谩皱留仙裙摺。", "恋恋青衫，犹染枯香，还叹鬓丝飘雪。", "盘心清露如铅水，又一夜、西风吹折。", "喜静看、匹练秋光，倒泻半湖明月。"]'),
('song-ci-374','虞美人','张炎','宋','宋词','song-ci','虞美人','[]','黄金谁解教歌舞。',66,'宋词/ci.song.3000.json','["黄金谁解教歌舞。", "留得当时谱。", "断情残意落人间。", "汉上行云迷却、旧巫山。", "妆楼何处寻樊素。", "空误周郎顾。", "一帘秋雨翦灯看。", "无限羁愁分付、玉箫寒。"]'),
('song-ci-375','踏莎行','张炎','宋','宋词','song-ci','踏莎行','[]','清气崖深，斜阳木末。',68,'宋词/ci.song.3000.json','["清气崖深，斜阳木末。", "松风泉水声相答。", "光浮碗面啜先春，何须美酒吴姬压。", "头上乌巾，鬓边白发。", "数间破屋从芜没。", "山中有此玉川人，相思一夜梅花发。"]'),
('song-ci-376','南乡子','张炎','宋','宋词','song-ci','南乡子','[]','晴野事春游。',66,'宋词/ci.song.3000.json','["晴野事春游。", "老去寻诗苦未休。", "一似浣花溪上路，清幽。", "烟草纤纤水自流。", "何处偶迟留。", "犹未忘情是酒筹。", "童子策驴人已醉，知不。", "醉里眉攒万国愁。"]'),
('song-ci-377','临江仙','张炎','宋','宋词','song-ci','临江仙','[]','忆得沈香歌断后，深宫客梦迢遥。',70,'宋词/ci.song.3000.json','["忆得沈香歌断后，深宫客梦迢遥。", "研池残墨溅花妖。", "青山人独自，早不侣渔樵。", "石壁苍寒巾尚挂，松风顶上飘飘。", "神仙那肯混尘嚣。", "诗魂元在此，空向水中招。"]'),
('song-ci-378','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','云冷未全开。',74,'宋词/ci.song.3000.json','["云冷未全开。", "檐冰雨沍苔。", "入花根、暧意先回。", "一夜绿房迎晓白，空忆遍、岭头梅。", "如幻旧情怀。", "寻春上吹台。", "正泥深、十二香街。", "且问谢家池畔草，春必定、几时来。"]'),
('song-ci-379','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','["\u957f\u6c5f"]','步高寒、下观浮远，清晖隔断风雨。',140,'宋词/ci.song.3000.json','["步高寒、下观浮远，清晖隔断风雨。", "醉魂误入滁阳路。", "落莫不知何处。", "栏屡拊。", "又却是，秋城自有芙蓉主。", "重游倦旅。", "对万壑千岩，长江巨浪，空翠洒衣履。", "景如许。", "都被楼台占取。", "晴岚暖霭朝暮。", "乾坤静里闲居赋。", "评泊水经茶谱。", "留胜侣。", "更底用，林泉曳杖寻桑苎。", "休休访古。", "看排闼青来，书床啸咏，莫向惠峰去。"]'),
('song-ci-380','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','["\u6d1e\u5ead\u6e56"]','清时乐事中园赋，怡情楚花湘草。',123,'宋词/ci.song.3000.json','["清时乐事中园赋，怡情楚花湘草。", "秀色通帘，生香聚酒，修景常留池沼。", "闲居自好。", "奈车马喧尘，未教闲了。", "把菊清游，冷红飞下洞庭晓。", "寻泉同步翠杳。", "更将秋共远，书画船小。", "款竹谁家，盟鸥某水，白月光涵圆峤。", "天浮浩渺。", "称绿发飘飘，溯风舒啸。", "缓筑堤沙，渭滨人未老。"]'),
('song-ci-381','华胥引','张炎','宋','宋词','song-ci','华胥引','[]','温泉浴罢，酣酒才苏，洗妆犹湿。',104,'宋词/ci.song.3000.json','["温泉浴罢，酣酒才苏，洗妆犹湿。", "落暮云深，瑶台月下逢太白。", "素衣初染天香，寻东风倾国。", "惆怅东栏，炯然玉树独立。", "只恐江空，顿忘却、锦袍清逸。", "柳迷归院，欲远花妖未得。", "谁写一枝淡雅，傍沈香亭北。", "说与莺莺，怕人错认秋色。"]'),
('song-ci-382','风入松','张炎','宋','宋词','song-ci','风入松','[]','松风掩昼隐深清。',90,'宋词/ci.song.3000.json','["松风掩昼隐深清。", "流水自泠泠。", "一从柯烂归来后，爱弦声。", "不爱枰声。", "颇笑山中散木，翻怜爨下劳薪。", "透云远响正丁丁。", "孤凤划然鸣。", "疑行岭上千秋雪，语高寒、相应何人。", "回首更无寻处，一江风雨潮生。"]'),
('song-ci-383','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','万里一飞篷。',64,'宋词/ci.song.3000.json','["万里一飞篷。", "吟老丹枫。", "潮生潮落海门东。", "三两点鸥沙外月，闲意谁同。", "一色与天通。", "绝去尘红。", "渔歌忽断荻花风。", "烟水自流心不竞，长笛霜空。"]'),
('song-ci-384','夜飞鹊・夜飞鹊慢','张炎','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','林霏散浮暝，河汉空云，都缘水国秋清。',129,'宋词/ci.song.3000.json','["林霏散浮暝，河汉空云，都缘水国秋清。", "绿房一夜迎向晓，海影飞落寒冰。", "蓬莱在何处，但危峰缥缈，玉籁无声。", "文箫素约，料相逢、依旧花阴。", "登眺尚馀佳兴，零露下衣襟，欲醉还醒。", "明月明年此夜，颉颃万里，同此阴晴。", "霓裳梦断，到如今、不许人听。", "正婆娑桂底，谁家弄笛，风起潮生。"]'),
('song-ci-385','风入松','张炎','宋','宋词','song-ci','风入松','[]','晴岚暖翠护烟霞。',90,'宋词/ci.song.3000.json','["晴岚暖翠护烟霞。", "乔木晋人家。", "幽居只恐归图画，唤樵青、多种桑麻。", "门掩推敲古意，泉分冷淡生涯。", "无边风月乐年华。", "留客可茶瓜。", "任他车马虽嫌僻，笑喧喧、流水寒鸦。", "小隐正宜深静，休栽湖上梅花。"]'),
('song-ci-386','石州慢','张炎','宋','宋词','song-ci','石州慢','[]','野色惊秋，随意散愁，踏碎黄叶。',123,'宋词/ci.song.3000.json','["野色惊秋，随意散愁，踏碎黄叶。", "谁家篱院闲花，似语试妆娇怯。", "行行步影，未教背写腰肢，一搦犹立门前雪。", "依约镜中春，又无端轻别。", "痴绝。", "汉皋何处，解佩何人，底须情切。", "空引东邻，遗恨丁香空结。", "十年旧梦，谩馀恍惚云窗，可怜不是当时蝶。", "深夜醉醒来，好一庭风月。"]'),
('song-ci-387','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','百花开后。',54,'宋词/ci.song.3000.json','["百花开后。", "一朵疑堆绣。", "绝色年年常似旧。", "因甚不随春瘦。", "脂痕淡约蜂黄。", "可怜独倚新妆。", "太白醉游何处，定应忘了沈香。"]'),
('song-ci-388','点绛唇','张炎','宋','宋词','song-ci','点绛唇','[]','独殿春光，此花开后无花了。',50,'宋词/ci.song.3000.json','["独殿春光，此花开后无花了。", "丹青人巧。", "不许芳心老。", "密影翻阶，曾为寻诗到。", "竹西好。", "采香歌杳。", "十里红楼小。"]'),
('song-ci-389','卜算子','张炎','宋','宋词','song-ci','卜算子','[]','雅淡浅深黄，顾影敧秋雨。',52,'宋词/ci.song.3000.json','["雅淡浅深黄，顾影敧秋雨。", "碧带犹皴笋指痕，不解擎芳醑。", "休唱古阳关，如把相思铸。", "却忆铜盘露已乾，愁在倾心处。"]'),
('song-ci-390','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','花占枝头忺日焙。',70,'宋词/ci.song.3000.json','["花占枝头忺日焙。", "金汞初抽，火鼎铅华退。", "还似瘢痕涂獭髓。", "胭脂淡抹微酣醉。", "数朵折来春槛外。", "欲染清香，只许梅相对。", "不是临风珠蓓蕾。", "山童隔竹休敲碎。"]'),
('song-ci-391','新雁过妆楼','张炎','宋','宋词','song-ci','新雁过妆楼','[]','遍插茱萸。',119,'宋词/ci.song.3000.json','["遍插茱萸。", "人何处、客里顿懒携壶。", "雁影涵秋，绝似暮雨相呼。", "料得曾留堤上月，旧家伴侣有书无。", "谩嗟吁。", "数声怨抑，翻致无书。", "谁识飘零万里，更可怜倦翼，同此江湖。", "饮啄关心，知是近日何如。", "陶潜尚存菊径，且休羡松风陶隐居。", "沙汀冷，拣寒枝、不似烟水黄芦。"]'),
('song-ci-392','洞仙歌','张炎','宋','宋词','song-ci','洞仙歌','[]','中峰壁立，挂飞来孤剑。',100,'宋词/ci.song.3000.json','["中峰壁立，挂飞来孤剑。", "苍雪纷纷堕晴藓。", "自当年诗酒，客里相逢，春尚好，鸥散烟波茂苑。", "只今谁最老，种玉人间，消得梅花共清浅。", "问我入山期，但恐山深，松风把红尘吹断。", "望蓬莱、知隔几重云，料只隔中间，白云一片。"]'),
('song-ci-393','风入松','张炎','宋','宋词','song-ci','风入松','[]','门前山可久长看。',90,'宋词/ci.song.3000.json','["门前山可久长看。", "留住白云难。", "溪虚却与云相傍，对白云、何必深山。", "爽气潜生树石，晴光竟入栏干。", "旧家三径竹千竿。", "苍雪拂衣寒。", "绿蓑青笠玄真子，钓风波、不是真闲。", "得似壶中日月，依然只在人间。"]'),
('song-ci-394','小重山','张炎','宋','宋词','song-ci','小重山','[]','淡色分山晓气浮。',70,'宋词/ci.song.3000.json','["淡色分山晓气浮。", "疏林犹剩叶，不多秋。", "林深彷佛昔曾游。", "频唤酒，渔屋岸西头。", "不拟此凝眸。", "朦胧清影里，过扁舟。", "行行应到白萍洲。", "烟水冷，传语旧沙鸥。"]'),
('song-ci-395','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','拂袖入山阿。',64,'宋词/ci.song.3000.json','["拂袖入山阿。", "深隐松萝。", "掬流洗耳厌尘多。", "石上一般清意味，不羡渔蓑。", "日月静中过。", "俗□消磨。", "风瓢分付与清波。", "却笑唐求因底事，无奈诗何。"]'),
('song-ci-396','忆王孙','张炎','宋','宋词','song-ci','忆王孙','[]','争棋赌墅意欣然。',36,'宋词/ci.song.3000.json','["争棋赌墅意欣然。", "心似游丝扬碧天。", "只为当时一著玄。", "笑苻坚。", "百万军声屐齿前。"]'),
('song-ci-397','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','秦地瓜分候已故。',70,'宋词/ci.song.3000.json','["秦地瓜分候已故。", "不学渊明，种秫辞归去。", "薄有田园还种取。", "养成碧玉甘如许。", "卜隐青门真得趣。", "蕙帐空闲，鹤怨来何暮。", "莫说蜗名催及戍。", "长安城下锄烟雨。"]'),
('song-ci-398','如梦令','张炎','宋','宋词','song-ci','如梦令','[]','苔径独行清昼。',40,'宋词/ci.song.3000.json','["苔径独行清昼。", "瑟瑟松风如旧。", "出岫本无心，迟种门前杨柳。", "回首。", "回首。", "篱下白衣来否。"]'),
('song-ci-399','丑奴儿・采桑子','张炎','宋','宋词','song-ci','丑奴儿・采桑子','[]','山人去后知何处，风月清虚。',52,'宋词/ci.song.3000.json','["山人去后知何处，风月清虚。", "来往无拘。", "戏引儿孙乐有馀。", "悬崖挂树如相语，常守枯株。", "久与人疏。", "闲了当年一卷书。"]'),
('song-ci-400','浣溪沙','张炎','宋','宋词','song-ci','浣溪沙','[]','空色庄严玉版师。',48,'宋词/ci.song.3000.json','["空色庄严玉版师。", "老斑遮护锦绷儿。", "只愁一夜被风吹。", "润处似沾篔谷雨，斫来如带渭川泥。", "从空托出镇帷犀。"]'),
('song-ci-401','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','辔摇衔铁。',54,'宋词/ci.song.3000.json','["辔摇衔铁。", "蹴踏平原雪。", "勇趁军声曾汗血。", "闲过升平时节。", "茸茸春草天涯。", "涓涓野水晴沙。", "多少骅骝老去，至今犹困盐车。"]'),
('song-ci-402','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','["\u897f\u6e56"]','二分春到柳，青未了，欲婆娑。',124,'宋词/ci.song.3000.json','["二分春到柳，青未了，欲婆娑。", "甚书剑飘零，身犹是客，岁月频过。", "西湖故园在否，怕东风、今日落梅多。", "抱瑟空行古道，盟鸥顿冷清波。", "知麽。", "老子狂歌。", "心未歇，鬓先斑。", "叹敝却貂裘，驱车万里，风雪关河。", "灯前恍疑梦醒，好依然、只著旧渔蓑。", "流水桃花渐暖，酒船不去如何。"]'),
('song-ci-403','长相思','张炎','宋','宋词','song-ci','长相思','[]','去来心。',44,'宋词/ci.song.3000.json','["去来心。", "短长亭。", "只隔中间一片云。", "不知何处寻。", "闷还颦。", "恨还瞋。", "同是天涯流落人。", "此情烟水深。"]'),
('song-ci-404','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','湖上景消磨。',74,'宋词/ci.song.3000.json','["湖上景消磨。", "飘零有梦过。", "问堤边、春事如何。", "可是而今张绪老，见说道、柳无多。", "客里醉时歌。", "寻思安乐窝。", "买扁舟、重缉渔蓑。", "欲趁桃花流水去，又却怕、有风波。"]'),
('song-ci-405','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','一犁初卸。',54,'宋词/ci.song.3000.json','["一犁初卸。", "息影斜阳下。", "角上汉书何不挂。", "老子近来慵跨。", "烟村草树离离。", "卧看流水忘归。", "莫饮山中清味，怕教洗耳人知。"]'),
('song-ci-406','满江红','张炎','宋','宋词','song-ci','满江红','[]','近日衰迟，但随分、蜗涎自足。',115,'宋词/ci.song.3000.json','["近日衰迟，但随分、蜗涎自足。", "底须共、红尘争道，顿荒松菊。", "壮志已荒圯上履，正音恐是沟中木。", "又安知、幕下有词人，归心速。", "书尚在，怜鱼腹。", "珠何处，惊鱼目。", "且依然诗思，灞桥人独。", "不用回头看堕甑，不愁抱石疑非玉。", "忽一声、长啸出山来，黄粱熟。"]'),
('song-ci-407','法曲献仙音','张炎','宋','宋词','song-ci','法曲献仙音','[]','梅失黄昏，雁惊白昼，脉脉斜飞云表。',114,'宋词/ci.song.3000.json','["梅失黄昏，雁惊白昼，脉脉斜飞云表。", "絮不生萍，水疑浮玉，此景正宜舒啸。", "记夜悄、曾乘兴，何必见安道。", "系船好。", "想前村、未知甚处。", "吟思苦，谁游灞桥路杳。", "清饮一瓢寒，又何妨、分傍茶灶。", "野屋萧萧，任楼中、低唱人笑。", "渐东风解冻，怕有桃花流到。"]'),
('song-ci-408','浣溪沙','张炎','宋','宋词','song-ci','浣溪沙','[]','昨夜蓝田采玉游。',48,'宋词/ci.song.3000.json','["昨夜蓝田采玉游。", "向阳瑶草带花收。", "如今风雨不须愁。", "零落依稀倾凿落，碎琼重叠缀搔头。", "白云黄鹤思悠悠。"]'),
('song-ci-409','浣溪沙','张炎','宋','宋词','song-ci','浣溪沙','[]','半面妆凝镜里春。',48,'宋词/ci.song.3000.json','["半面妆凝镜里春。", "同心带舞掌中身。", "因沾弱水褪精神。", "冷艳喜寻梅共笑，枯香羞与佩同纫。", "湘皋犹有未归人。"]'),
('song-ci-410','一枝春','张炎','宋','宋词','song-ci','一枝春','["\u897f\u6e56"]','竹外横枝，并栏干、试数风才一信。',116,'宋词/ci.song.3000.json','["竹外横枝，并栏干、试数风才一信。", "么禽对语，彷佛醉眠初醒。", "遥知是雪，甚都把、暮寒消尽。", "清更润。", "明月飞来，瘦却旧时疏影。", "东阁谩撩诗兴。", "料西湖树老，难认和靖。", "晴窗自好，胜事每来独领。", "融融向暖，笑尘世、万花犹冷。", "须酿成、一点春腴，暗香在鼎。"]'),
('song-ci-411','水调歌头','张炎','宋','宋词','song-ci','水调歌头','[]','白发已如此，岁序更骎骎。',114,'宋词/ci.song.3000.json','["白发已如此，岁序更骎骎。", "化机消息，壮生天籁雍门琴。", "颇笑论文说剑，休问高车驷马，衮衮□黄金。", "蚁在元无梦，水竞不流心。", "绝交书，招隐操，恶圆箴。", "世尘空扰，脱巾挂壁且松阴。", "谁对紫微阁下，我对白萍洲畔，朝市与山林。", "不用一钱买，风月短长吟。"]'),
('song-ci-412','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','聚首不多时。',74,'宋词/ci.song.3000.json','["聚首不多时。", "烟波又别离。", "有黄金、应铸相思。", "折得梅花先寄我，山正在、里湖西。", "风雪脆荷衣。", "休教鸥鹭知。", "鬓丝丝、犹混尘泥。", "何日束书归旧隐，只恐怕、种瓜迟。"]'),
('song-ci-413','南乡子','张炎','宋','宋词','song-ci','南乡子','[]','爱此碧相依。',66,'宋词/ci.song.3000.json','["爱此碧相依。", "卜筑西园隐逸时。", "三径成阴门可款，幽栖。", "苍雪纷纷冷不飞。", "青眼旧心知。", "瘦节终看岁晚期。", "人在清风来往处，吟诗。", "更好梅花著一枝。"]'),
('song-ci-414','朝中措','张炎','宋','宋词','song-ci','朝中措','[]','清明时节雨声哗。',57,'宋词/ci.song.3000.json','["清明时节雨声哗。", "潮拥渡头沙。", "翻被梨花冷看，人生苦恋天涯。", "燕帘莺户，云窗雾阁，酒醒啼鸦。", "折得一枝杨柳，归来插向谁家。"]'),
('song-ci-415','采桑子','张炎','宋','宋词','song-ci','采桑子','[]','西园冷罥秋千索，雨透花颦。',52,'宋词/ci.song.3000.json','["西园冷罥秋千索，雨透花颦。", "雨过花皴。", "近觉江南无好春。", "杜郎不恨寻芳晚，梦里行云。", "陌上行尘。", "最是多愁老得人。"]'),
('song-ci-416','阮郎归','张炎','宋','宋词','song-ci','阮郎归','[]','钿车骄马锦相连。',56,'宋词/ci.song.3000.json','["钿车骄马锦相连。", "香尘逐管弦。", "瞥然飞过水秋千。", "清明寒食天。", "花贴贴，柳悬悬。", "莺房几醉眠。", "醉中不信有啼鹃。", "江南二十年。"]'),
('song-ci-417','浣溪沙','张炎','宋','宋词','song-ci','浣溪沙','[]','艾蒳香消火未残。',48,'宋词/ci.song.3000.json','["艾蒳香消火未残。", "便能晴去不多寒。", "冶游天气却身闲。", "带雨移花浑懒看，应时插柳日须攀。", "最堪惆怅是东栏。"]'),
('song-ci-418','风入松','张炎','宋','宋词','song-ci','风入松','[]','向人圆月转分明。',90,'宋词/ci.song.3000.json','["向人圆月转分明。", "箫鼓又逢迎。", "风吹不老蛾儿闹，绕玉梅、犹恋香心。", "报道依然放夜，何妨款曲行春。", "锦灯重见丽繁星。", "水影动梨云。", "今朝准拟花朝醉，奈今宵、别是光阴。", "帘底听人笑语，莫教迟了□青。"]'),
('song-ci-419','踏莎行','张炎','宋','宋词','song-ci','踏莎行','[]','瑶草收香，琪花采汞。',68,'宋词/ci.song.3000.json','["瑶草收香，琪花采汞。", "冰轮碾处芳尘动。", "竹炉汤暖火初红，玉纤调罢歌声送。", "麾去茶经，袭藏酒颂。", "一杯清味佳宾共。", "从来采药得长生，蓝桥休被琼浆弄。"]'),
('song-ci-420','鹧鸪天','张炎','宋','宋词','song-ci','鹧鸪天','[]','楼上谁将玉笛吹。',64,'宋词/ci.song.3000.json','["楼上谁将玉笛吹。", "山前水阔暝云低。", "劳劳燕子人千里，落落梨花雨一枝。", "修禊近，卖饧时。", "故乡惟有梦相随。", "夜来折得江头柳，不是苏堤也皱眉。"]'),
('song-ci-421','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','[]','又孤吟、灞桥深雪，千山绝尽飞鸟。',140,'宋词/ci.song.3000.json','["又孤吟、灞桥深雪，千山绝尽飞鸟。", "梅花也著东风笑，一夜瘦添多少。", "春悄悄。", "正断梦愁诗，忘却池塘草。", "前村路杳。", "看野水流冰，舟闲渡口，何必见安道。", "慵登眺。", "脉脉霏霏未了。", "寒威犹自清峭。", "终须几日开晴去，无奈此时怀抱。", "空暗恼。", "料酒兴歌情，未肯随人老。", "惜花起早。", "拚醉□忘归，接䍦更好，一笑任倾倒。"]'),
('song-ci-422','满江红','张炎','宋','宋词','song-ci','满江红','[]','老子今年，多准备、吟笺赋笔。',115,'宋词/ci.song.3000.json','["老子今年，多准备、吟笺赋笔。", "还自喜、锦囊添富，顿非畴昔。", "书册琴棋清队仗，云山水竹闲踪迹。", "任醉筇、游屐过平生，千年客。", "回首梦，东隅失。", "乘兴去，桑榆得。", "且怡然一笑，探梅消息。", "天下神仙何处有，神仙只向人间觅。", "折梅花、横挂酒壶归，白鸥识。"]'),
('song-ci-423','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','锦街穿戏鼓，听铁马、响春冰。',124,'宋词/ci.song.3000.json','["锦街穿戏鼓，听铁马、响春冰。", "甚舞绣歌云，欢情未足，早已收灯。", "从今便须胜赏，步青青、野色一枝藤。", "落魄花间酒侣，温存竹里吟朋。", "休憎。", "短发鬅鬙。", "游兴懒、我何曾。", "任蹴踏芳尘，寻蕉覆鹿，自笑无能。", "清狂尚如旧否，倚东风、啸咏古兰陵。", "十里梅花霁雪，水边楼观先登。"]'),
('song-ci-424','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','江南无贺老，看万壑、出清冰。',124,'宋词/ci.song.3000.json','["江南无贺老，看万壑、出清冰。", "想柳思周情，长歌短咏，密与传灯。", "山川润分秀色，称醉挥、健笔剡溪藤。", "一语不谈俗事，几人来结吟朋。", "堪憎。", "我发鬅鬙。", "频赋曲、旧时曾。", "但春蚓秋蛩，寒篱晚砌，颇叹非能。", "何如种瓜种秫，带一锄、归去隐东陵。", "野啸天风两耳，翠微深处孙登。"]'),
('song-ci-425','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','寒食不多时。',64,'宋词/ci.song.3000.json','["寒食不多时。", "燕燕才归。", "杏花零落水痕肥。", "浅碧分山初过雨，一霎晴晖。", "闲折小桃枝。", "蝶也相随。", "晚妆不合整蛾眉。", "蓦忽思量张敞画，又被愁知。"]'),
('song-ci-426','临江仙','张炎','宋','宋词','song-ci','临江仙','[]','一点白鸥何处去，半江潮落沙虚。',70,'宋词/ci.song.3000.json','["一点白鸥何处去，半江潮落沙虚。", "淡黄柳上月痕初。", "暇观情悄悄，凝想步徐徐。", "每一相思千里梦，十年有此相疏。", "休休寄雁问何如。", "如何休寄雁，难写绝交书。"]'),
('song-ci-427','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','绕枝倦鹊，鬓萧萧、肯信如今犹客。',120,'宋词/ci.song.3000.json','["绕枝倦鹊，鬓萧萧、肯信如今犹客。", "风雪荷衣寒叶补，一点灯花悬壁。", "万里舟车，十年书剑，此意青天识。", "泛然身世，故家休问清白。", "却笑醉倒衰翁，石床飞梦，不入槐安国。", "只恐溪山游未了，莫叹飘零南北。", "滚滚江横，呜呜歌罢，渺渺情何极。", "正无聊赖，天风吹下孤笛。"]'),
('song-ci-428','谒金门','张炎','宋','宋词','song-ci','谒金门','[]','晚晴薄。',53,'宋词/ci.song.3000.json','["晚晴薄。", "一片杏花零落。", "纵是东风浑未恶。", "二分春过却。", "可怪寒生池阁。", "下了重重帘幕。", "忽见旧巢还是错。", "燕归何处著。"]'),
('song-ci-429','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','采芳人杳。',54,'宋词/ci.song.3000.json','["采芳人杳。", "顿觉游情少。", "客里看春多草草。", "总被诗愁分了。", "去年燕子天涯。", "今年燕子谁家。", "三月休听夜雨，如今不是催花。"]'),
('song-ci-430','渔家傲','张炎','宋','宋词','song-ci','渔家傲','[]','门掩新阴孤馆静。',71,'宋词/ci.song.3000.json','["门掩新阴孤馆静。", "杨花却解来相趁。", "几日方知因酒病。", "无憀甚。", "脱巾挂壁将书枕。", "见说红堆满径。", "不知何处游人盛。", "自笑扁舟犹未定。", "清和近。", "寻诗已约兰陵令。"]'),
('song-ci-431','渔家傲','张炎','宋','宋词','song-ci','渔家傲','[]','辛苦移家聊处静。',72,'宋词/ci.song.3000.json','["辛苦移家聊处静。", "扫除花径歌声趁。", "也学维摩闲示病。", "迂疏甚。", "松风两耳和衣枕。", "颇倦扶筇寻捷径。", "东墙蔼蔼红香盛。", "少待摇人波自定。", "蓬壶近。", "且呼白鹤招韩令。"]'),
('song-ci-432','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','苔根抱古，透阳春、挺挺林间英物。',120,'宋词/ci.song.3000.json','["苔根抱古，透阳春、挺挺林间英物。", "隔水笛声那得到，斜日空明绝壁。", "半树篱边，一枝竹外，冷艳凌苍雪。", "淡然相对，万花无此清杰。", "还念庾岭幽情，江南聊折，赠行人应发。", "寂寂西窗闲弄影，深夜寒灯明灭。", "且浸芳壶，休簪短帽，照见萧萧发。", "几时归去，朗吟湖上香月。"]'),
('song-ci-433','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','["\u6d1e\u5ead\u6e56"]','曾记宴蓬壶。',74,'宋词/ci.song.3000.json','["曾记宴蓬壶。", "寻思认得无。", "醉归来、事已模糊。", "忽对画图如梦寐，又因甚、下清都。", "拍手笑相呼。", "应书缩地符。", "恐人间、天上同途。", "隔水一声何处笛，正月满、洞庭湖。"]'),
('song-ci-434','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','丹丘瑶草。',54,'宋词/ci.song.3000.json','["丹丘瑶草。", "不许秋风扫。", "记得对花曾被恼。", "犹似前时春好。", "湘皋闲立双清。", "相看波冷无声。", "独说长生未老，不知老却梅兄。"]'),
('song-ci-435','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','回首欲婆娑。',64,'宋词/ci.song.3000.json','["回首欲婆娑。", "淡扫修蛾。", "盈盈不语奈情何。", "应恨梅兄矾弟远，云隔山阿。", "弱水夜寒多。", "带月曾过。", "羽衣飞过染馀波。", "白鹤难招归未得，天阔星河。"]'),
('song-ci-436','西江月','张炎','宋','宋词','song-ci','西江月','[]','缥缈波明洛浦，依稀玉立湘皋。',58,'宋词/ci.song.3000.json','["缥缈波明洛浦，依稀玉立湘皋。", "独将兰蕙入离骚。", "不识山中瑶草。", "月照英翘楚楚，江空醉魄陶陶。", "犹疑颜色尚清高。", "一笑出门春老。"]'),
('song-ci-437','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','异乡倦旅，问扁舟东下，归期何日。',120,'宋词/ci.song.3000.json','["异乡倦旅，问扁舟东下，归期何日。", "琴剑空随身万里，天地谁非行客。", "李杜飘零，羊昙悲感，回首俱陈迹。", "羁怀难写，豆虫吟破孤寂。", "柳外门掩疏阴，佳人何处，溪上苹花白。", "留得一方无用月，隐隐山阳闻笛。", "旧雨不来，风流云散，惟有长相忆。", "雁书休寄，寸心分付梅驿。"]'),
('song-ci-438','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','["\u897f\u6e56"]','听江湖、夜雨十年灯，孤影尚中州。',119,'宋词/ci.song.3000.json','["听江湖、夜雨十年灯，孤影尚中州。", "对荒凉茂苑，吟情渺渺，心事悠悠。", "见说寒梅犹在，无处认西楼。", "招取楼边月，同载扁舟。", "明日琴书何处，正风前堕叶，草外闲鸥。", "甚消磨不尽，惟有古今愁。", "总休问、西湖南浦，渐春来、烟水入天流。", "清游好，醉招黄鹤，一啸清秋。"]'),
('song-ci-439','风入松','张炎','宋','宋词','song-ci','风入松','[]','爱闲能有几人来。',90,'宋词/ci.song.3000.json','["爱闲能有几人来。", "松下独徘徊。", "清虚冷淡神仙事，笑名场、多少尘埃。", "漱齿石边危坐，洗心易里舒怀。", "划然长啸白云堆。", "更待月明□。", "一瓢春水山中饮，喜无人、踏破苍苔。", "开了桃花半树，此游不是天台。"]'),
('song-ci-440','风入松','张炎','宋','宋词','song-ci','风入松','[]','一瓢饮水曲肱眠。',90,'宋词/ci.song.3000.json','["一瓢饮水曲肱眠。", "此乐不知年。", "今朝忽上龙峰顶，却原来、有此甘泉。", "洗却平生尘土，慵游万里山川。", "照人如鉴止如渊。", "古窦暗涓涓。", "当时桑苎今何在，想松风、吹断茶烟。", "著我白云堆里，安知不是神仙。"]'),
('song-ci-441','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','玉立水云乡。',64,'宋词/ci.song.3000.json','["玉立水云乡。", "尔我相忘。", "披离寒羽庇风霜。", "不趁白鸥游海上，静看鱼忙。", "应笑我凄凉。", "客路何长。", "犹将孤影侣斜阳。", "花底鹓行无认处，却对秋塘。"]'),
('song-ci-442','菩萨蛮','陈义','宋','宋词','song-ci','菩萨蛮','[]','天生体态腰肢细。',52,'宋词/ci.song.3000.json','["天生体态腰肢细。", "新词唱彻歌声利。", "出口便清奇。", "扬尘簌簌飞。", "主人恩义重。", "宴出红妆宠。", "便要赏新荷。", "时光也不多。"]'),
('song-ci-443','菩萨蛮','陈义','宋','宋词','song-ci','菩萨蛮','[]','去年共饮菖蒲酒。',52,'宋词/ci.song.3000.json','["去年共饮菖蒲酒。", "今年却向僧房守。", "好事更多磨。", "教人没奈何。", "主人恩义重。", "知我心头痛。", "待要赏新荷。", "争知疾愈麽。"]'),
('song-ci-444','满庭芳','梅娇','宋','宋词','song-ci','满庭芳','[]','一种阳和，玉英初纵，雪天分外精神。',114,'宋词/ci.song.3000.json','["一种阳和，玉英初纵，雪天分外精神。", "冰肌肉骨，别是一家春。", "楼上笛声三弄，百花都未知音。", "明窗畔，临风对月，曾结岁寒盟。", "笑杏花何太晚，迟疑不发，等待春深。", "只宜远望，举目似烧林。", "丽质芳姿虽好，一时取媚东君。", "争如我，青青结子，金鼎内调羹。"]'),
('song-ci-445','满庭芳','杏俏','宋','宋词','song-ci','满庭芳','[]','景傍清明，日和风暖，数枝浓淡胭脂。',117,'宋词/ci.song.3000.json','["景傍清明，日和风暖，数枝浓淡胭脂。", "春来早起，惟我独芳菲。", "门外几番雨过，似佳人、细腻香肌。", "堪赏处，玉楼人醉，斜插满头归。", "梅花何太早，消疏骨肉，叶密花稀。", "不逢媚景，开后甚孤栖。", "恐怕百花笑你，甘心受、雪压霜欺。", "争如我，年年得意，占断踏青时。"]'),
('song-ci-446','飞龙宴','苏小娘','宋','宋词','song-ci','飞龙宴','[]','炎炎暑气时，流光闪烁，闲扃深院。',120,'宋词/ci.song.3000.json','["炎炎暑气时，流光闪烁，闲扃深院。", "水阁凉亭，半开帘幕遥观。", "灼灼榴花吐艳。", "细雨洒、小荷香浅。", "树影竹影，清凉潇洒，枕簟摇纨扇。", "堪叹浮世忙如箭。", "对良辰欢乐，莫辞频劝。", "遇酒逢歌，恣情遂意迷恋。", "须信人生聚散。", "奈区区、利牵名绊。", "少年未倦。", "良天皓月金尊满。"]'),
('song-ci-447','踏莎行','张魁','宋','宋词','song-ci','踏莎行','[]','凤髻堆鸦，香酥莹腻。',68,'宋词/ci.song.3000.json','["凤髻堆鸦，香酥莹腻。", "雨中花占街前地。", "弓鞋湿透立多时，无人为问深深意。", "眉上新愁，手中文字。", "如何不倩鳞鸿去。", "想伊只诉薄情人，官中不管闲公事。"]'),
('song-ci-448','声声慢','张枢密','宋','宋词','song-ci','声声慢','[]','星冠懒带，鹤氅慵披，色心顿起兰房。',119,'宋词/ci.song.3000.json','["星冠懒带，鹤氅慵披，色心顿起兰房。", "离了三清归去，作个新郎。", "良宵自有佳景，更烧甚、清香德香。", "瑶台上，便玉皇亲诏，也则寻常。", "常观里、孤孤令令，争如赴鸳闱，夜夜成双。", "救苦天尊，你且远离他方。", "更深酒阑歌罢，殢玉人、云雨交相。", "问则甚，咱门这里拜章。"]'),
('song-ci-449','踏莎行','申二官人','宋','宋词','song-ci','踏莎行','[]','葱草身才、灯心脚手。',68,'宋词/ci.song.3000.json','["葱草身才、灯心脚手。", "闲时与蝶花间走。", "有时跌倒屋檐头，蜘蛛网里翻筋斗。", "水马驰来，藕丝缠就。", "鹅毛般上三杯酒。", "等闲试把秤儿秤，平盘分上何曾有。"]'),
('song-ci-450','失调名','杨岛仙','宋','宋词','song-ci','失调名','[]','待得团圆时候，樽前问这时节。',14,'宋词/ci.song.3000.json','["待得团圆时候，樽前问这时节。"]'),
('song-ci-451','失调名','吴德远','宋','宋词','song-ci','失调名','[]','过平康巷陌绮罗丛。',24,'宋词/ci.song.3000.json','["过平康巷陌绮罗丛。", "赢得佳人，妙舞艳歌，争劝金锺。"]'),
('song-ci-452','失调名','连静女','宋','宋词','song-ci','失调名','[]','朦胧月影，黯淡花阴，独立等多时。',126,'宋词/ci.song.3000.json','["朦胧月影，黯淡花阴，独立等多时。", "只恐冤家误约，又怕他、侧近人知。", "千回作念，万般思忆，心下暗猜疑。", "蓦地偷来厮见，抱著郎、语颤声低。", "轻移莲步，暗褪罗裳，携手过廊西。", "已是更阑人静，粉郎恣意怜伊。", "霎时云雨，半晌欢娱，依旧两分飞。", "去也回眸告道，待等奴、兜上鞋儿。"]'),
('song-ci-453','武陵春','连静女','宋','宋词','song-ci','武陵春','[]','人道有情须有梦，无梦岂无情。',56,'宋词/ci.song.3000.json','["人道有情须有梦，无梦岂无情。", "夜夜相思直到明。", "有梦怎生成。", "伊若忽然来梦里，邻笛又还惊。", "笛里声声不忍听。", "浑是断肠声。"]'),
('song-ci-454','生查子','楚娘','宋','宋词','song-ci','生查子','[]','去年梅雪天，千里人归远。',48,'宋词/ci.song.3000.json','["去年梅雪天，千里人归远。", "今岁雪梅天，千里人追怨。", "铁石作心肠，铁石刚犹软。", "江海比君恩，江海深犹浅。"]'),
('song-ci-455','南歌子','谢福娘','宋','宋词','song-ci','南歌子','[]','闲傍药栏西。',66,'宋词/ci.song.3000.json','["闲傍药栏西。", "正是春光三月时。", "深紫浅红光照眼，依稀。", "有似西施醉枕敧。", "摘放胆瓶儿。", "冷艳幽光映酒卮。", "曾记古人题品语，祆知。", "今夜花王得艳妻。"]'),
('song-ci-456','南歌子','张时','宋','宋词','song-ci','南歌子','[]','暖日未斜西。',66,'宋词/ci.song.3000.json','["暖日未斜西。", "正是迷花殢酒时。", "红药雕阑呈冷艳，依稀。", "花重枝柔压半敧。", "相对耍猴儿。", "一捻幽芳劝酒卮。", "魏紫姚黄来觑着，方知。", "准拟今宵醉伴妻。"]'),
('song-ci-457','人月圆','双渐','宋','宋词','song-ci','人月圆','[]','碧纱低映秦娥面，咫尺暗香浓。',59,'宋词/ci.song.3000.json','["碧纱低映秦娥面，咫尺暗香浓。", "瑶池春晚，长天共恨，烟锁芙蓉。", "夭桃再赏，流莺声巧，不待春工。", "樽前潜想，樱桃破处，得似香红。"]'),
('song-ci-458','鹧鸪天','黄夫人','宋','宋词','song-ci','鹧鸪天','[]','先自春光似酒浓。',64,'宋词/ci.song.3000.json','["先自春光似酒浓。", "时听莺语透帘栊。", "小桥杨柳飘香絮，山寺绯桃散落红。", "莺渐老，蝶西东。", "春归难觅恨无穷。", "侵阶草色迷朝雨，满地梨花逐晓风。"]'),
('song-ci-459','醉亭楼','刘使君','宋','宋词','song-ci','醉亭楼','[]','平生性格，随分好些春色。',96,'宋词/ci.song.3000.json','["平生性格，随分好些春色。", "沉醉恋花陌。", "虽然年老心未老，满头花压巾帽侧。", "鬓如霜，须似雪，自嗟恻。", "几个相知劝我染，几个相知劝我摘。", "染摘有何益。", "当初怕成短命鬼，如今已过中年客。", "且留些，妆晚景，尽教白。"]'),
('song-ci-460','浣溪沙','李氏2','宋','宋词','song-ci','浣溪沙','[]','无力蔷薇带雨低。',48,'宋词/ci.song.3000.json','["无力蔷薇带雨低。", "多情蝴蝶趁花飞。", "流水飘香乳燕啼。", "南浦魂销春不管，东阳衣减镜仙知。", "小楼今夜月依依。"]'),
('song-ci-461','失调名','朱希真','宋','宋词','song-ci','失调名','[]','苦汝临期话别，与君挽手叮咛。',79,'宋词/ci.song.3000.json','["苦汝临期话别，与君挽手叮咛。", "归期誓约十馀朝，去后又经三四月，鱼沉雁杳，空倚著六曲阑干。", "凤只鸾孤，谩独宿半床衾枕。", "欲寄花牌传密意，奈无黄耳堪凭。", "待修锦字诉离情。"]'),
('song-ci-462','采桑子','朱希真','宋','宋词','song-ci','采桑子','[]','王孙去后无芳草，绿遍书阶。',63,'宋词/ci.song.3000.json','["王孙去后无芳草，绿遍书阶。", "尘满妆台。", "粉面羞搽泪满腮。", "教我甚情怀。", "去时梅蕊全然少，等到花开花已成梅。", "梅子青青又待黄。", "兀自未归来。"]'),
('song-ci-463','一翦梅','张幼谦','宋','宋词','song-ci','一翦梅','[]','同年同日又同窗。',72,'宋词/ci.song.3000.json','["同年同日又同窗。", "不似鸾凰。", "谁似鸾凰。", "石榴树下事匆忙。", "惊散鸳鸯。", "拆散鸳鸯。", "一年不到读书堂。", "教不思量。", "怎不思量。", "朝朝暮暮只烧香。", "有分成双。", "愿早成双。"]'),
('song-ci-464','长相思','张幼谦','宋','宋词','song-ci','长相思','[]','天有神。',44,'宋词/ci.song.3000.json','["天有神。", "地有神。", "海誓山盟字字真。", "如今墨尚新。", "过一春。", "又一春。", "不解金钱变作银。", "如何忘却人。"]'),
('song-ci-465','卜算子','张幼谦','宋','宋词','song-ci','卜算子','[]','去时不由人，归怎由人也。',52,'宋词/ci.song.3000.json','["去时不由人，归怎由人也。", "罗带同心结到成，底事教┾舍。", "心是十分真，情没些儿假。", "若道归迟打棹篦，甘受三千下。"]'),
('song-ci-466','卜算子','罗惜惜','宋','宋词','song-ci','卜算子','[]','幸得那人归，怎便教来也。',52,'宋词/ci.song.3000.json','["幸得那人归，怎便教来也。", "一日相思十二辰，真是情难舍。", "本是好因缘，又怕因缘假。", "若是教随别个人，相见黄泉下。"]'),
('song-ci-467','应景乐','萧回','宋','宋词','song-ci','应景乐','["\u957f\u6c5f"]','金陵故国。',97,'宋词/ci.song.3000.json','["金陵故国。", "极目长江浩渺，千重隔。", "山无际，临湍怒涛碛。", "俯春城苇寂。", "芳昼迤逦，一簇烟村将晚，严光旧台侧。", "何处倦游客。", "对此景惹起离怀，顿觉旧日意，魂黯愁积。", "幽恨绵绵，何计消溺。", "回首洛城东，千里暮云碧。"]'),
('song-ci-468','阮郎归','春娘','宋','宋词','song-ci','阮郎归','[]','胡虏中原乱似麻。',58,'宋词/ci.song.3000.json','["胡虏中原乱似麻。", "此景依稀似永嘉。", "丁珠片玉落泥沙。", "何时返翠华。", "呈祥鸾凤失仙槎。", "因循离恨加。", "前生应是负偿他。", "思量无岸涯。"]'),
('song-ci-469','西江月','张生2','宋','宋词','song-ci','西江月','[]','一望朱楼巧小，四边绣幕低垂。',58,'宋词/ci.song.3000.json','["一望朱楼巧小，四边绣幕低垂。", "个人活脱似杨妃。", "倚遍阑干十二。", "最苦两双情眼，难禁四只愁眉。", "无言回首日沉西。", "不道一声安置。"]'),
('song-ci-470','小重山','张生2','宋','宋词','song-ci','小重山','[]','杏火无烟烧断肠。',70,'宋词/ci.song.3000.json','["杏火无烟烧断肠。", "织成春恨切，柳丝长。", "当时谁是种花郎。", "却不教，柳近杏花傍。", "柳道不须忙。", "春深须是有，絮飞扬。", "等闲扑着杏腮香。", "恁时节，选甚隔池塘。"]'),
('song-ci-471','西江月','郑云娘','宋','宋词','song-ci','西江月','[]','一片冰轮皎洁，十分桂魄婆娑。',58,'宋词/ci.song.3000.json','["一片冰轮皎洁，十分桂魄婆娑。", "不施方便是何如。", "莫是嫦娥妒我。", "虽则清光可爱，奈缘好事多磨。", "仗谁传与片云呵。", "遮取霎时则个。"]'),
('song-ci-472','减字木兰花','吕岩','宋','宋词','song-ci','减字木兰花','[]','暂游大庾。',52,'宋词/ci.song.3000.json','["暂游大庾。", "白鹤飞来谁共语。", "岭畔人家。", "曾见寒梅几度花。", "春来春去。", "人在落花流水处。", "花满前溪。", "藏尽神仙人不知。"]'),
('song-ci-473','渔家傲','吕岩','宋','宋词','song-ci','渔家傲','[]','二月江南山水路。',36,'宋词/ci.song.3000.json','["二月江南山水路。", "李花零落春无主。", "一个鱼儿无觅处。", "风和雨。", "玉龙生甲归天去。"]'),
('song-ci-474','望江南・忆江南','吕岩','宋','宋词','song-ci','望江南・忆江南','[]','瑶池上，瑞雾霭群仙。',64,'宋词/ci.song.3000.json','["瑶池上，瑞雾霭群仙。", "素练金童锵凤板，青衣玉女啸鸾笙。", "身在大罗天。", "沉醉处，缥缈玉京山。", "唱彻步虚清燕罢，不知今夕是何年。", "海水又桑田。"]'),
('song-ci-475','梧桐影','吕岩','宋','宋词','song-ci','梧桐影','[]','落日斜，西风冷。',24,'宋词/ci.song.3000.json','["落日斜，西风冷。", "幽人今夜来不来，教人立尽梧桐影。"]'),
('song-ci-476','促拍满路花','吕岩','宋','宋词','song-ci','促拍满路花','["\u5e90\u5c71"]','秋风吹渭水，落叶满长安。',105,'宋词/ci.song.3000.json','["秋风吹渭水，落叶满长安。", "黄尘车马道、独清闲。", "自然炉鼎，虎绕与龙盘。", "九转丹砂就，琴心三叠，蕊宫看舞胎仙。", "任万钉、宝带貂蝉。", "富贵欲薰天。", "黄粱炊未熟、梦惊残。", "是非海里，直道作人难。", "袖手江南去，白苹红寥，又寻湓浦庐山。"]'),
('song-ci-477','沁园春','吕岩','宋','宋词','song-ci','沁园春','[]','七返还丹，在人先须，炼已待时。',140,'宋词/ci.song.3000.json','["七返还丹，在人先须，炼已待时。", "正一阳初动，中宵漏永，温温铅鼎，光透帘帏。", "造化争驰，虎龙交合，进火工夫犹斗危。", "曲江上，看月华莹静，有个乌飞。", "当时。", "自饮刀圭。", "又谁信无中养就儿。", "辨水源清浊，木金间隔，不因师指，此事难知。", "道要玄微，天机深远，下手速修犹太迟。", "蓬莱路，仗三千行满，动步云归。"]'),
('song-ci-478','浪淘沙','吕岩','宋','宋词','song-ci','浪淘沙','[]','我有屋三间。',64,'宋词/ci.song.3000.json','["我有屋三间。", "柱用八山。", "周回四壁海遮拦。", "万象森罗为斗栱，瓦盖青天。", "无漏得多年。", "结就因缘。", "修成功行满三千。", "降得火龙伏得虎，陆地通仙。"]'),
('song-ci-479','失调名','吕岩','宋','宋词','song-ci','失调名','[]','别无巧妙，与你方儿一个。',38,'宋词/ci.song.3000.json','["别无巧妙，与你方儿一个。", "子后午前定息坐。", "夹脊双门昆仑过。", "恁时得气力，思量我。"]'),
('song-ci-480','步蟾宫','吕岩','宋','宋词','song-ci','步蟾宫','[]','坎离乾兑分子午。',60,'宋词/ci.song.3000.json','["坎离乾兑分子午。", "但认取、自家宗祖。", "炼甲庚、更降龙虎。", "地雷震动山头雨。", "要浇灌、黄芽出土。", "有人若问是谁传，但说道、先生姓吕。"]'),
('song-ci-481','西江月','吕岩','宋','宋词','song-ci','西江月','[]','落日数声啼鸟，香风满路吹花。',58,'宋词/ci.song.3000.json','["落日数声啼鸟，香风满路吹花。", "道人邀我煮新茶。", "荡涤胸中潇洒。", "世事不堪回首，梦魂犹绕天涯。", "凤停桥畔即吾家，管甚月明今夜。"]'),
('song-ci-482','沁园春','吕岩','宋','宋词','song-ci','沁园春','[]','琳馆清标，琼台丽质，何年天上飞来。',118,'宋词/ci.song.3000.json','["琳馆清标，琼台丽质，何年天上飞来。", "扬州暂倚，后土为深栽。", "独立乾坤一树，春风占、万朵齐开。", "天然巧，蕊珠圆簇，玉瓣轻裁。", "见一花九朵，类玲珑玉斝，错落琼杯。", "得满盛香露，洗荡尘埃。", "是真元孕育，有仙风道骨，岂是凡胎。", "问真宰，难留下土，携而上蓬莱。"]'),
('song-ci-483','失调名','海哥','宋','宋词','song-ci','失调名','[]','海哥风措。',63,'宋词/ci.song.3000.json','["海哥风措。", "被渔人、下网打住。", "将在帝城中，每日教言语。", "甚时节、放我归去。", "龙王传语。", "这里思量你。", "千回万度。", "螃蟹最恓惶，鲇鱼尤忧虑。"]'),
('song-ci-484','八声甘州','何仙姑','宋','宋词','song-ci','八声甘州','[]','千门万户，尽七颠八倒，掘地寻天。',130,'宋词/ci.song.3000.json','["千门万户，尽七颠八倒，掘地寻天。", "真个玄妙，返作笑胡言。", "无为大道人行少，向捏怪途中有万千。", "伤感。", "蜣转却做灵丹。", "无奈伤嗟最苦，又不知端的，枉弃了家缘。", "时间清净，岂解汞收铅。", "心思意想，何曾遣暂合眼。", "阴魔作睡缠。", "展转。", "越思深返作仇冤。", "谁信无中生有，有中生无，万派归源。"]'),
('song-ci-485','蝶恋花','宋媛','宋','宋词','song-ci','蝶恋花','[]','云破蟾光穿晓户。',70,'宋词/ci.song.3000.json','["云破蟾光穿晓户。", "敧枕凄凉，多少伤心处。", "惟有相思情最苦。", "檀郎咫尺千山阻。", "莫学飞花兼落絮。", "摇荡春风，迤逦抛人去。", "结尽寸肠千万缕。", "如今认得先辜负。"]'),
('song-ci-486','阮郎归','宋媛','宋','宋词','song-ci','阮郎归','[]','东风成阵送春归。',56,'宋词/ci.song.3000.json','["东风成阵送春归。", "庭花高下飞。", "柔条缭绕入帘帏。", "斑斑装舞衣。", "云鬓乱，坐偷啼。", "郎来何负期。", "人生恰似这芳菲。", "芳菲能几时。"]'),
('song-ci-487','清平乐令・清平乐','吴城小龙女','宋','宋词','song-ci','清平乐令・清平乐','[]','帘卷曲栏独倚。',54,'宋词/ci.song.3000.json','["帘卷曲栏独倚。", "江展暮天无际。", "泪眼不曾晴，家在吴头楚尾。", "数点雪花乱委。", "扑漉沙鸥惊起。", "诗句欲成时，没入苍烟丛里。"]'),
('song-ci-488','望江南・忆江南','蔡真人','宋','宋词','song-ci','望江南・忆江南','[]','阑干曲，红扬绣帘旌。',64,'宋词/ci.song.3000.json','["阑干曲，红扬绣帘旌。", "花嫩不禁纤手捻，被风吹去意还惊。", "眉黛蹙山青。", "铿铁板，闲引步虚声。", "尘世无人知此曲，却骑黄鹤上瑶京。", "风冷月华清。"]'),
('song-ci-489','烛影摇红','懒堂女子','宋','宋词','song-ci','烛影摇红','[]','绿净湖光，浅寒先到芙蓉岛。',116,'宋词/ci.song.3000.json','["绿净湖光，浅寒先到芙蓉岛。", "谢池幽梦属才郎，几度生春草。", "尘世多情易老。", "更那堪、秋风袅袅。", "晓来羞对，香芷汀洲，枯荷池沼。", "恨锁横波，远山浅黛无人扫。", "湘江人去叹无依，此意从谁表。", "喜趁良宵月皎。", "况难逢、人间两好。", "莫辞沉醉，醉入屏山，只愁天晓。"]'),
('song-ci-490','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','瑶阙琼宫，高枕巫山十二。',115,'宋词/ci.song.3000.json','["瑶阙琼宫，高枕巫山十二。", "睹瞿塘、千载滟滟云涛沸。", "异景无穷好，闲吟满酌金卮。", "忆前时。", "楚襄王，曾来梦中相会。", "吾正鬓乱钗横，敛霞衣云缕。", "向前低揖。", "问我仙职。", "桃杏遍开，绿草萋萋铺地。", "燕子来时，向巫山、朝朝行雨暮行云，有闲时，只恁画堂高枕。"]'),
('song-ci-491','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','绕绕云梯，上彻青霄霞外。',92,'宋词/ci.song.3000.json','["绕绕云梯，上彻青霄霞外。", "与诸仙同饮，镇长春醉。", "虎啸猿吟，碧桃香异风飘细。", "希奇。", "想人间难识，这般滋味。", "姮娥奏乐箫韶，有仙音异品，自然清脆。", "遏住行云不敢飞。", "空凝滞。", "好是波澜澄湛，一溪香水。"]'),
('song-ci-492','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','山染青螺缥渺，人间难陟。',101,'宋词/ci.song.3000.json','["山染青螺缥渺，人间难陟。", "有珍珠光照，昼夜无休息。", "仙景无极。", "欲言时。", "汝等何知。", "且修心，要观游，亦非。", "大段难易。", "下俯浮生，尚自争名逐利。", "岂不省，来岁扰扰兵戈起。", "天惨云愁，念时衰如何是。", "使我辈、终日蓬宫下泪。"]'),
('song-ci-493','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','再启诸公，百岁还如电急。',92,'宋词/ci.song.3000.json','["再启诸公，百岁还如电急。", "高名显位瞬息尔。", "泛水轻沤，霎那间、难久立。", "画烛当风里。", "安能久之。", "速往茅峰割爱，休名避世。", "等功成、须有上真相引指。", "放死求生，施良药、功无比。", "千万记。", "此个奇方第一。"]'),
('song-ci-494','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','方结实累累。',92,'宋词/ci.song.3000.json','["方结实累累。", "翠枝交映，蟠桃颗颗，仙味真香美。", "遂命双成，持灵刀割来，耳服一粒，令我延年万岁。", "堪笑东方，便启私心盗饵。", "使宫中仙伴，递互相尤殢。", "无奈双成，向王母高陈之。", "遂指方，偷了蟠桃是你。"]'),
('song-ci-495','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','紫云绛霭，高拥瑶砌。',95,'宋词/ci.song.3000.json','["紫云绛霭，高拥瑶砌。", "晓光中、无限剖列。", "肃整天仙队。", "又有殊音欲举，声还止。", "朝罢时。", "亦有清香飘世。", "玉驾才兴，高上真仙尽退。", "有琼花如雪，散漫飞空里。", "玉女金童，捧丹文、传仙诲。", "抚诸仙，早起劳卿过耳。"]'),
('song-ci-496','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','光阴奇。',95,'宋词/ci.song.3000.json','["光阴奇。", "扶桑宫里。", "日月常昼，风物鲜明可爱。", "无阴晦。", "大帝频銮於瑶池。", "朱阑外，乘凤飞。", "教主开颜命醉。", "宝乐齐吹。", "尽是琼姿天妓。", "每三杯，须用圣母亲来揖。", "异果名花几千般，香盈袂。", "意欲归。", "却乘鸾车凤翼。"]'),
('song-ci-497','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','显焕明霞，万丈祥云高布，望仙官衣带，曳曳临香砌。',96,'宋词/ci.song.3000.json','["显焕明霞，万丈祥云高布，望仙官衣带，曳曳临香砌。", "玉兽齐焚，满高穹、盘龙势。", "大帝起。", "玉女金童遍侍。", "奉敕宣言，甚荷诸仙厚意。", "复回奏，感恩顿首皆躬袂。", "奏毕还宫，尚依然云霞密，奇更异。", "非我君，何闻耳。"]'),
('song-ci-498','惜奴娇','巫山神女','宋','宋词','song-ci','惜奴娇','[]','吾归矣。',93,'宋词/ci.song.3000.json','["吾归矣。", "仙宫久离。", "洞户无人管之。", "专俟吾归。", "欲要开金燧。", "千万频修己。", "言讫无忘之。", "哩囉哩。", "此去无由再至。", "事冗难言，尔辈须能自会。", "汝之言，还便是如吾意。", "大抵方寸平平，无忧耳。", "虽改易之。", "愁何畏。"]'),
('song-ci-499','浪淘沙','玉英','宋','宋词','song-ci','浪淘沙','[]','塞上早春时。',64,'宋词/ci.song.3000.json','["塞上早春时。", "暖律犹微。", "柳舒金线拂回堤。", "料得江乡应更好，开尽梅溪。", "昼漏渐迟迟。", "愁损仙机。", "几回无语敛双眉。", "凭遍阑干十二曲，日下楼西。"]'),
('song-ci-500','白苎','紫姑','宋','宋词','song-ci','白苎','[]','绣帘垂，画堂悄，寒风淅沥。',152,'宋词/ci.song.3000.json','["绣帘垂，画堂悄，寒风淅沥。", "遥天万里，黯淡同云幂幂。", "渐纷纷、六花零乱散空碧。", "姑射宴瑶池，把碎玉、零珠抛掷。", "林峦望中，高下琼瑶一白。", "严子陵钓台迷踪迹。", "追惜。", "燕然画角，宝钥珊瑚，是时丞相，虚作银城换得。", "当此际、偏宜访袁安宅。", "醺醺醉了，任他金钗舞困，玉壶频侧。", "又是东君，暗遣花神，先报南国。", "昨夜江梅，漏泄春消息。"]'),
('song-ci-501','望江南・忆江南','清源真君','宋','宋词','song-ci','望江南・忆江南','[]','才举意，玄象照离宫。',64,'宋词/ci.song.3000.json','["才举意，玄象照离宫。", "坎女离男金水火，几多铁骑漫英雄。", "最苦是云中。", "辽阳鹤，惊起老苍龙。", "四海九州沾惠泽，狼烟影里弄清风。", "堪作主人公。"]'),
('song-ci-502','木兰花・玉楼春','李季萼','宋','宋词','song-ci','木兰花・玉楼春','[]','东风忽起黄昏雨。',64,'宋词/ci.song.3000.json','["东风忽起黄昏雨。", "红紫飘残香满路。", "凭阑空有惜春心，浓绿满枝无处诉。", "春光背我堂堂去。", "纵有黄金难买住。", "欲将春去问残花，花亦不言春已暮。"]'),
('song-ci-503','天仙子','随车娘子','宋','宋词','song-ci','天仙子','[]','别酒未斟心先醉。',80,'宋词/ci.song.3000.json','["别酒未斟心先醉。", "忽听阳关辞故里。", "扬鞭勒马到皇都，三题尽，当际会。", "稳跳龙门三级水。", "天意令吾先送喜。", "不审君侯知得未。", "蔡邕博识爨桐声，君背负，只此是。", "酒满金杯来劝你。"]'),
('song-ci-504','瑞鹤仙','紫姑','宋','宋词','song-ci','瑞鹤仙','[]','睹娇红细捻。',126,'宋词/ci.song.3000.json','["睹娇红细捻。", "是西子、当日留心千叶。", "西都竞栽接。", "赏园林台榭，何妨日涉。", "轻罗慢褶。", "费多少、阳和调燮。", "向晓来、露浥芳苞，一点醉红潮颊。", "双靥。", "姚黄国艳，魏紫天香，倚风羞怯。", "云鬓试插。", "引动狂蜂浪蝶。", "况东君开宴，赏心乐事，莫惜献酬频叠。", "看相将，红药翻阶，尚馀侍妾。"]'),
('song-ci-505','杨柳枝','玉真','宋','宋词','song-ci','杨柳枝','[]','已谢芳华更不留。',48,'宋词/ci.song.3000.json','["已谢芳华更不留。", "几经秋。", "故宫台榭只荒邱。", "忍回头。", "塞外风霜家万里，望中愁。", "楚魂湘血恨悠悠。", "此生休。"]'),
('song-ci-506','忆少年','乩仙','宋','宋词','song-ci','忆少年','[]','凄凉天气，凄凉院落，凄凉时候。',56,'宋词/ci.song.3000.json','["凄凉天气，凄凉院落，凄凉时候。", "孤鸿叫斜月，伴寒灯残漏。", "落尽梧桐秋影瘦。", "菱鉴古、画眉难就。", "重阳又近也，对黄花依旧。"]'),
('song-ci-507','鹊桥仙','乩仙','宋','宋词','song-ci','鹊桥仙','[]','鸾舆初驾，牛车齐发，隐隐鹊桥咿轧。',68,'宋词/ci.song.3000.json','["鸾舆初驾，牛车齐发，隐隐鹊桥咿轧。", "尤云殢雨正欢浓，但只怕、来朝初八。", "霞垂彩幔，月明银烛，馥郁香喷金鸭。", "年年此际一相逢，未审是、甚时结煞。"]'),
('song-ci-508','千金意','琴精','宋','宋词','song-ci','千金意','[]','音音音。',80,'宋词/ci.song.3000.json','["音音音。", "音音你负心。", "你真负心。", "孤负我到如今。", "记的年时，低低唱、浅浅斟。", "一曲值千金。", "如今寂寞古墙阴。", "秋风荒草白云深。", "断桥流水何处寻。", "凄凄切切，冷冷清清，教奴怎禁。"]'),
('song-ci-509','浣溪沙','珍娘','宋','宋词','song-ci','浣溪沙','[]','溪雾溪烟溪景新。',48,'宋词/ci.song.3000.json','["溪雾溪烟溪景新。", "溶溶春水浸春云。", "碧琉璃底静无尘。", "风扬游丝随蝶翅，雨飘飞絮湿鸳唇。", "桃花片片送残春。"]'),
('song-ci-510','青玉案','刘清之','宋','宋词','song-ci','青玉案','[]','江南十月春风早。',80,'宋词/ci.song.3000.json','["江南十月春风早。", "见枝上、梅英小。", "爱日初升清雾晓。", "绣筵中启，星图高挂，膝下斑衣绕。", "今年献寿多欢笑。", "弄玉新将二雏好。", "此曲尊前何所祷。", "十分康乐，十分强健，一树庄椿老。"]'),
('song-ci-511','玉交枝・忆秦娥','刘焘','宋','宋词','song-ci','玉交枝・忆秦娥','[]','念谁伴、茜裙翠袖。',9,'宋词/ci.song.3000.json','["念谁伴、茜裙翠袖。"]'),
('song-ci-512','失调名','田为','宋','宋词','song-ci','失调名','[]','映竹园啼乌。',6,'宋词/ci.song.3000.json','["映竹园啼乌。"]'),
('song-ci-513','沁园春','崔中','宋','宋词','song-ci','沁园春','[]','自己阳生，正是中虚，静极动时。',139,'宋词/ci.song.3000.json','["自己阳生，正是中虚，静极动时。", "默地雷微震，冲开玉户，天心朗彻，放下帘帏。", "真火冲融，灵泉复凑，不昧谷神何险危。", "自然妙，若三川龙跃，九万鹏飞。", "中中二土成圭。", "意眷恋浓如母护儿。", "这恍惚真容，不空不色，窈冥妙象，无识无知。", "命住丹圆，全真体道，夺志精修休自迟。", "收功了，把三才全理，一贯全归。"]'),
('song-ci-514','满庭芳','何锄翁','宋','宋词','song-ci','满庭芳','[]','二气旋还，三宫升降，往来於是无穷。',117,'宋词/ci.song.3000.json','["二气旋还，三宫升降，往来於是无穷。", "透关神水，铅汞过三峰。", "返复周流八脉，戊己炼、阴虎阳龙。", "凝情处，金光朗朗，身外见形容。", "灵光，真造化，天机深远，推测难通。", "算利名酒色，恰似秋风。", "大道玄炉进火，三田内养出神功。", "功成后，金书来诏，平步赴瑶宫。"]'),
('song-ci-515','醉落魄・一斛珠','无名氏','宋','宋词','song-ci','醉落魄・一斛珠','[]','红牙板歇。',68,'宋词/ci.song.3000.json','["红牙板歇。", "韶声断、六么初彻。", "小槽酒滴真珠竭。", "紫玉瓯圆，浅浪泛春雪。", "香芽嫩蕊清心骨。", "醉中襟量与天阔。", "夜阑似觉归仙阙。", "走马章台，踏碎满街月。"]'),
('song-ci-516','满江红','无名氏','宋','宋词','song-ci','满江红','[]','浪蕊浮花，当不住、晚风吹了。',115,'宋词/ci.song.3000.json','["浪蕊浮花，当不住、晚风吹了。", "微雨过，池塘飞絮，一帘晴画。", "寂寂山光春似梦，依依草色熏如酒。", "近新来、怕上小红楼，凭阑眺。", "心事阻，诗情少。", "东皇去，良辰杳。", "想故园闲趣，水村烟柳。", "此日鹃声天不管，当年燕子人何有。", "叹江南、离别酒初醒，频回首。"]'),
('song-ci-517','西江月','无名氏','宋','宋词','song-ci','西江月','[]','三级掀腾波浪，一堂庆会风云。',58,'宋词/ci.song.3000.json','["三级掀腾波浪，一堂庆会风云。", "快乘霹雳化龙门。", "头角人中有分。", "谁状个中佳致，须还笔扫千军。", "是他画手亦通神。", "同向来春夺迅。"]'),
('song-ci-518','西江月','无名氏','宋','宋词','song-ci','西江月','[]','身禀五行正气，此心如鉴光明。',58,'宋词/ci.song.3000.json','["身禀五行正气，此心如鉴光明。", "不从龟鹤问年龄。", "万物有衰有盛。", "多谢道人著眼，我於身世常轻。", "任从性巧与心灵，此事从来分定。"]'),
('song-ci-519','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','真个美。',53,'宋词/ci.song.3000.json','["真个美。", "水墨观音难比。", "闻道观音谁不害。", "见来须顶礼。", "徐步金莲满地。", "那更兰心聪慧。", "一曲清歌离皓齿。", "梁尘飞不已。"]'),
('song-ci-520','水龙吟','无名氏','宋','宋词','song-ci','水龙吟','[]','邦人前世条缘，福星遇得长庚李。',126,'宋词/ci.song.3000.json','["邦人前世条缘，福星遇得长庚李。", "光芒初照，一声霹雳，重开天地。", "试问年来，民间安枕，伊谁之赐。", "有青天白日，和风甘雨，公如父、氏如子。", "今度虎牌重到，感皇恩、欢声千里。", "衮归未晚，纱笼人物，御屏名字。", "碧嶂长春，清江不尽，棠阴堪憩。", "愿年年把酒，庆公初度，祝公千岁。"]'),
('song-ci-521','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','个个修行，人人咽纳，谁悟真道。',126,'宋词/ci.song.3000.json','["个个修行，人人咽纳，谁悟真道。", "曲径多岐，旁门小法，误了人多少。", "容成岂是，神仙究竟，采药谩多炉灶。", "忽一朝，脱却桶底，性根坏倒。", "争如内观，无为清净，学取本来庄老。", "匹配阴阳，抽添铅汞，八卦为端表。", "人生如梦，流年似箭，回首也须闻早。", "贪迷恋，春花秋月，何时是了。"]');
